-- Poems batch 31
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('978213c1-b154-4786-abf4-87068bbf7284','三月三日宴王明府山亭','高瑾','唐','唐诗','tang','','[]','暮春元巳，春服初裁。',60,'全唐诗/poet.tang.3000.json','["暮春元巳，春服初裁。", "童冠八九，于洛之隈。", "河堤草變，鞏樹花開。", "逸人談發，仙御舟來。", "間關黃鳥，瀺灂丹腮。", "樂飲命席，優哉悠哉。"]'),
('3fd3c655-b0a9-4b60-86af-8b6dd41df9a2','晦日宴高氏林亭','高瑾','唐','唐诗','tang','','[]','試入山亭望，言是石崇家。',48,'全唐诗/poet.tang.3000.json','["試入山亭望，言是石崇家。", "二月風光起，三春桃李華。", "鶯吟上喬木，雁往息平沙。", "相看會取醉，寧知還路賒。"]'),
('d9e98389-3c67-44ab-8a62-c88c5be0fa00','晦日重宴','高瑾','唐','唐诗','tang','','[]','忽聞鶯響谷，於此命相知。',48,'全唐诗/poet.tang.3000.json','["忽聞鶯響谷，於此命相知。", "正開彭澤酒，來向高陽池。", "柳葉風前弱，梅花影處危。", "賞洽林亭晚，落照下參差。"]'),
('34b69c2d-d8c1-4bff-9e3d-2508a1e83716','上元夜效小庾體','高瑾','唐','唐诗','tang','','[]','初年三五夜，相知一兩人。',48,'全唐诗/poet.tang.3000.json','["初年三五夜，相知一兩人。", "連鑣出巷口，飛轂下池漘。", "燈光恰似月，人面倂如春。", "遨遊終未已，相歡待日輪。"]'),
('66e9672b-8a2a-4876-819d-bd4aeb091640','晦日宴高氏林亭','王茂時','唐','唐诗','tang','','[]','踐勝尋良會，乘春翫物華。',48,'全唐诗/poet.tang.3000.json','["踐勝尋良會，乘春翫物華。", "還隨張放友，來向石崇家。", "止水分巖鏡，閑庭枕浦沙。", "未極林泉賞，參差落照斜。"]'),
('cfccbfd5-e1a9-4b6a-a3fd-9bd0918b7361','晦日宴高氏林亭','徐皓','唐','唐诗','tang','','[]','綺筵乘暇景，瓊醑對年華。',48,'全唐诗/poet.tang.3000.json','["綺筵乘暇景，瓊醑對年華。", "門多金埒騎，路引璧人車。", "蘋早猶藏葉，梅殘正落花。", "藹藹林亭晚，餘興促流霞。"]'),
('9113e0d7-e9c4-4353-9aca-8021d40eb19d','晦日宴高氏林亭','長孫正隱','唐','唐诗','tang','','[]','晦晚屬煙霞，遨遊重歲華。',48,'全唐诗/poet.tang.3000.json','["晦晚屬煙霞，遨遊重歲華。", "歌鐘雖戚里，林藪是山家。", "細雨猶開日，深池不漲沙。", "淹留迷處所，巖岫幾重花。"]'),
('f6224c81-e134-4905-ab41-b0c639eef760','上元夜效小庾體同用春字','長孫正隱','唐','唐诗','tang','','[]','薄晚嘯遊人，車馬亂驅塵。',48,'全唐诗/poet.tang.3000.json','["薄晚嘯遊人，車馬亂驅塵。", "月光三五夜，燈燄一重春。", "煙雲迷北闕，簫管識南鄰。", "洛城終不閉，更出小平津。"]'),
('eab43c99-79c0-4b79-89f5-a7408f8e547e','晦日宴高氏林亭','高紹','唐','唐诗','tang','','[]','嘯侶入山家，臨春翫物華。',48,'全唐诗/poet.tang.3000.json','["嘯侶入山家，臨春翫物華。", "葛弦調綠水，桂醑酌丹霞。", "岸柳開新葉，庭梅落早花。", "興洽林亭晚，方還倒載車。"]'),
('a0464ebb-ba52-474f-ac7b-6b3a13cec685','晦日宴高氏林亭','郎餘令','唐','唐诗','tang','','[]','三春休晦節，九谷泛年華。',48,'全唐诗/poet.tang.3000.json','["三春休晦節，九谷泛年華。", "半晴餘細雨，全晚澹殘霞。", "尊開疎竹葉，管應落梅花。", "興闌相顧起，流水送香車。"]'),
('9a280978-cd68-4d49-bf3a-d197d5b0bd63','聽歌','劉得仁','唐','唐诗','tang','','[]','朱檻滿明月，美人歌落梅。',48,'全唐诗/poet.tang.30000.json','["朱檻滿明月，美人歌落梅。", "忽驚塵起處，疑是有風來。", "一曲聽初徹，幾年愁暫開。", "東南正雲雨，不得見陽臺。"]'),
('a9eea7ec-888e-44f0-8a5a-e92b9d7554bf','青龍寺僧院','劉得仁','唐','唐诗','tang','','[]','常多簪組客，非獨看高松。',48,'全唐诗/poet.tang.30000.json','["常多簪組客，非獨看高松。", "此地堪終日，開門見數峰。", "苔新禽跡少，泉冷樹陰重。", "師意如山裏，空房曉暮鐘。"]'),
('46dd7555-5804-4a56-b362-26df4dcf816e','夏夜會同人','劉得仁','唐','唐诗','tang','','[]','沈沈清暑夕，星斗儼虛空。',48,'全唐诗/poet.tang.30000.json','["沈沈清暑夕，星斗儼虛空。", "岸幘栖禽下，烹茶玉漏中。", "形骸忘已久，偃仰趣無窮。", "日汲泉來漱，微開密篠風。"]'),
('2e7e64ea-aa87-456e-b4aa-942822271e15','遊崔監丞城南別業','劉得仁','唐','唐诗','tang','','[]','門與青山近，青山復幾重。',48,'全唐诗/poet.tang.30000.json','["門與青山近，青山復幾重。", "雪融皇子岸，春浥翠微峰。", "地有經冬草，林無未老松。", "竹寒溪隔寺，晴日直聞鐘。"]'),
('02de7d48-2092-43ac-9f42-b34c0f529353','荅韋先輩春雨後見寄','劉得仁','唐','唐诗','tang','','[]','風散五更雨，鳥啼三月春。',48,'全唐诗/poet.tang.30000.json','["風散五更雨，鳥啼三月春。", "軒窗透初日，硯席絕纖塵。", "帝里峰頭出，鄰家樹色新。", "憐君高且靜，有句寄閑人。"]'),
('ab5c8c16-35c2-42f5-8726-764b7ddac590','題吳先生山居','劉得仁','唐','唐诗','tang','','[]','先生此幽隱，便可謝人羣。',48,'全唐诗/poet.tang.30000.json','["先生此幽隱，便可謝人羣。", "潭底見秋石，樹間飛霽雲。", "山居心已慣，俗事耳憎聞。", "念我要多疾，開爐藥許分。"]'),
('21ae5fa9-4166-4a87-8fa2-9cde7be03edf','晚遊慈恩寺','劉得仁','唐','唐诗','tang','','[]','寺去幽居近，每來因採薇。',48,'全唐诗/poet.tang.30000.json','["寺去幽居近，每來因採薇。", "伴僧行不困，臨水語忘歸。", "磬動青林晚，人驚白鷺飛。", "堪嗟浮俗事，皆與道相違。"]'),
('7ec90e57-dc10-4b78-a5ee-522f9b0c781b','題王處士山居','劉得仁','唐','唐诗','tang','','[]','茅堂入谷遠，林暗絕其鄰。',48,'全唐诗/poet.tang.30000.json','["茅堂入谷遠，林暗絕其鄰。", "終日有流水，經年無到人。", "溪雲常欲雨，山洞別開春。", "自得仙家術，栽松獨養真。"]'),
('7622a4bf-6053-4613-8a94-b1a60a7b163f','宿僧院','劉得仁','唐','唐诗','tang','','[]','禪地無塵夜，焚香話所歸。',48,'全唐诗/poet.tang.30000.json','["禪地無塵夜，焚香話所歸。", "樹搖幽鳥夢，螢入定僧衣。", "破月斜天半，高河下露微。", "翻令嫌白日，動即與心違。"]'),
('6552a1cc-269d-414b-9e6b-1ec167fd77a8','曉別呂山人','劉得仁','唐','唐诗','tang','','[]','疎鐘兼漏盡，曙色照青氛。',48,'全唐诗/poet.tang.30000.json','["疎鐘兼漏盡，曙色照青氛。", "栖鶴出高樹，山人歸白雲。", "月盈期重宿，丹熟約相分。", "羨入秋風洞，幽泉仔細聞。"]'),
('4f3306e9-a602-49b5-8183-c04e89396d3d','送知全禪師南遊','劉得仁','唐','唐诗','tang','','[]','師譽振京城，談空萬乘聽。',48,'全唐诗/poet.tang.30000.json','["師譽振京城，談空萬乘聽。", "北行山已雪，南去木猶青。", "夜嶽禪銷月，秋潭汲動星。", "迴期不可定，孤鶴在高冥。"]'),
('d752d820-ad9b-4c1d-afe6-869523196ef8','上張水部','劉得仁','唐','唐诗','tang','','[]','出入門闌久，兒童亦有情。',48,'全唐诗/poet.tang.30000.json','["出入門闌久，兒童亦有情。", "不須將姓字，長說向公卿。", "每許連牀坐，時容並馬行。", "恩深轉無語，懷抱自分明。"]'),
('a695501a-4c10-4201-9f0d-c1b714a703d1','塞上行作','劉得仁','唐','唐诗','tang','','[]','鄉井從離別，窮邊觸目愁。',48,'全唐诗/poet.tang.30000.json','["鄉井從離別，窮邊觸目愁。", "生人居外地，塞雪下中秋。", "鴈舉之衡翅，河穿入虜流。", "將軍心莫苦，向此取封侯。"]'),
('7e9a141b-c628-4caf-8644-3b81fd30c436','贈江夏盧使君','劉得仁','唐','唐诗','tang','','[]','詩人中最屈，無與使君儔。',48,'全唐诗/poet.tang.30000.json','["詩人中最屈，無與使君儔。", "白髮雖求退，明時合見收。", "登山猶自健，縱酒可多愁。", "好是能騎馬，相逢見鄂州。"]'),
('8350a26b-4f98-47f8-81a1-dc51ee8f3495','冬夜寄白閣僧','劉得仁','唐','唐诗','tang','','[]','營營不自息，暌闊數年情。',48,'全唐诗/poet.tang.30000.json','["營營不自息，暌闊數年情。", "林下期難逐，人間事旋生。", "鳥棲寒水迥，月映積冰清。", "石室焚香坐，懸知不爲名。"]'),
('303ad4fe-b67f-476e-aa48-0de91ba3e9f4','送姚合郎中任杭州','劉得仁','唐','唐诗','tang','','[]','水陸中分程，看花一月行。',48,'全唐诗/poet.tang.30000.json','["水陸中分程，看花一月行。", "會稽山隔浪，天竺樹連城。", "候吏齎魚印，迎船載斾旌。", "渡江春始半，列嶼草初生。"]'),
('2b23b1ca-c2b6-4e37-8988-8a50b9ca0c3c','西園','劉得仁','唐','唐诗','tang','','[]','夏圃秋涼入，樹低逢幘欹。',48,'全唐诗/poet.tang.30000.json','["夏圃秋涼入，樹低逢幘欹。", "水聲翻敗堰，山翠濕疎籬。", "綠滑莎藏徑，紅連果壓枝。", "幽人更何事，旦夕與僧期。"]'),
('a2824170-01ff-4e81-8ad8-68a0d03a402f','昊天觀新栽竹','劉得仁','唐','唐诗','tang','','[]','清風枝葉上，山鳥已栖來。',48,'全唐诗/poet.tang.30000.json','["清風枝葉上，山鳥已栖來。", "根別古溝岸，影生秋觀苔。", "徧思諸草木，惟此出塵埃。", "恨爲移君晚，空庭更擬栽。"]'),
('ce87d6be-f182-452d-9bcf-8c92c74dd567','晚步曲江因謁慈恩寺恭上人','劉得仁','唐','唐诗','tang','','[]','豈曰趣名者，年年待命通。',48,'全唐诗/poet.tang.30000.json','["豈曰趣名者，年年待命通。", "坐令青嶂上，興起白雲中。", "岸浸如天水，林含似雨風。", "南宗猶有碍，西寺問恭公。"]'),
('2b53de07-354c-417a-bc20-46b39309233c','送姚處士歸亳州','劉得仁','唐','唐诗','tang','','[]','白髮麻衣破，還譙別弟迴。',48,'全唐诗/poet.tang.30000.json','["白髮麻衣破，還譙別弟迴。", "首垂聽樂淚，花落待歌杯。", "石路尋芝熟，柴門有鹿來。", "明王下徵詔，應就碧峰開。"]'),
('1dd6b649-cea8-4b5d-906f-880bf0d94a43','寄樓子山雲棲上人','劉得仁','唐','唐诗','tang','','[]','一室鑿崔嵬，危梯疊蘚苔。',48,'全唐诗/poet.tang.30000.json','["一室鑿崔嵬，危梯疊蘚苔。", "永無塵事到，時有至人來。", "澗谷冬深靜，煙嵐日午開。", "修身知得地，京寺未言迴。"]'),
('1bdbd392-323e-42fd-86e6-1e577ed63975','秋夜喜友人宿','劉得仁','唐','唐诗','tang','','[]','莫說春闈事，清宵且共吟。',48,'全唐诗/poet.tang.30000.json','["莫說春闈事，清宵且共吟。", "頻年遺我輩，何日遇知音。", "逼曙天傾斗，將寒葉墜林。", "無將簪紱意，只損壯夫心。"]'),
('2b52ca1a-7472-4e9c-a758-8a1a2bd17b18','秋日同僧宿西池','劉得仁','唐','唐诗','tang','','[]','菡萏遍秋水，隔林香似焚。',48,'全唐诗/poet.tang.30000.json','["菡萏遍秋水，隔林香似焚。", "僧同池上宿，霞向月邊分。", "渚鳥栖蒲立，城砧接曙聞。", "來宵莫他約，重此話孤雲。"]'),
('d8d996b4-2eb5-4fdf-9572-6af8ecdc4a85','宿韋津山居','劉得仁','唐','唐诗','tang','','[]','永夕見招宿，詩書盈草堂。',48,'全唐诗/poet.tang.30000.json','["永夕見招宿，詩書盈草堂。", "靜吟傾美酒，高論出名場。", "窗颯松篁韻，庭兼雪月光。", "心期身未老，一去泛瀟湘。"]'),
('136bbd8c-eb1c-43c1-8b24-782ca328e0c4','夜攜酒訪崔正字','劉得仁','唐','唐诗','tang','','[]','只應芸閣吏，知我僻兼愚。',48,'全唐诗/poet.tang.30000.json','["只應芸閣吏，知我僻兼愚。", "吟興忘飢凍，生涯任有無。", "慘雲埋遠岫，陰吹吼寒株。", "忽起圍爐思，招攜酒滿壺。"]'),
('76688ee0-108b-4fb1-8369-5b643832349d','送蔡京東歸迎侍','劉得仁','唐','唐诗','tang','','[]','高堂惟兩別，此別是榮歸。',48,'全唐诗/poet.tang.30000.json','["高堂惟兩別，此別是榮歸。", "薄俸迎親遠，平時知己稀。", "鄆郊秋木見，魯寺夜鐘微。", "近臘西來日，多逢霰雪飛。"]'),
('64f7ffee-d8d2-40c2-96b1-f65bb510bf2b','中秋','劉得仁','唐','唐诗','tang','','["\u6292\u60c5", "\u8282\u65e5", "\u4e2d\u79cb"]','塵裏兼塵外，咸期此夕明。',48,'全唐诗/poet.tang.30000.json','["塵裏兼塵外，咸期此夕明。", "一年惟一度，長恐有雲生。", "露洗微埃盡，光濡是物清。", "朗吟看正好，惆悵又西傾。"]'),
('2b0aeb3c-26cd-40cf-98ec-6d898b7d2bf4','池上宿','劉得仁','唐','唐诗','tang','','[]','事事不求奢，長吟省嘆嗟。',48,'全唐诗/poet.tang.30000.json','["事事不求奢，長吟省嘆嗟。", "無才堪世棄，有句向誰誇。", "老樹呈秋色，空池浸月華。", "涼風白露夕，此境屬詩家。"]'),
('ed167333-59af-4452-be9b-5b14631730fd','秋夕即事','劉得仁','唐','唐诗','tang','','[]','永夕坐暝久，蕭蕭猨狖啼。',48,'全唐诗/poet.tang.30000.json','["永夕坐暝久，蕭蕭猨狖啼。", "漏微砧韻隔，月落斗杓低。", "危葉無風墜，幽禽並樹栖。", "自憐在岐路，不醉亦沈迷。"]'),
('c009334b-4ddb-4e1b-b0da-1fe220b533c9','晚夏','劉得仁','唐','唐诗','tang','','[]','日夕是西風，流光半已空。',48,'全唐诗/poet.tang.30000.json','["日夕是西風，流光半已空。", "山光漸凝碧，樹葉即翻紅。", "學淺慙多士，秋成羨老農。", "誰憐信公道，不泣路岐中。"]'),
('2b2086b5-58ca-46c2-a2a6-7b6fe5e63cb6','夏日即事','劉得仁','唐','唐诗','tang','','[]','到曉改詩句，四鄰嫌苦吟。',48,'全唐诗/poet.tang.30000.json','["到曉改詩句，四鄰嫌苦吟。", "中宵橫北斗，夏木隱栖禽。", "天地先秋肅，軒窗映月深。", "幽庭多此景，惟恐曙光侵。"]'),
('5945cb07-2e68-4f90-9e85-100588998082','夏日通濟里居酬諸先輩見訪','劉得仁','唐','唐诗','tang','','[]','君子遠相尋，聯鑣到敝林。',48,'全唐诗/poet.tang.30000.json','["君子遠相尋，聯鑣到敝林。", "有詩誰索和，無酒可賒斟。", "門列晴峰色，堂開古木陰。", "何因駐清聽，惟恐日西沈。"]'),
('898f5b76-d67e-415b-aa29-0dac947fce03','寄姚諫議','劉得仁','唐','唐诗','tang','','[]','鳴鞭靜路塵，籍籍諫垣臣。',48,'全唐诗/poet.tang.30000.json','["鳴鞭靜路塵，籍籍諫垣臣。", "函疏封還密，爐香侍立親。", "篋多臨水作，窗宿臥雲人。", "危坐開寒紙，燈前起草頻。"]'),
('9c71caa8-2dec-4fc9-abdb-1adcf745f1f4','和厲玄侍御題戶部相公廬山草堂','劉得仁','唐','唐诗','tang','','["\u5e90\u5c71"]','白雲居創畢，詔入鳳池年。',48,'全唐诗/poet.tang.30000.json','["白雲居創畢，詔入鳳池年。", "林長雙峰樹，潭分並寺泉。", "石溪盤鶴外，岳室閉猨前。", "柱史題詩後，松前更肅然。"]'),
('e90dab5d-7bd8-4253-97ae-c324cc38a5a1','題山中故靜禪師','劉得仁','唐','唐诗','tang','','[]','寂滅身何在，門人隔此生。',48,'全唐诗/poet.tang.30000.json','["寂滅身何在，門人隔此生。", "影懸塵已厚，塔種柏初成。", "溪院秋先雪，山堂古有精。", "當時挂錫處，樹老幾枝傾。"]'),
('3569c89a-b3e9-485f-9d5a-b1797112654d','夏日遊慈恩寺','劉得仁','唐','唐诗','tang','','[]','何處消長日，慈恩精舍頻。',48,'全唐诗/poet.tang.30000.json','["何處消長日，慈恩精舍頻。", "僧高容野客，樹密絕囂塵。", "閑上凌虛塔，相逢避暑人。", "却愁歸去路，馬迹竝車輪。"]'),
('69e6771a-9618-4817-a98b-63bae08e606d','題終南麻先生寂禪師石室','劉得仁','唐','唐诗','tang','','[]','因居石室貧，五十二迴春。',48,'全唐诗/poet.tang.30000.json','["因居石室貧，五十二迴春。", "擁褐冥心客，窮經暮齒人。", "翠沈空水定，雨絕片雲新。", "危細秋峰徑，相隨到頂頻。"]'),
('6384393b-fbb2-409d-bcc9-984bde31dcf5','送靈武朱書記','劉得仁','唐','唐诗','tang','','[]','靈帥與誰善，得君賓幕中。',48,'全唐诗/poet.tang.30000.json','["靈帥與誰善，得君賓幕中。", "從容應盡禮，贊畫致元功。", "連塞雲長慘，纔秋樹半空。", "相如偏自愜，掌記復乘驄。"]'),
('0ca268d2-c4aa-47b4-ba0c-5ccea08dd431','弔草堂禪師','劉得仁','唐','唐诗','tang','','[]','杖履疑師在，房關四壁蛩。',48,'全唐诗/poet.tang.30000.json','["杖履疑師在，房關四壁蛩。", "貯瓶經臘水，響塔隔山鐘。", "乳鴿沿苔井，齋猨散雪峰。", "如何不相見，倚徧寺前松。"]'),
('ddcfa724-864f-4ae0-ad50-9ae5fbc3b0f1','早春送湘潭李少府之任','劉得仁','唐','唐诗','tang','','[]','柳新春水湄，春岸草離離。',48,'全唐诗/poet.tang.30000.json','["柳新春水湄，春岸草離離。", "祖席觴云盡，離人淚各垂。", "業文傳不朽，作尉豈多時。", "公退琴堂上，風吹斑竹枝。"]'),
('def9ba93-b443-4807-8332-97c615a371c2','送越客歸','劉得仁','唐','唐诗','tang','','[]','霜薄東南地，江楓落未齊。',48,'全唐诗/poet.tang.30000.json','["霜薄東南地，江楓落未齊。", "衆山離楚上，孤棹宿吳西。", "渚客留僧語，籠猨失子啼。", "到家冬即是，荷盡若耶溪。"]'),
('b510f3a7-a145-44e6-816f-7a74d676707f','送周鉞往江夏','劉得仁','唐','唐诗','tang','','[]','東西南北郡，自說徧曾遊。',48,'全唐诗/poet.tang.30000.json','["東西南北郡，自說徧曾遊。", "人世終多故，皇都不少留。", "郢城帆過夜，漢水月方秋。", "此謁親知去，聞猨豈解愁。"]'),
('a9624fa0-5afd-4041-8f5b-5811a4af2901','送河池李明府之任','劉得仁','唐','唐诗','tang','','[]','河池安所理，種柳與彈琴。',48,'全唐诗/poet.tang.30000.json','["河池安所理，種柳與彈琴。", "自合清時化，仍資白首吟。", "程餘行片月，公退入遙林。", "想得詢民瘼，方稱單父心。"]'),
('2e852287-bccd-4698-9053-d0df2ac6c509','送蔡京侍御赴大梁幕','劉得仁','唐','唐诗','tang','','[]','同城各多故，會面亦稀疎。',48,'全唐诗/poet.tang.30000.json','["同城各多故，會面亦稀疎。", "及道須相別，臨岐恨有餘。", "梁園飛楚鳥，汴水走淮魚。", "衆說裁軍檄，陳琳遠不如。"]'),
('109ad1d2-3731-443a-b90d-aa4365c7d15e','哭鮑溶有感','劉得仁','唐','唐诗','tang','','[]','寥落故人宅，今來身已亡。',48,'全唐诗/poet.tang.30000.json','["寥落故人宅，今來身已亡。", "古苔封墨沼，深竹映書堂。", "秋色池館靜，雨聲雲水涼。", "無因展交道，日暮剖心腸。"]'),
('135b439d-b60c-4a42-8d0c-22cc25e42426','送僧歸玉泉寺','劉得仁','唐','唐诗','tang','','[]','玉泉歸故剎，便老是僧期。',48,'全唐诗/poet.tang.30000.json','["玉泉歸故剎，便老是僧期。", "亂木孤蟬後，寒山絕鳥時。", "若尋流水去，轉出白雲遲。", "見說千峰路，溪深復頂危。"]'),
('78ada3c5-92a7-4de7-ae14-836488679e66','宣義池上','劉得仁','唐','唐诗','tang','','[]','修篁夾綠池，幽絮此中飛。',48,'全唐诗/poet.tang.30000.json','["修篁夾綠池，幽絮此中飛。", "何必青山遠，仍將白髮歸。", "鳥啼亦有恨，鷗習總無機。", "樹起秋風細，西林磬入微。"]'),
('3d828921-91fb-4ada-8631-dfae14941a9b','回中夜訪獨孤從事','劉得仁','唐','唐诗','tang','','[]','滿庭霜月魄，風靜絕纖聞。',48,'全唐诗/poet.tang.30000.json','["滿庭霜月魄，風靜絕纖聞。", "邊境時無事，州城夜訪君。", "擁裘聽塞角，酌醴話湘雲。", "贊佐元戎美，恩齊十萬軍。"]'),
('f7cc5d03-dbca-4ec7-9fc3-5c31a33d9bac','宿宣義池亭','劉得仁','唐','唐诗','tang','','[]','暮色遶柯亭，南山幽竹青。',48,'全唐诗/poet.tang.30000.json','["暮色遶柯亭，南山幽竹青。", "夜深斜舫月，風定一池星。", "島嶼無人跡，菰蒲有鶴翎。", "此中足吟眺，何用泛滄溟。"]'),
('aa4780fe-f910-470e-bdad-95daf6277090','送智玄首座歸蜀中舊山','劉得仁','唐','唐诗','tang','','[]','像教得重興，因師說大乘。',48,'全唐诗/poet.tang.30000.json','["像教得重興，因師說大乘。", "從來悟明主，今去證高僧。", "蜀國煙霞異，靈山水月澄。", "鄉閭諸善友，喜似見南能。"]'),
('935bcd90-e68c-48a4-88d6-124bd8c50b8b','賀顧非熊及第其年內索文章','劉得仁','唐','唐诗','tang','','[]','愚爲童稚時，已解念君詩。',48,'全唐诗/poet.tang.30000.json','["愚爲童稚時，已解念君詩。", "及得高科晚，須逢聖主知。", "花前飜有淚，鬢上却無絲。", "從此東歸去，休爲墜葉期。"]'),
('701ddaac-fd35-42ee-88e2-1da8d56e9a62','冬日駱家亭子','劉得仁','唐','唐诗','tang','','[]','亭臺臘月時，松竹見貞姿。',48,'全唐诗/poet.tang.30000.json','["亭臺臘月時，松竹見貞姿。", "林積煙藏日，風吹水合池。", "恨無人此住，靜有鶴相窺。", "是景吟詩徧，真於野客宜。"]'),
('17cc0659-dfef-47e7-a538-bd689b2b8c2b','題邵公禪院','劉得仁','唐','唐诗','tang','','[]','無事門多掩，陰階竹掃苔。',48,'全唐诗/poet.tang.30000.json','["無事門多掩，陰階竹掃苔。", "勁風吹雪聚，渴鳥啄冰開。", "樹向寒山得，人從瀑布來。", "終期天目老，擎錫逐雲回。"]'),
('a239c65c-e5e0-4463-b314-ce56f0a3fac4','憶鶴','劉得仁','唐','唐诗','tang','','[]','自爾歸仙後，經秋又過春。',48,'全唐诗/poet.tang.30000.json','["自爾歸仙後，經秋又過春。", "白雲尋不得，紫府去無因。", "此地空明月，何山伴羽人。", "終期華表上，重見令威身。"]'),
('1e51c2e4-da56-4b03-a51c-efd01ac12d4e','聽夜泉','劉得仁','唐','唐诗','tang','','[]','靜裏層層石，潺湲到鶴林。',48,'全唐诗/poet.tang.30000.json','["靜裏層層石，潺湲到鶴林。", "流迴出幾洞，源遠歷千岑。", "寒助空山月，清兼此夜心。", "幽人聽達曙，相和蘚牀吟。"]'),
('55514f96-18dc-412d-bdd7-218adfc9c4b8','樂遊原春望','劉得仁','唐','唐诗','tang','','[]','樂遊原上望，望盡帝都春。',48,'全唐诗/poet.tang.30000.json','["樂遊原上望，望盡帝都春。", "始覺繁華地，應無不醉人。", "雲開雙闕麗，柳映九衢新。", "愛此頻來往，多閑逐此身。"]'),
('671f169b-74f0-4341-9794-b56981663920','贈雍陶博士','劉得仁','唐','唐诗','tang','','[]','腹是羣書笥，官爲六義師。',48,'全唐诗/poet.tang.30000.json','["腹是羣書笥，官爲六義師。", "情高少塵事，朝下足閑時。", "有句同人伏，無私胄子知。", "漢庭公議在，正與觸邪宜。"]'),
('be950e41-d288-48fc-ac81-10f672e10e82','夏日感懷寄所知','劉得仁','唐','唐诗','tang','','[]','了了見岐路，欲行難負心。',48,'全唐诗/poet.tang.30000.json','["了了見岐路，欲行難負心。", "趨時不圓轉，自古易湮沈。", "日正林方合，蜩鳴夏已深。", "中郎今遠在，誰識爨桐音。"]'),
('2e0ac513-c652-4631-b893-d23c84b7b059','陳情上知己','劉得仁','唐','唐诗','tang','','[]','性與才俱拙，名場迹甚微。',48,'全唐诗/poet.tang.30000.json','["性與才俱拙，名場迹甚微。", "久居顏亦厚，獨立事多非。", "刻骨搜新句，無人憫白衣。", "明時自堪戀，不是不知機。"]'),
('d831bfd0-8896-458c-a99d-4caff225b24d','秋夜寄友人二首 一','劉得仁','唐','唐诗','tang','','[]','永夜無他慮，長吟畢二更。',48,'全唐诗/poet.tang.30000.json','["永夜無他慮，長吟畢二更。", "暗燈搖碧影，滯雨滴堦聲。", "道進愁還淺，年加睡自輕。", "如何得深術，相與捨浮名。"]'),
('36b8a859-6ad4-4a45-97a2-2ccba295e584','秋夜寄友人二首 二','劉得仁','唐','唐诗','tang','','[]','所思同海岱，所夢亦煙波。',48,'全唐诗/poet.tang.30000.json','["所思同海岱，所夢亦煙波。", "默坐看山久，閑行值寺過。", "獨吟黃葉亂，相去碧峰多。", "我有歸心在，君行竟若何。"]'),
('4c73eb1e-1e2f-40de-90cd-2857e6935596','寄春坊顧校書','劉得仁','唐','唐诗','tang','','[]','寧因不得志，寂寞本相宜。',48,'全唐诗/poet.tang.30000.json','["寧因不得志，寂寞本相宜。", "冥目冥心坐，花開花落時。", "數畦蔬甲出，半夢鳥聲移。", "只恐龍樓吏，歸山又見違。"]'),
('74011ffb-7b38-471b-a8ad-b3b0e7c23bd3','寄雍陶先輩','劉得仁','唐','唐诗','tang','','[]','久別青雲士，幽人分固然。',48,'全唐诗/poet.tang.30000.json','["久別青雲士，幽人分固然。", "愁心不易去，蹇步卒難前。", "盡落經霜葉，頻陰欲雪天。", "歸山自有限，豈待白頭年。"]'),
('ecebd171-37e0-4cc4-af91-4fdb3cc8b99d','對月寄雍陶','劉得仁','唐','唐诗','tang','','[]','圓明寒魄上，天地一光中。',48,'全唐诗/poet.tang.30000.json','["圓明寒魄上，天地一光中。", "臨水通宵坐，知君此興同。", "華凝衣有露，靜極樹無風。", "若向湘江見，湘江徹底空。"]'),
('c700f2d8-70aa-45bb-a629-4c031233965f','寄謝觀','劉得仁','唐','唐诗','tang','','[]','十五年餘苦，今朝始遇君。',48,'全唐诗/poet.tang.30000.json','["十五年餘苦，今朝始遇君。", "無慙於白日，不枉別孤雲。", "得失天難問，稱揚鬼亦聞。", "此恩銷鏤骨，吟坐葉紛紛。"]'),
('9c28c1bb-a4bd-47ef-9b8b-948384c0d164','送鄂州崔大夫赴鎮','劉得仁','唐','唐诗','tang','','[]','廉問帝難人，朝庭輟重臣。',48,'全唐诗/poet.tang.30000.json','["廉問帝難人，朝庭輟重臣。", "入山初有雪，登路正無塵。", "去國鳴騶緩，經雲住斾頻。", "千峰與萬木，清聽雨情新。"]'),
('78ac70fa-70b4-4765-81fd-843396890874','送錢給事赴虢州','劉得仁','唐','唐诗','tang','','[]','帝心憂虢俗，暫庭輟掖垣臣。',49,'全唐诗/poet.tang.30000.json','["帝心憂虢俗，暫庭輟掖垣臣。", "疲瘵初承制，鄉閭似得春。", "化成應有瑞，位重轉聞貧。", "用作鹽梅日，爭迴臥轍人。"]'),
('9d970f1c-e131-416a-a697-f1b808f09e69','送雍陶侍御赴兖州裴尚書命','劉得仁','唐','唐诗','tang','','[]','綸閣知孤直，翻論北巷賢。',48,'全唐诗/poet.tang.30000.json','["綸閣知孤直，翻論北巷賢。", "且縻蓮幕裏，會致玉堦前。", "洙泗秋微動，龜蒙月正圓。", "元戎軍務息，清句待君聯。"]'),
('6cc338af-cc0a-4023-bef7-ccb1ad77c293','送新羅人歸本國','劉得仁','唐','唐诗','tang','','[]','雞林隔巨浸，一住一年行。',48,'全唐诗/poet.tang.30000.json','["雞林隔巨浸，一住一年行。", "日近國先曙，風吹海不平。", "眼穿鄉井樹，頭白渺瀰程。", "到彼星霜換，唐家語却生。"]'),
('fb04a1e4-2037-4557-8f64-8ff411d411db','送車濤罷舉歸山','劉得仁','唐','唐诗','tang','','[]','朝是暮還非，人情冷暖移。',48,'全唐诗/poet.tang.30000.json','["朝是暮還非，人情冷暖移。", "浮生只如此，強進欲何爲。", "要路知無援，深山必遇師。", "憐君明此理，休去不遲疑。"]'),
('ca88948a-2217-4e99-aeec-b462b64ed530','送王書記歸邠州','劉得仁','唐','唐诗','tang','','[]','陳琳輕一別，馬上意超然。',48,'全唐诗/poet.tang.30000.json','["陳琳輕一別，馬上意超然。", "來日行煩暑，歸時聽早蟬。", "陰雲翳城郭，細雨紊山川。", "從事公劉地，元戎舊禮賢。"]'),
('f1f2f173-b539-4d06-9db6-05e80a615c10','送謝觀之劒南從事','劉得仁','唐','唐诗','tang','','[]','迢遞從知己，他人敢更言。',48,'全唐诗/poet.tang.30000.json','["迢遞從知己，他人敢更言。", "離京雖未臘，到府已應暄。", "飛急奔行鴈，啼酸憶子猨。", "江山無限思，君擬共誰論。"]'),
('32183dec-fbda-47f9-8dba-2726587dadb8','送顧非熊作尉盱眙','劉得仁','唐','唐诗','tang','','[]','一名兼一尉，未足是君伸。',48,'全唐诗/poet.tang.30000.json','["一名兼一尉，未足是君伸。", "厲數爲詩者，多來作諫臣。", "路翻平楚闊，草帶古淮新。", "天下雖云大，同聲有幾人。"]'),
('f4e11d28-ade6-48af-bc37-a09ed8a0c2e6','送高湘及第後東歸覲叔','劉得仁','唐','唐诗','tang','','[]','此去幾般榮，登科鼎足名。',48,'全唐诗/poet.tang.30000.json','["此去幾般榮，登科鼎足名。", "無慙入南巷，高價聳東京。", "窗對嵩山碧，庭來洛水聲。", "門前桃李樹，一徑已陰成。"]'),
('54bb20d9-8a85-40a1-9505-c08101ed0aff','送友人下第歸覲','劉得仁','唐','唐诗','tang','','[]','君此卜行日，高堂應夢歸。',48,'全唐诗/poet.tang.30000.json','["君此卜行日，高堂應夢歸。", "莫將和氏淚，滴著老萊衣。", "嶽雨連河細，田禽出麥飛。", "到家調膳後，吟苦落蟬暉。"]'),
('f1cdca0b-584e-424e-9f05-20b263c7c1d3','送友人下第歸揚州覲省','劉得仁','唐','唐诗','tang','','[]','新柳間花垂，東西京路岐。',48,'全唐诗/poet.tang.30000.json','["新柳間花垂，東西京路岐。", "園林知自到，寢食計相思。", "雨斷淮山出，帆揚楚樹移。", "晨昏心已泰，蟬發是回時。"]'),
('190bb6b0-5c3e-46bd-afa7-1aa2f21e2fbf','早行','劉得仁','唐','唐诗','tang','','[]','萬類半已動，此心寧自安。',48,'全唐诗/poet.tang.30000.json','["萬類半已動，此心寧自安。", "月沈平野盡，星隱曙空殘。", "馬渡橫流廣，人行湛露寒。", "還思猶夢者，不信早行難。"]'),
('6c3f5026-f29b-4cb4-a5c1-0f6ed8d3d454','通濟里居酬廬肇見尋不遇','劉得仁','唐','唐诗','tang','','[]','衡門掩綠苔，樹下絕塵埃。',48,'全唐诗/poet.tang.30000.json','["衡門掩綠苔，樹下絕塵埃。", "偶赴高僧約，旋知長者來。", "雲山堪眺望，車馬必裴回。", "問以何爲待，慙無酒一杯。"]'),
('4848e67c-4b51-41c4-bd9c-d906e13a2e58','贈王尊師','劉得仁','唐','唐诗','tang','','[]','爲道常日損，尊師修此心。',48,'全唐诗/poet.tang.30000.json','["爲道常日損，尊師修此心。", "挂肩黃布被，穿髪白蒿簪。", "符札靈砂字，弦彈古素琴。", "囊中曾有藥，點土亦成金。"]'),
('785c49d3-7be0-4b4d-a7ea-6175a4d58ea2','冬夜與蔡校書宿無可上人院','劉得仁','唐','唐诗','tang','','[]','儒釋偶同宿，夜窗寒更清。',48,'全唐诗/poet.tang.30000.json','["儒釋偶同宿，夜窗寒更清。", "忘機於世久，晤語到天明。", "月倒高松影，風旋一磬聲。", "真門猶是幻，不用覺浮生。"]'),
('316d736f-0f74-4687-baf0-fd3c7cac457e','冬日喜同志宿','劉得仁','唐','唐诗','tang','','[]','相逢話清夜，言實轉相知。',48,'全唐诗/poet.tang.30000.json','["相逢話清夜，言實轉相知。", "共道名雖切，唯論命不疑。", "吟身坐霜石，眠鳥握風枝。", "別憶天台客，煙霞昔有期。"]'),
('03a5e7a9-06b6-4d1a-a392-bcf0ca12cda2','逢呂上山人','劉得仁','唐','唐诗','tang','','[]','塵裏正愁老，相逢眼益明。',48,'全唐诗/poet.tang.30000.json','["塵裏正愁老，相逢眼益明。", "從前枉多病，此後鮮疎名。", "古柏今收子，深山許事兄。", "長生如有分，願逐到蓬瀛。"]'),
('f4fb66dc-e8e2-417f-88b3-2df1f0e52fca','春暮對雨','劉得仁','唐','唐诗','tang','','[]','春暮雨微微，翻疑墜葉時。',48,'全唐诗/poet.tang.30000.json','["春暮雨微微，翻疑墜葉時。", "氣蒙楊柳重，寒勒牡丹遲。", "未夕鳥先宿，望晴人有期。", "何當廓陰閉，新暑竹風吹。"]'),
('50397bb4-b68f-43a0-bc2c-b7cfa36f50da','長信宮','劉得仁','唐','唐诗','tang','','[]','簟涼秋氣初，長信恨何如。',48,'全唐诗/poet.tang.30000.json','["簟涼秋氣初，長信恨何如。", "拂黛月生指，解鬟雲滿梳。", "一從悲畫扇，幾度泣前魚。", "坐聽南宮樂，清風搖翠裾。"]'),
('1bb6d134-5c32-4b4f-a00d-74fd7bf193ee','初夏題段郎中修竹里南園','劉得仁','唐','唐诗','tang','','[]','高人遊息處，與此曲池連。',48,'全唐诗/poet.tang.30000.json','["高人遊息處，與此曲池連。", "密樹纔春後，深山在目前。", "遠峰初絕雨，片石欲生煙。", "數有僧來宿，應緣靜好禪。"]'),
('b42236c0-f015-4bf2-bc4f-c6b407ed3289','題景玄禪師院','劉得仁','唐','唐诗','tang','','[]','古僧精進者，師復是誰流。',48,'全唐诗/poet.tang.30000.json','["古僧精進者，師復是誰流。", "道貴行無我，禪難說到頭。", "汲泉羸鶴立，擁褐老猨愁。", "曾住深山院，何如此院幽。"]'),
('fe62a52d-e93a-4c54-8962-7641bafc1c57','夏日樊川別業即事','劉得仁','唐','唐诗','tang','','[]','無事稱無才，柴門亦罕開。',48,'全唐诗/poet.tang.30000.json','["無事稱無才，柴門亦罕開。", "脫巾吟永日，著屐步荒臺。", "風卷微塵上，霆將暴雨來。", "終南雲漸合，咫尺失崔嵬。"]'),
('6cc30b55-c750-47ff-af4a-f3d913887862','寄無可上人','劉得仁','唐','唐诗','tang','','[]','省學爲詩日，宵吟每達晨。',48,'全唐诗/poet.tang.30000.json','["省學爲詩日，宵吟每達晨。", "十年期是夢，一事未成身。", "枉別山中客，殊非世上人。", "今來已如此，須得桂榮新。"]'),
('ae383f81-ff32-431c-95e5-ba280eadc54f','和范校書贈造微上人','劉得仁','唐','唐诗','tang','','[]','得性見微公，何曾執著空。',48,'全唐诗/poet.tang.30000.json','["得性見微公，何曾執著空。", "修心將佛竝，吐論與儒通。", "曉漱松杉下，宵禪雪月中。", "他生有緣會，君子亦應同。"]'),
('d9c08297-a2e7-4353-85d6-0f92010a165b','訪曲江胡處士','劉得仁','唐','唐诗','tang','','[]','何況歸山後，而今已似仙。',48,'全唐诗/poet.tang.30000.json','["何況歸山後，而今已似仙。", "卜居天苑畔，閑步禁樓前。", "落日明沙岸，微風上紙鳶。", "靜還林石下，坐讀養生篇。"]'),
('d10f711a-b2a1-4f39-8b6a-220594025cb2','慈恩寺塔下避暑','劉得仁','唐','唐诗','tang','','[]','古松凌巨塔，脩竹映空廊。',48,'全唐诗/poet.tang.30000.json','["古松凌巨塔，脩竹映空廊。", "竟日聞虛籟，深山只此涼。", "僧真生我靜，水淡發茶香。", "坐久東樓望，鐘聲振夕陽。"]'),
('7ee61090-d908-4cd3-9d71-ef302ccbede7','秋晚與友人遊青龍寺','劉得仁','唐','唐诗','tang','','[]','高視終南秀，西風度閣涼。',48,'全唐诗/poet.tang.30000.json','["高視終南秀，西風度閣涼。", "一生同隙影，幾處好山光。", "暮鳥投嬴木，寒鐘送夕陽。", "因居話心地，川冥宿僧房。"]'),
('a9d0d1fe-464a-4a4b-b497-2e2e7b8713ae','春日雨後作','劉得仁','唐','唐诗','tang','','[]','朝來微有雨，天地爽無塵。',48,'全唐诗/poet.tang.30000.json','["朝來微有雨，天地爽無塵。", "北厥明如晝，南山碧動人。", "車輿終日別，草樹一城新。", "枉是吾君戚，何門謁紫宸。"]'),
('89881aa6-2479-4d76-8bbd-bdb68acab3a6','別王山人','劉得仁','唐','唐诗','tang','','[]','旨甘雖自足，未是祿榮親。',48,'全唐诗/poet.tang.30000.json','["旨甘雖自足，未是祿榮親。", "尚逐趨時伴，多離有道人。", "山居衣以草，生寄藥隨身。", "不食長無疾，年知出十旬。"]'),
('d145d16f-5c47-40d0-9b2e-a8ad34ef40e9','贈陶山人','劉得仁','唐','唐诗','tang','','[]','處士例營營，惟君縱此生。',48,'全唐诗/poet.tang.30000.json','["處士例營營，惟君縱此生。", "閑能資壽考，健不換公卿。", "藥圃妻同耨，山田子共耕。", "定知丹熟後，無姓亦無名。"]'),
('0864c886-51ed-4774-979c-f3503805d74f','禁署早春晴望','劉得仁','唐','唐诗','tang','','[]','御林聞有早鶯聲，玉檻春香九陌晴。',64,'全唐诗/poet.tang.30000.json','["御林聞有早鶯聲，玉檻春香九陌晴。", "寒著霽雲歸紫閣，暖浮佳氣動芳城。", "宮池日到冰初解，輦路風吹草欲生。", "鴛侶此時皆賦詠，商山雪在思尤清。"]'),
('8281301a-f855-458f-9814-97a2dfca7c51','山中尋道人不遇','劉得仁','唐','唐诗','tang','','[]','年過弱冠風塵裏，常擬隨師學鍊形。',64,'全唐诗/poet.tang.30000.json','["年過弱冠風塵裏，常擬隨師學鍊形。", "石路特來尋道者，雲房空見有仙經。", "碁於松底留殘局，鶴向潭邊退數翎。", "便欲此居閑到老，先生何日下青冥。"]'),
('d99e3bf8-a9bd-418e-b68b-74eb247f4333','贈敬晊助教二首 一','劉得仁','唐','唐诗','tang','','[]','到來常聽說清虛，手把玄元七字書。',64,'全唐诗/poet.tang.30000.json','["到來常聽說清虛，手把玄元七字書。", "仙籍不知名姓有，道情惟見往來疎。", "已能絕粒無飢色，早晚休官買隱居。", "便欲去隨爲弟子，片雲孤鶴可相於。"]'),
('24382132-0f96-49f4-99bd-cd66f346932d','贈敬晊助教二首 二','劉得仁','唐','唐诗','tang','','[]','街西靜觀求居處，不到權門到寺頻。',64,'全唐诗/poet.tang.30000.json','["街西靜觀求居處，不到權門到寺頻。", "禁掖人知連狀薦，國庠官滿一家貧。", "清儀稱是蓬瀛客，直氣堪爲諫諍臣。", "自顧無成年漸長，報恩惟願殺微身。"]'),
('90e530f9-651e-42f1-a03c-5c5059646b2f','送祖山人歸山','劉得仁','唐','唐诗','tang','','[]','獨來朝市笑浮雲，却憶煙霞出帝城。',64,'全唐诗/poet.tang.30000.json','["獨來朝市笑浮雲，却憶煙霞出帝城。", "不說金丹能點化，空教弟子學長生。", "壺中瀉酒看雲影，洞裏逢師下鶴迎。", "料得仙家玉牌上，已鐫白日上昇名。"]'),
('805edd84-2acf-48cb-b45e-313cea835b68','監試蓮花峰','劉得仁','唐','唐诗','tang','','[]','太華萬餘重，岧嶤只此峰。',72,'全唐诗/poet.tang.30000.json','["太華萬餘重，岧嶤只此峰。", "當秋倚寥泬，入望似芙蓉。", "翠拔千尋直，青危一朵穠。", "氣分毛女秀，靈有羽人蹤。", "倒影侵官路，流香激廟松。", "塵埃終不及，車馬自憧憧。"]'),
('3162fc3c-6966-4a74-a8dc-d7ff9f823bd5','京兆府試目極千里','劉得仁','唐','唐诗','tang','','[]','獻賦多年客，低眉恨不前。',72,'全唐诗/poet.tang.30000.json','["獻賦多年客，低眉恨不前。", "此心常鬱矣，縱目忽超然。", "送驥登長路，有鴻入遠天。", "古墟煙冪冪，窮野草綿綿。", "樹與金城接，山疑桂水連。", "何當開霽日，無物翳平川。"]'),
('b022a966-3974-4005-83f9-3e0fbad78f47','尋陳處士山堂','劉得仁','唐','唐诗','tang','','[]','步溪凡幾轉，始得見幽蹤。',96,'全唐诗/poet.tang.30000.json','["步溪凡幾轉，始得見幽蹤。", "路隱千根樹，門開萬仞峰。", "片雲生石竇，淺水臥枯松。", "窮谷風光冷，深山翠碧濃。", "鶴看空裏過，仙向坐中逢。", "底露秋潭水，聲微暮觀鐘。", "他年來此定，異日願相容。", "且喜今歸去，人間事更慵。"]'),
('0cf3e4fa-5683-4d0f-a788-4d99e9cccb0b','題從伯舍人道正里南園','劉得仁','唐','唐诗','tang','','[]','帝里餘新第，朱門面碧岑。',120,'全唐诗/poet.tang.30000.json','["帝里餘新第，朱門面碧岑。", "曙堂增爽氣，喬木動清陰。", "直去親瑤陛，朝迴在竹林。", "風流才子調，好尚古人心。", "薜荔遮窗暗，莓苔近井深。", "禮無青草隔，詩共白衣吟。", "軒靜留孤鶴，庭虛到遠砧。", "掩關裁鳳詔，開鏡理瓊簪。", "種植今如此，塵埃永不侵。", "雲奔投刺者，日日待爲霖。"]'),
('6777f6f1-7d62-44e7-b785-0fca3e34bb05','賦得聽松聲','劉得仁','唐','唐诗','tang','','[]','庭際微風動，高松韻自生。',72,'全唐诗/poet.tang.30000.json','["庭際微風動，高松韻自生。", "聽時無物亂，盡日覺神清。", "強與幽泉竝，翻嫌細雨幷。", "拂空增鶴唳，過牖合琴聲。", "況復當秋暮，偏宜在月明。", "不知深澗底，蕭瑟有誰聽。"]'),
('972f30a9-b76a-47e1-b075-2816554d79c5','宿普濟寺','劉得仁','唐','唐诗','tang','','[]','京寺數何窮，清幽此不同。',120,'全唐诗/poet.tang.30000.json','["京寺數何窮，清幽此不同。", "曲江臨閣北，御苑自牆東。", "廣陌車音急，危樓夕景通。", "亂峰沈暝野，毒暑過秋空。", "幡揚虛無裡，星生杳靄中。", "月光籠月殿，蓮氣入蓮宮。", "綴草涼天露，吹人古木風。", "飲茶除假寐，聞磬釋塵蒙。", "童子眠苔淨，高僧話漏終。", "待鳴曉鐘後，萬井復朣朧。"]'),
('52595d46-a77e-4a59-8a99-22e8845ea56a','和鄭校書夏日遊鄭泉','劉得仁','唐','唐诗','tang','','[]','太虛懸畏景，古木蔽清陰。',120,'全唐诗/poet.tang.30000.json','["太虛懸畏景，古木蔽清陰。", "爰有泉堪挹，閑思日可尋。", "來聞鳴滴滴，照竦碧沈沈。", "幾脉成溪壑，何人測淺深。", "澄時無一物，分處厲千林。", "淨溉靈根藥，涼浮玉翅禽。", "飲疑蠲宿疾，見自失煩襟。", "僧共雲前瀨，龍和月下吟。", "疊光輕吹動，徹底曉霞侵。", "不用頻遊去，令君少進心。"]'),
('29ad430b-4f67-43c7-bbd2-0a7020e2a9aa','和段校書冬夕寄題廬山','劉得仁','唐','唐诗','tang','','["\u5e90\u5c71"]','名高身未到，此恨蓄多時。',240,'全唐诗/poet.tang.30000.json','["名高身未到，此恨蓄多時。", "是夕吟因話，他年必去隨。", "嘗聞廬嶽頂，半入楚江湄。", "幾處懸崖上，千尋瀑布垂。", "爐峰松淅瀝，湓浦柳參差。", "日色連湖白，鐘聲拂浪遲。", "煙梯緣薜荔，嶽寺步欹危。", "地本饒靈草，林曾出祖師。", "石樓霞耀壁，猨樹鶴分枝。", "細徑縈巖末，高窗見海涯。", "嵌空寒更極，寂寞夜尤思。", "陰谷冰埋朮，仙田雪覆芝。", "亂泉禪客瀨，異迹逸人知。", "蘚室新開竈，檉潭末了棋。", "如何遂閑放，長得在希夷。", "空務漁樵事，方無道路悲。", "謝公臺尚在，陶令柳潛衰。", "塵外難相許，人間貴迹遺。", "雖懷丹桂影，不忘白雲期。", "仁者終攜手，今朝預賦詩。"]'),
('e9db9b28-6597-4bf5-a1da-1e7831c91184','書事寄萬年厲員外','劉得仁','唐','唐诗','tang','','["\u9ec4\u5c71"]','帝城皆劇縣，令尹美居東。',168,'全唐诗/poet.tang.30000.json','["帝城皆劇縣，令尹美居東。", "遂拜趙張下，蹔離星象中。", "擁歸從北闕，送上動南宮。", "紫禁黃山遶，滄溟素滻通。", "封疆親日月，邑里出王公。", "賦稅充天府，歌謠入聖聰。", "土膏寒麥覆，人海晝塵蒙。", "廨宇松連翠，朝街火散紅。", "文場新桂茂，粉署舊蘭崇。", "留客揮盈爵，抽毫詠早鴻。", "前騶潘岳貴，故里邵平窮。", "勸隱蓮峰久，期耕樹谷同。", "鳧飛將去葉，劒氣尚埋豐。", "何必華陰土，方垂拂拭功。"]'),
('905c8101-f5d9-4b47-95c1-3102068dba4b','上姚諫議','劉得仁','唐','唐诗','tang','','[]','高文與盛德，皆謂古無倫。',96,'全唐诗/poet.tang.30000.json','["高文與盛德，皆謂古無倫。", "聖代生才子，明庭有諫臣。", "已瞻龍衮近，漸向鳳池新。", "却憶波濤郡，來時島嶼春。", "名因詩句大，家似布衣貧。", "曾暗投新軸，頻聞獎滯身。", "照吟清夕月，送藥紫霞人。", "終計依門館，何疑不化鱗。"]'),
('e7aaf13e-81c3-4327-8477-d365443f8e03','上翰林丁學士','劉得仁','唐','唐诗','tang','','[]','今代如堯代，徵賢察衆情。',120,'全唐诗/poet.tang.30000.json','["今代如堯代，徵賢察衆情。", "久聆推行寔，然後佐聰明。", "官自文華重，恩因顧問生。", "詞人求作稱，天子許和羹。", "御柳凋霜晚，宮泉滴月清。", "直廬寒漏近，秋燭白麻成。", "玉殿移時對，金輿數侍行。", "賜衣香未散，借馬色難名。", "時輩何偏羨，儒流此最榮。", "終當聞夑理，寰宇永昇平。"]'),
('317e4d45-6475-4905-bab3-56fde484c321','二','劉得仁','唐','唐诗','tang','','[]','何處訪岐路，青雲但憶歸。',48,'全唐诗/poet.tang.30000.json','["何處訪岐路，青雲但憶歸。", "風塵數年限，門館一生依。", "外族帝王是，中朝親舊稀。", "翻令浮議者，不許九霄飛。"]'),
('d940c14b-44e3-4fa1-b3ae-7690fc7e97d9','山中舒懷寄上丁學士','劉得仁','唐','唐诗','tang','','[]','五字投精鑒，慙非大雅詞。',72,'全唐诗/poet.tang.30000.json','["五字投精鑒，慙非大雅詞。", "本求閑賜覽，豈料便蒙知。", "幽拙欣殊幸，提攜更不疑。", "弱苗須雨長，懶翼在風吹。", "礪鏃端楊葉，光門待桂枝。", "計聞塵裏譽，因和禁中詩。"]'),
('334f9b36-52a5-4240-b83c-12755ffe5d86','鶯出谷','劉得仁','唐','唐诗','tang','','[]','東風潛啓物，動息意皆新。',72,'全唐诗/poet.tang.30000.json','["東風潛啓物，動息意皆新。", "此鳥從幽谷，依林報早春。", "出寒雖未及，振羽漸能頻。", "稍類沖天鶴，多隨折桂人。", "尊前喧有語，花裏晝藏身。", "若向穠華處，餘禽不見親。"]'),
('7b0c00e0-5f71-46a7-8733-8b1abed9354f','哭翰林丁侍郎','劉得仁','唐','唐诗','tang','','[]','相知出肺腑，非舊亦非親。',96,'全唐诗/poet.tang.30000.json','["相知出肺腑，非舊亦非親。", "每見雲霄侶，多陽鄙拙身。", "即期扶泰運，豈料哭賢人。", "應是隨先帝，依前作近臣。", "平生任公直，愛弟尚風塵。", "宅閉青松古，墳臨赤水新。", "官清仍齒壯，兒小復家貧。", "惆悵天難問，空流淚滿巾。"]'),
('b0681f1f-81d3-478f-98c2-39bbd6a5657a','陳情上李景讓大夫','劉得仁','唐','唐诗','tang','','[]','一被浮名誤，旋遭白髮侵。',168,'全唐诗/poet.tang.30000.json','["一被浮名誤，旋遭白髮侵。", "裴回戀明主，夢寐在秋岑。", "遇物唯多感，居常只是吟。", "待時鉗定口，經事壓低心。", "辛苦文場久，因緣戚里深。", "老迷新道路，貧賣舊園林。", "晴賞行聞水，宵棊坐見參。", "龜留閑去問，僧約偶來尋。", "望喜潛憑鵲，娛情願有琴。", "此生如遂意，誓死報知音。", "上德憐孤直，唯公拔陸沈。", "丘山恩忽被，螻蟻力難任。", "作鑒明同日，聽言重若金。", "從茲更無限，翹足俟爲霖。"]'),
('16114419-f06b-44b5-af56-4af8fed1658e','和鄭先輩謝秩閑居寓書所懷','劉得仁','唐','唐诗','tang','','[]','西風日夜吹，萬木共離披。',120,'全唐诗/poet.tang.30000.json','["西風日夜吹，萬木共離披。", "近甸新晴後，高人得意時。", "暫閑心亦泰，論道面難欺。", "把筆還詩債，將琴當酒資。", "藍衫懸竹桁，烏帽挂松枝。", "名占文章重，官歸諫憲遲。", "生涯貧帝里，公議到台司。", "室冷沾苔蘚，門清絕路岐。", "莫言鄰白屋，即賀立丹墀。", "豈慮塵埃久，雲霄故有期。"]'),
('b18e6e00-7c44-484c-9197-f4cacdda35ca','病中晨起即事寄場中往還','劉得仁','唐','唐诗','tang','','[]','昨日離塵裏，今朝懶已成。',96,'全唐诗/poet.tang.30000.json','["昨日離塵裏，今朝懶已成。", "豈能爲久隱，更欲泥浮名。", "虛牖晨光白，幽園曉氣清。", "戴沙尋水去，披霧入林行。", "疊葉孤禽在，初陽半樹明。", "桑麻新雨潤，蘆荻古波聲。", "易向田家熟，元于世路生。", "病多三徑塞，吟苦四鄰驚。"]'),
('fd989d0a-b616-40a4-acda-574811deb1d6','悲老宮人','劉得仁','唐','唐诗','tang','','[]','白髮宮娃不解悲，滿頭猶自插花枝。',32,'全唐诗/poet.tang.30000.json','["白髮宮娃不解悲，滿頭猶自插花枝。", "曾緣玉貌君王寵，準擬人看似舊時。"]'),
('b4e71f6b-3ac3-4563-8a7f-23fb8edd286d','村中閑步','劉得仁','唐','唐诗','tang','','[]','閑共野人臨野水，新秋高樹挂清暉。',32,'全唐诗/poet.tang.30000.json','["閑共野人臨野水，新秋高樹挂清暉。", "不知塵里無窮事，白鳥雙飛入翠微。"]'),
('081391b5-bb6c-4fc0-89da-c68e67061117','上巳日','劉得仁','唐','唐诗','tang','','[]','未敢分明賞物華，十年如見夢中花。',32,'全唐诗/poet.tang.30000.json','["未敢分明賞物華，十年如見夢中花。", "遊人過盡衡門掩，獨自凭欄到日斜。"]'),
('bb6cae31-a706-4a2b-af71-f62dca8c9875','省試日上崔侍郎四首 一','劉得仁','唐','唐诗','tang','','[]','衣上年年淚血痕，只將懷抱訴乾坤。',32,'全唐诗/poet.tang.30000.json','["衣上年年淚血痕，只將懷抱訴乾坤。", "如今主聖臣賢日，豈致人間一物冤。"]'),
('4283ce43-ec9c-4b01-8986-93f7b261b55d','省試日上崔侍郎四首 二','劉得仁','唐','唐诗','tang','','[]','如病如癡二十秋，求名難得又難休。',32,'全唐诗/poet.tang.30000.json','["如病如癡二十秋，求名難得又難休。", "回看骨肉須堪恥，一著麻衣便白頭。"]'),
('27ad0030-f8e6-4193-8ead-5cb8709856d6','省試日上崔侍郎四首 三','劉得仁','唐','唐诗','tang','','[]','戚里稱儒媿小才，禮闈公道此時開。',32,'全唐诗/poet.tang.30000.json','["戚里稱儒媿小才，禮闈公道此時開。", "他人何事虛相指，明主無私不是媒。"]'),
('007a18ee-6f67-4323-84ef-db707f098030','省試日上崔侍郎四首 四','劉得仁','唐','唐诗','tang','','[]','方寸終朝似火然，爲求白日上青天。',32,'全唐诗/poet.tang.30000.json','["方寸終朝似火然，爲求白日上青天。", "自嗟辜負平生眼，不識春光二十年。"]'),
('720cddd2-8fb9-4c3b-9ab6-48843d9dc70d','秋夜','劉得仁','唐','唐诗','tang','','[]','秋氣滿堂孤燭冷，清宵無寐憶山歸。',32,'全唐诗/poet.tang.30000.json','["秋氣滿堂孤燭冷，清宵無寐憶山歸。", "窗前月過三更後，細竹吟風似雨微。"]'),
('8d95be93-4b1d-477d-9e26-773a89fb8588','長門怨','劉得仁','唐','唐诗','tang','','[]','爭得一人聞此怨，長門深夜有妍姝。',32,'全唐诗/poet.tang.30000.json','["爭得一人聞此怨，長門深夜有妍姝。", "早知雨露翻相悞，只插荆釵嫁匹夫。"]'),
('7d773f4b-7e6e-41be-8d98-6961f29ac814','賈婦怨','劉得仁','唐','唐诗','tang','','[]','嫁與商人頭欲白，未曾一日得雙行。',32,'全唐诗/poet.tang.30000.json','["嫁與商人頭欲白，未曾一日得雙行。", "任君逐利輕江海，莫把風濤似妾輕。"]'),
('8ae6c860-b5be-4270-ad3b-a57fcf7be7b0','寄友人','劉得仁','唐','唐诗','tang','','[]','風颯沈思眼忽開，塵埃污得是庸才。',32,'全唐诗/poet.tang.30000.json','["風颯沈思眼忽開，塵埃污得是庸才。", "那堪更見巢松鶴，飛入青雲不下來。"]'),
('470ffb4c-de73-46fa-8aeb-f773da19e394','晏起','劉得仁','唐','唐诗','tang','','[]','日過辰時猶在夢，客來應笑也求名。',32,'全唐诗/poet.tang.30000.json','["日過辰時猶在夢，客來應笑也求名。", "浮生自得長高枕，不向人間與命爭。"]'),
('22a7a7f5-8476-44da-9918-ccec79c42898','馬上別單于劉評事','劉得仁','唐','唐诗','tang','','[]','廟謀宏遠人難測，公主生還帝感深。',32,'全唐诗/poet.tang.30000.json','["廟謀宏遠人難測，公主生還帝感深。", "天下底平須共喜，一時閑事莫驚心。"]'),
('917638b9-f60e-4f06-adba-4b2564f8657c','贈從弟谷','劉得仁','唐','唐诗','tang','','[]','此世榮枯豈足驚，相逢惟要眼長青。',32,'全唐诗/poet.tang.30000.json','["此世榮枯豈足驚，相逢惟要眼長青。", "從來不愛三閭死，今日憑君莫獨醒。"]'),
('3c776f78-a13c-49a8-bba2-68cbb50a7a83','別山居','劉得仁','唐','唐诗','tang','','[]','萬壑千巖景象開，登臨未足又須回。',32,'全唐诗/poet.tang.30000.json','["萬壑千巖景象開，登臨未足又須回。", "憑師莫斷松間路，秋月圓時弟子來。"]'),
('8b745136-cb59-40fb-a44f-0db2dbd983fd','贈道人','劉得仁','唐','唐诗','tang','','[]','長在城中無定業，賣丹磨鏡兩途貧。',32,'全唐诗/poet.tang.30000.json','["長在城中無定業，賣丹磨鏡兩途貧。", "三山來往尋常事，不省曾驚市井人。"]'),
('60425d83-727c-4642-b19c-c7198a84d101','對月寄同志','劉得仁','唐','唐诗','tang','','[]','霜滿中庭月在林，塞鴻頻過又更深。',32,'全唐诗/poet.tang.30000.json','["霜滿中庭月在林，塞鴻頻過又更深。", "支頤不語相思坐，料得君心似我心。"]'),
('71afe261-2093-41ab-8b68-59d0bd4b91c3','憶鶴','劉得仁','唐','唐诗','tang','','[]','白絲翎羽丹砂頂，曉度秋煙出翠微。',32,'全唐诗/poet.tang.30000.json','["白絲翎羽丹砂頂，曉度秋煙出翠微。", "來向孤松枝上立，見人吟苦却高飛。"]'),
('b720a3be-ffef-4606-9884-129d27af9b6b','雲門寺','劉得仁','唐','唐诗','tang','','[]','上方僧又起，清磬出林初。',48,'全唐诗/poet.tang.30000.json','["上方僧又起，清磬出林初。", "吟苦曉燈暗，露零秋草疎。", "舊山多夢到，流水送愁餘。", "寄寺欲經歲，慚無親故書。"]'),
('d446a0c0-81f4-42df-ab74-26a4575dd893','中秋宿鄧逸人居','劉得仁','唐','唐诗','tang','','[]','偶與山僧宿，吟詩坐到明。',48,'全唐诗/poet.tang.30000.json','["偶與山僧宿，吟詩坐到明。", "夜涼耽月色，秋渴漱泉聲。", "磵木如竿聳，窗雲作片生。", "白衣閑自貴，不揖漢公卿。"]'),
('dace2ed2-8258-4d6e-9f0e-917be68a2012','句','劉得仁','唐','唐诗','tang','','[]','外家雖是帝，當路且無親。',76,'全唐诗/poet.tang.30000.json','["外家雖是帝，當路且無親。", "白日只如哭，黃泉免恨無。", "身閑甘旨下，白髮太平人。", "同遊芳草寺，見示白雲詩。", "猶祈啓金口，一爲動文權。", "深山寺路千層石，竹杖椶鞋便可登。"]'),
('3c64bb3c-68fd-4dc0-8830-3c319892b3a2','題山院','權審','唐','唐诗','tang','','[]','萬葉風聲利，一山秋氣寒。',24,'全唐诗/poet.tang.30000.json','["萬葉風聲利，一山秋氣寒。", "曉霜浮碧瓦，落日度朱欄。"]'),
('43199678-079e-4d21-8f2f-811c906c1d34','絕句','權審','唐','唐诗','tang','','[]','得即高歌失即休，多悲多恨謾悠悠。',32,'全唐诗/poet.tang.30000.json','["得即高歌失即休，多悲多恨謾悠悠。", "今朝有酒今朝醉，明日愁來明日愁。"]'),
('3a3ea083-2e71-4035-b46c-dedd73ed924b','郡中有懷寄上睦州員外杜十三兄','邢羣','唐','唐诗','tang','','[]','城枕溪流更淺斜，麗譙連帶邑人家。',66,'全唐诗/poet.tang.30000.json','["城枕溪流更淺斜，麗譙連帶邑人家。", "經冬野菜青青色，未臘山梅處處花。", "雖免嶂雲生嶺上，永無音信到天涯。", "如今歲[晏]從羈滯，心喜彈冠事不賒。"]'),
('22730452-aa1a-4986-99d7-68ea1b0a5eaa','早發靈芝望九華寄杜員外使君','曹汾','唐','唐诗','tang','','[]','戴月早辭三秀館，遲明初識久華峰。',64,'全唐诗/poet.tang.30000.json','["戴月早辭三秀館，遲明初識久華峰。", "嵯嵯玉劒寒鋩利，褭褭青蓮翠葉重。", "奇狀却疑人畫出，嵐光如爲客添濃。", "行春若到五溪上，此處褰帷正面逢。"]'),
('efdd2828-7392-4516-921c-6060a4e02842','落花','嚴惲','唐','唐诗','tang','','[]','春光冉冉歸何處，更向花前把一杯。',32,'全唐诗/poet.tang.30000.json','["春光冉冉歸何處，更向花前把一杯。", "盡日問花花不語，爲誰零落爲誰開。"]'),
('e6aec2d8-b762-419f-905f-8e2029dfc90f','題籌筆驛','殷潛之','唐','唐诗','tang','','[]','江東矜割據，鄴下奪孤嫠。',168,'全唐诗/poet.tang.30000.json','["江東矜割據，鄴下奪孤嫠。", "霸畧非匡漢，宏圖欲佐誰。", "奏書辭後主，仗劒出全師。", "重襲襃斜路，懸開反正旗。", "欲將苞有截，必使舉無遺。", "沈慮經謀際，揮毫決勝時。", "圜觚當分畫，前箸此操持。", "山秀扶英氣，川流入妙思。", "算成功在彀，運去事終虧。", "命屈天方厭，人亡國自隨。", "艱難推舊姓，開創極初基。", "總歎曾過地，寧探作教資。", "若歸新曆數，誰復顧衰危。", "報德兼明道，長留識者知。"]'),
('480467a5-65ca-4ff9-8a00-c3d2a2727f91','送高遂赴舉','祝元膺','唐','唐诗','tang','','[]','句曲舊宅真，自產日月英。',36,'全唐诗/poet.tang.30000.json','["句曲舊宅真，自產日月英。", "既涵嶽瀆氣，安無神仙名。", "松桂邐迤色，與君相送情。"]'),
('e8150221-6eed-4041-b2f2-c81c2a549452','寄道友','祝元膺','唐','唐诗','tang','','[]','兩頷凝清霜，玉爐焚天香。',24,'全唐诗/poet.tang.30000.json','["兩頷凝清霜，玉爐焚天香。", "爲我延歲華，得入不死鄉。"]'),
('338e07c8-8635-4582-b65d-d2e188a1ca37','夢仙謠','祝元膺','唐','唐诗','tang','','[]','蟾蜍夜作青冥燭，螮蝀晴爲碧落梯。',32,'全唐诗/poet.tang.30000.json','["蟾蜍夜作青冥燭，螮蝀晴爲碧落梯。", "好箇分明天上路，誰教深入武陵溪。"]'),
('d18a1dad-aa6d-4f2b-a423-615147b25135','句','祝元膺','唐','唐诗','tang','','[]','霧紋斑似豹，水力健如龍。',12,'全唐诗/poet.tang.30000.json','["霧紋斑似豹，水力健如龍。"]'),
('9852645a-b113-4fe7-bf47-1041aeea01a2','賀鄧璠使君正拜袁州','彭蟾','唐','唐诗','tang','','[]','六年惠愛及黎甿，大府論功俟陟明。',64,'全唐诗/poet.tang.30000.json','["六年惠愛及黎甿，大府論功俟陟明。", "尺一詔書天上降，二千石祿世間榮。", "新添畫戟門增峻，舊躡青雲路轉平。", "更待皇恩醒善政，碧油幢到郡齋迎。"]'),
('a4a38f84-7941-4773-8bd3-e9cd34fc754b','和嚴惲落花詩','王樞','唐','唐诗','tang','','[]','花落花開人世夢，衰榮閑事且持杯。',32,'全唐诗/poet.tang.30000.json','["花落花開人世夢，衰榮閑事且持杯。", "春風底事輕搖落，何似從來不要開。"]'),
('05e59e1f-fd53-47a0-a83c-1fce7862686a','詠宣律和尚袈裟','張希復','唐','唐诗','tang','','[]','共覆三衣中夜寒，披時不鎮尼師壇。',32,'全唐诗/poet.tang.30000.json','["共覆三衣中夜寒，披時不鎮尼師壇。", "無因蓋得龍宮地，畦裏塵飛葉相殘。"]'),
('cf7c54f7-8454-4621-bafd-e6096ae38434','鶯出谷','錢可復','唐','唐诗','tang','','[]','玉律陽和變，時禽羽翮新。',72,'全唐诗/poet.tang.30000.json','["玉律陽和變，時禽羽翮新。", "載飛初出谷，一囀已驚人。", "拂柳宜煙暖，衝花覺露春。", "摶風翻翰疾，向日弄吭頻。", "求友心何切，遷喬幸有因。", "華林高玉樹，棲託及芳晨。"]'),
('f6cdeee1-e60f-46d3-800c-aa308b59f6f0','鶯出谷','張鷺','唐','唐诗','tang','','[]','弱柳隨儔匹，遷鶯正及春。',72,'全唐诗/poet.tang.30000.json','["弱柳隨儔匹，遷鶯正及春。", "乘風音響遠，映日羽毛新。", "已得辭幽谷，還將脫俗塵。", "鴛鸞方可慕，燕雀迥無鄰。", "遊止知難屈，飜飛在此伸。", "一枝如借便，終冀託深仁。"]'),
('953d4fe0-ceeb-4707-92dd-3473f0d26424','鶯出谷','劉莊物','唐','唐诗','tang','','[]','幸因辭舊谷，從此及芳晨。',72,'全唐诗/poet.tang.30000.json','["幸因辭舊谷，從此及芳晨。", "欲語如調舌，初飛似畏人。", "風調歸影便，日煖吐聲頻。", "翔集知無阻，聯綿貴有因。", "喜遷喬木近，寧厭對花新。", "堪念微禽意，關關也愛春。"]'),
('e82ec8c2-9986-4696-946c-13abe1987f04','題呂食新水閣兼寄南商州郎中','朱景玄','唐','唐诗','tang','','[]','丹檻初結構，孤高冠清川。',48,'全唐诗/poet.tang.30000.json','["丹檻初結構，孤高冠清川。", "庭臨谷中樹，簷落山上泉。", "曉色挂殘月，夜聲雜繁絃。", "青春去如水，康樂歸何年。"]'),
('bcdfe5f3-ba4d-4692-8931-709895dcf1a0','華山南望春','朱景玄','唐','唐诗','tang','','[]','靈嶽多異狀，巉巉出虛空。',72,'全唐诗/poet.tang.30000.json','["靈嶽多異狀，巉巉出虛空。", "閑雲戀巖壑，起滅蒼翠中。", "皓氣澄野水，神光秘瓊宮。", "鶴巢前林雪，瀑落滿澗風。", "春盡花未發，川迴路難窮。", "何因著山屐，鹿跡尋羊公。"]'),
('0227fccd-0a08-4a4b-a2de-aa9d2969c1b2','水閣','朱景玄','唐','唐诗','tang','','[]','樓居半池上，澄影共相空。',24,'全唐诗/poet.tang.30000.json','["樓居半池上，澄影共相空。", "謝守題詩處，蓮開淨碧中。"]'),
('094c422e-ea03-42cd-baad-1da58efc0397','迎風亭','朱景玄','唐','唐诗','tang','','[]','山雨留清氣，溪飆送早涼。',24,'全唐诗/poet.tang.30000.json','["山雨留清氣，溪飆送早涼。", "時回石門步，階下碧雲光。"]'),
('8b1ef4ca-410a-4f20-b758-33faf4faf334','雙櫧亭','朱景玄','唐','唐诗','tang','','[]','連簷對雙樹，冬翠夏無塵。',24,'全唐诗/poet.tang.30000.json','["連簷對雙樹，冬翠夏無塵。", "未肯慙桃李，成陰不待春。"]'),
('f6b6c7d1-b222-4235-bb67-f75ac04393a6','蓮亭','朱景玄','唐','唐诗','tang','','[]','回塘最幽處，拍水小亭開。',24,'全唐诗/poet.tang.30000.json','["回塘最幽處，拍水小亭開。", "莫怪闌干溼，鵁鶄夜宿來。"]'),
('51ad6094-adc2-4a1d-b5cd-986bb04e2032','中峯亭','朱景玄','唐','唐诗','tang','','[]','中峯上翠微，窗曉早霞飛。',24,'全唐诗/poet.tang.30000.json','["中峯上翠微，窗曉早霞飛。", "幾引登山屐，春風踏雪歸。"]'),
('9c27bf3c-f7c5-41ec-a0f8-86dc7739bfdd','飛雲亭','朱景玄','唐','唐诗','tang','','[]','上結孤圓頂，飛軒出泰清。',24,'全唐诗/poet.tang.30000.json','["上結孤圓頂，飛軒出泰清。", "有時迷處所，梁棟曉雲生。"]'),
('efd5b98e-0945-4545-8249-c0e0e10a89e4','四望亭','朱景玄','唐','唐诗','tang','','[]','高亭羣峰首，四面俯晴川。',24,'全唐诗/poet.tang.30000.json','["高亭羣峰首，四面俯晴川。", "每見晨光曉，階前萬井煙。"]'),
('403c8ada-4a05-4ffc-9b9d-be7f2077f8fb','望蓮臺','朱景玄','唐','唐诗','tang','','[]','秋臺好登望，菡萏發清池。',24,'全唐诗/poet.tang.30000.json','["秋臺好登望，菡萏發清池。", "半似紅顏醉，凌波欲暮時。"]'),
('e932f96f-0c1b-4526-a14b-420a3368969c','茶亭','朱景玄','唐','唐诗','tang','','[]','靜得塵埃外，茶芳小華山。',24,'全唐诗/poet.tang.30000.json','["靜得塵埃外，茶芳小華山。", "此亭真寂寞，世路少人閑。"]'),
('b18f9cc2-c00f-4360-be22-5239aaf9350a','宿新安村步','朱景玄','唐','唐诗','tang','','[]','淅淅寒流漲淺沙，月明空渚徧蘆花。',32,'全唐诗/poet.tang.30000.json','["淅淅寒流漲淺沙，月明空渚徧蘆花。", "離人偶宿孤村下，永夜聞砧一兩家。"]'),
('7dfaefcc-d03b-49a3-81a1-a4b338a3f06a','遠聞本郡行春到舊山二首 一','朱景玄','唐','唐诗','tang','','[]','一身從宦留京邑，五馬遙聞到舊山。',32,'全唐诗/poet.tang.30000.json','["一身從宦留京邑，五馬遙聞到舊山。", "已領煙霞光野徑，深慚老幼候柴關。"]'),
('a889c4f3-38d2-45f9-8c7a-29931e72d844','遠聞本郡行春到舊山二首 二','朱景玄','唐','唐诗','tang','','[]','清風借響松筠外，畫隼停暉水石間。',32,'全唐诗/poet.tang.30000.json','["清風借響松筠外，畫隼停暉水石間。", "定掩溪名在圖傳，共知軒蓋此登攀。"]'),
('3efca3db-0930-42db-8ec5-f3006eb41351','和崔使君臨發不得觀積雪','朱景玄','唐','唐诗','tang','','[]','貧居稍與池塘近，旬日軒車不降來。',32,'全唐诗/poet.tang.30000.json','["貧居稍與池塘近，旬日軒車不降來。", "一樹瓊花空有待，曉風看落滿青苔。"]'),
('79e71022-c513-4c45-91af-bcebd74af647','句','朱景玄','唐','唐诗','tang','','[]','塞鴻先秋去，邊草入夏生。',12,'全唐诗/poet.tang.30000.json','["塞鴻先秋去，邊草入夏生。"]'),
('de245af8-9524-42fd-b981-25f5751f55ea','別青州妓段東美 一','薛宜僚','唐','唐诗','tang','','[]','經年郵驛許安棲，一會他鄉別恨迷。',32,'全唐诗/poet.tang.30000.json','["經年郵驛許安棲，一會他鄉別恨迷。", "今日海帆飄萬里，不堪腸斷對含啼。"]'),
('3c6b2b9c-7570-4a5a-8635-1857e0a01c9b','別青州妓段東美 二','薛宜僚','唐','唐诗','tang','','[]','阿母桃花方似錦，王孫草色正如煙。',32,'全唐诗/poet.tang.30000.json','["阿母桃花方似錦，王孫草色正如煙。", "不須更向滄溟望，惆悵歡情恰一年。"]'),
('08bbde96-16df-418c-a1be-cbf73918bd37','詠韋臯','郭圓','唐','唐诗','tang','','[]','宣父從周又適秦，昔賢誰少出風塵。',32,'全唐诗/poet.tang.30000.json','["宣父從周又適秦，昔賢誰少出風塵。", "當時甚訝張延賞，不識韋臯是貴人。"]'),
('0f0946e8-326e-4554-8826-8ecbc07bcc86','進宣宗收復河湟詩','崔鉉','唐','唐诗','tang','','[]','邊陲萬里注恩波，宇宙羣芳洽凱歌。',64,'全唐诗/poet.tang.30000.json','["邊陲萬里注恩波，宇宙羣芳洽凱歌。", "右地名王爭解辮，遠方戎壘盡投戈。", "煙塵永息三秋戍，瑞氣遙清九折河。", "共遇聖明千載運，更觀俗阜與時和。"]'),
('13e56361-c239-4005-9b7b-fd2ee27aa334','詠架上鷹','崔鉉','唐','唐诗','tang','','["\u5fd7\u5411", "\u548f\u7269", "\u5199\u9e1f", "\u548f\u7269\u8bd7", "\u9e1f"]','天邊心膽架頭身，欲擬飛騰未有因。',32,'全唐诗/poet.tang.30000.json','["天邊心膽架頭身，欲擬飛騰未有因。", "萬里碧霄終一去，不知誰是解絛人。"]'),
('13045d25-13a5-44a7-a4e9-be6d53718f6e','越亭二十韻','元晦','唐','唐诗','tang','','[]','乏才叨八使，徇祿非三顧。',240,'全唐诗/poet.tang.30000.json','["乏才叨八使，徇祿非三顧。", "南服頒詔條，東林證迷誤。", "未聞述職效，偶脫囂煩趣。", "激水濬㘭塘，緣崖欹磴步。", "西巖煥朝旭，深壑囊宿霧。", "影氣爽衣巾，涼颸輕杖履。", "臨高神慮寂，遠眺川原布。", "孤帆逗汀煙，飜鵶集江樹。", "獨探洞府靜，怳若偓佺遇。", "一瞬契真宗，百年成妄故。", "孱顏石戶啓，杳靄溪雲度。", "松籟韻宮商，鴛甍勢翔遡。", "津梁危彴架，濟物虛舟渡。", "環流馳羽觴，金英妬妝嫮。", "笳吟寒壘迥，鳥噪空山暮。", "悵望麋鹿心，低迴車馬路。", "懸冠謝陶令，褫珮懷疏傅。", "遐想蛻纓緌，徒慙卹襦袴。", "福盈禍之倚，權勝道所惡。", "何必棲禪關，無言自冥悟。"]'),
('b2c7731d-02ac-411c-859b-173c3e270460','除浙東留題桂郡林亭','元晦','唐','唐诗','tang','','[]','紫泥遠自金鑾降，朱斾翻馳鏡水頭。',64,'全唐诗/poet.tang.30000.json','["紫泥遠自金鑾降，朱斾翻馳鏡水頭。", "陶令風光偏畏夜，子牟衰鬢暗驚秋。", "西隣月色何時見，南國春光豈再游。", "莫遣豔歌催客醉，不堪回首翠蛾愁。"]'),
('7645f905-1a7f-4770-90cc-b8e49bf15d60','句','元晦','唐','唐诗','tang','','[]','石靜如開鏡，山高若聳蓮。',24,'全唐诗/poet.tang.30000.json','["石靜如開鏡，山高若聳蓮。", "筍竿抽玉管，花蔓綴金鈿。"]'),
('88a09882-7ba0-4d96-9527-f72370b41839','和元常侍除浙東留題','路貫','唐','唐诗','tang','','[]','謝安致理逾三載，黃霸清聲徹九重。',64,'全唐诗/poet.tang.30000.json','["謝安致理逾三載，黃霸清聲徹九重。", "猶輟珮環歸鳳闕，且將仁政到稽峯。", "林間立馬羅千騎，池上開筵醉一鍾。", "共喜甘棠有新詠，獨慚霜鬢又攀龍。"]'),
('33a668cd-706d-4c0d-9228-64c0c7aa533a','贈鞏疇','鄭薰','唐','唐诗','tang','','[]','密雪松桂寒，書窗導餘清。',240,'全唐诗/poet.tang.30000.json','["密雪松桂寒，書窗導餘清。", "風憾冰玉碎，階前琴磬聲。", "榻靜几硯潔，帙散縑緗明。", "高論展僧肇，精言資鞏生。", "立意加玄虛，析理分縱橫。", "萬化悉在我，一物安能驚。", "江海何所動，丘山常自平。", "遲速不相閡，後先徒起爭。", "鏡照分妍醜，秤稱分重輕。", "顏容寧入鑑，銖兩豈關衡。", "蘊微道超忽，剖鐙音泠泠。", "紙上掣牢鍵，舌端搖利兵。", "圓澈保直性，客塵排妄情。", "有住即非住，無行即是行。", "疏越捨朱絃，哇淫鄙秦箏。", "淡薄貴無味，羊斟慙大羹。", "洪遠包乾坤，幽窅潛沈冥。", "罔煩跬步舉，頓達萬里程。", "廬遠尚莫曉，隱留曾誤聽。", "直須持妙說，共詣毗耶城。"]'),
('772ad2f8-114d-4124-bc6b-b2f2bf7b1832','句','鄭薰','唐','唐诗','tang','','[]','項斯逢水部，誰道不關情。',12,'全唐诗/poet.tang.30000.json','["項斯逢水部，誰道不關情。"]'),
('39d6c425-ebb3-4d3a-9d6b-e6e3b06f4faa','鑷白曲','薛逢','唐','唐诗','tang','','[]','去年鑷白鬢，境裏猶堪認年少。',268,'全唐诗/poet.tang.30000.json','["去年鑷白鬢，境裏猶堪認年少。", "今年鑷白髮，兩眼昏昏手戰跳。", "滿酌濃酹假顏色，顏色不揚翻自笑。", "少年曾讀古人書，本期獨善安有餘。", "雖蓋長安一片瓦，未遑卒歲容寧居。", "前年依亞成都府，月請俸緍六十五。", "妻兒骨肉愁欲來，偏梁閣道歸得否。", "長安六月塵亙天，池塘鼎沸林欲燃。", "合家慟哭出門送，獨驅匹馬陵山巔。", "到官只是推誠信，終日兢兢幸無恡。", "丞相知憐爲小心，忽然奏佩專城印。", "專城俸入一倍多，況兼職祿霜峨峨。", "山妻稚女悉迎到，時列綠罇酣酒歌。", "醉來便向罇前倒，風月滿頭絲皓皓。", "雖然減得闔門憂，又加去國五年老。", "五年老，知奈何，來日少，去日多。", "金鎚鎚碎黃金鑷，更唱罇前老去歌。"]'),
('41200c91-3236-48c1-b23b-84b0695b0bc9','君不見','薛逢','唐','唐诗','tang','','[]','君不見，馬侍中，氣吞河朔稱英雄。',176,'全唐诗/poet.tang.30000.json','["君不見，馬侍中，氣吞河朔稱英雄。", "君不見，韋太尉，二十年前鎮蜀地。", "一朝冥漠歸下泉，功業勝名兩憔悴。", "奉誠園裏篙棘生，長興街南沙路平。", "當時帶礪在何處，今日子孫無地耕。", "或聞羈旅甘常調，簿尉文參各天表。", "清明縱便天使來，一把紙錢風樹杪。", "碑文半缺碑堂摧，祁連塚象狐兔開。", "野花似雪落何處，棠棃樹下香風來。", "馬侍中，韋太尉，盛去衰來片時事。", "人生倏忽一夢中，何必深深固權位。"]'),
('b56332c5-ea25-4e78-8f08-489da70fb0df','老去也','薛逢','唐','唐诗','tang','','[]','惆悵人生不滿百，一事無成頭雪白。',128,'全唐诗/poet.tang.30000.json','["惆悵人生不滿百，一事無成頭雪白。", "迴看幼累與老妻，俱是途中遠行客。", "匣中舊鏡照膽明，昔曾見我髭未生。", "朝巾暮櫛不自省，老皮皴皺文縱橫。", "合掌髻子蒜許大，此日方知非是我。", "暗數七旬能幾何，不覺中腸熱如火。", "老去也，爭奈何，敲酒盞，唱短歌。", "短歌未竟日已沒，月映西南庭樹柯。"]'),
('06df66db-1a03-4b81-8be2-f0ab109bc66e','追昔行','薛逢','唐','唐诗','tang','','[]','朝光如飛猶尚可，暮更如箭不容臥。',284,'全唐诗/poet.tang.30000.json','["朝光如飛猶尚可，暮更如箭不容臥。", "犍爲穿城更漏頻，一一皆從枕邊過。", "一夕凡幾更，一更凡幾聲。", "青春枉向鏡中老，白髮虛從愁裏生。", "曾窺帝里東鄰女，自比桃花鏡中許。", "一朝嫁得征戌兒，荷戈千里防秋去。", "去時只作旦暮期，別後生死俱不知。", "風驚粉色入蟬鬢，愁送鏡花潛墮枝。", "前年因出長安陌，見一女人頭雪白。", "日中扶杖憇樹陰，髣髴形容認相識。", "向予吁嗟還獨語，曾與君家鄰舍住。", "當時妾嫁與征人，幾向牆頭誚夫主。", "花開葉洛何推遷，屈指數當三十年。", "眉頭薤葉同枯葉，琴上朱弦成斷弦。", "嫁時寶鏡依然在，鵲影菱花滿光彩。", "夢裏長嗟離別多，愁中不覺顏容改。", "歎息人生能幾何，喜君顏貌未蹉跎。", "因君下馬重相顧，請奏青門腸斷歌。"]'),
('45775c39-7411-4d7d-bbb5-3355b6176989','醉春風','薛逢','唐','唐诗','tang','','[]','去年春似今年春，依舊野花愁殺人。',224,'全唐诗/poet.tang.30000.json','["去年春似今年春，依舊野花愁殺人。", "犍爲縣裏古城上，開是好花飛是塵。", "戲蝶狂蜂相往返，一枝花上聲千萬。", "時節先從暖處開，北枝未發南枝晚。", "江城太守鬚髯蒼，忽然置酒開華堂。", "歌兒舞女亦隨後，暫醉始知天地長。", "頃年曾作東周掾，同舍尋春屢開宴。", "斗門亭上柳如絲，洛水橋邊月如練。", "洛陽風俗不禁街，騎馬夜歸香滿懷。", "坐客爭吟雲碧句，美人醉贈珊瑚釵。", "日往月來何草草，今年又校三年老。", "槽中駿馬不能騎，惆悵落花開滿道。", "爲報時人知不知，看花對酒定無疑。", "君看野外孤墳下，石羊石馬是誰家。"]'),
('74f58e76-5109-410a-b85f-6c03da624eba','鄰相反行','薛逢','唐','唐诗','tang','','[]','東家有兒年十五，只向田園獨辛苦。',320,'全唐诗/poet.tang.30000.json','["東家有兒年十五，只向田園獨辛苦。", "夜開溝水遶稻田，曉叱耕牛墾塉土。", "西家有兒纔弱齡，儀容清峭雲鶴形。", "涉書獵史無早暮，坐期朱紫如拾青。", "東家西家兩相誚，西兒笑東東又笑。", "西云養志與榮名，彼此相非不同調。", "東家自云雖辛苦，躬耕早暮及所親。", "男舂女爨二十載，堂上未爲衰老人。", "朝機暮織還充體，餘者到兄還及弟。", "春秋伏臘長在家，不許妻奴暫違禮。", "爾今二十方讀書，十年取第三十餘。", "往來途路長離別，幾人便得昇公車。", "縱令得官身須老，銜恤終天向誰道。", "百年骨肉歸下泉，萬里枌榆長秋草。", "我今躬耕奉所天，耘鋤刈獲當少年。", "面上笑添今日喜，肩頭薪續廚中煙。", "縱使此身頭雪白，又有兒孫還稼穡。", "家藏一卷古孝經，世世相傳皆得力。", "爲報西家知不知，何須謾笑東家兒。", "生前不得供甘滑，歿後揚名徒爾爲。"]'),
('c9a971df-d466-4eb4-8dd6-c0ca17104ceb','靈臺家兄古鏡歌','薛逢','唐','唐诗','tang','','[]','一尺圓潭深黑色，篆文如絲人不識。',224,'全唐诗/poet.tang.30000.json','["一尺圓潭深黑色，篆文如絲人不識。", "耕夫云住赫連城，赫連城下親耕得。", "鏡上磨瑩一月餘，日中漸見菱花舒。", "金膏洗拭鉎澀盡，黑雲吐出新蟾蜍。", "人言此是千年物，百鬼聞之形暗慄。", "玉匣曾經龍照來，豈宜更鑒農夫質。", "有時霹靂半夜驚，窗中飛電如晦明。", "盤龍鱗脹玉匣溢，牙爪觸風時有聲。", "耕夫不解珍靈異，翻懼赫連神作祟。", "十千賣與靈臺兄，百丈靈湫坐中至。", "溢匣水色如玉傾，兒童不敢窺泓澄。", "寒光照人近不得，坐愁雷電湫中生。", "吾兄吾兄須愛惜，將來慎勿虛拋擲。", "興雲致雨會有時，莫譴紅牀穢靈跡。"]'),
('c0944f9f-23d3-4187-9968-bf7a253903dd','觀競渡','薛逢','唐','唐诗','tang','','["\u7aef\u5348\u8282"]','三月三日天清明，楊花繞江啼曉鶯。',224,'全唐诗/poet.tang.30000.json','["三月三日天清明，楊花繞江啼曉鶯。", "使君未出郡齋內，江上已聞齊和聲。", "使君出時皆有引，馬前已被紅旗陣。", "兩岸羅衣破鼻香，銀釵照日如霜刃。", "鼓聲三下紅旗開，兩龍躍出浮水來。", "擢影斡波飛萬劒，鼓聲劈浪鳴千雷。", "雷聲衝急波相近，兩龍望標目如瞬。", "江上人呼霹靂聲，竿頭綵挂虹霓暈。", "前船搶水已得標，後船失勢空揮橈。", "瘡眉血首爭不定，輸岸一朋心似燒。", "只將標示輸贏賞，兩岸十舟五來往。", "須臾戲罷各東西，競脫文身請書上。", "吾今細觀競渡兒，何殊當路權相持。", "不思得所各休去，會到摧舟折楫時。"]'),
('b5dffd51-debc-40e9-88ca-3289eda3e328','酬牛秀才登樓見示','薛逢','唐','唐诗','tang','','[]','旅館再經秋，心煩嬾上樓。',48,'全唐诗/poet.tang.30000.json','["旅館再經秋，心煩嬾上樓。", "年光同過隙，人事且隨流。", "骨肉憑書問，鄉關託夢遊。", "所嗟山郡酒，傾盡只添憂。"]'),
('83b107b3-f528-4431-9517-98be25067597','夏夜宴明月湖','薛逢','唐','唐诗','tang','','[]','夏夜宴南湖，琴觴興不孤。',48,'全唐诗/poet.tang.30000.json','["夏夜宴南湖，琴觴興不孤。", "月搖天上桂，星泛浦中珠。", "助照螢隨舫，添盤筍迸廚。", "聖朝思靜默，堪守谷中愚。"]'),
('c717d4bc-574c-4c04-a9a0-5292fad95c82','大水','薛逢','唐','唐诗','tang','','[]','暴雨逐驚雷，從風忽驟來。',48,'全唐诗/poet.tang.30000.json','["暴雨逐驚雷，從風忽驟來。", "浪驅三島至，江拆二儀開。", "勢恐圓樞折，聲疑厚軸摧。", "冥心問元化，天眼幾時回。"]'),
('d297092f-106d-4103-b3b2-32ffaca6ea56','席上酬東川嚴中丞敘舊見贈','薛逢','唐','唐诗','tang','','[]','昔記披雲日，今逾二十年。',48,'全唐诗/poet.tang.30000.json','["昔記披雲日，今逾二十年。", "聲名俱是夢，恩舊半歸泉。", "朱紱慙衰齒，紅妝慘別筵。", "離歌正淒切，休更促危弦。"]'),
('3d7985f7-339f-44be-843e-e5f422fbd804','禁火','薛逢','唐','唐诗','tang','','[]','日日冒煙塵，忽忽禁火辰。',48,'全唐诗/poet.tang.30000.json','["日日冒煙塵，忽忽禁火辰。", "塞榆關水濕，邊草賊迴春。", "歲月傷風邁，瘡痍念苦辛。", "沙中看白骨，腸斷故鄉人。"]'),
('c5799fb7-6f39-47fc-977c-1fb96fd2692e','詠柳','薛逢','唐','唐诗','tang','','[]','弱植驚風急自傷，暮來翻遣思悠揚。',64,'全唐诗/poet.tang.30000.json','["弱植驚風急自傷，暮來翻遣思悠揚。", "曾飄紫陌隨高下，敢拂朱闌競短長。", "縈砌乍飛還乍舞，撲池如雪又如霜。", "莫令歧路頻攀折，漸擬垂陰到畫堂。"]'),
('f8d102c4-b25b-412f-afce-35db35c339d9','宮詞','薛逢','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bab\u6028", "\u4e03\u8a00\u5f8b\u8bd7"]','十二樓中盡曉妝，望仙樓上望君王。',64,'全唐诗/poet.tang.30000.json','["十二樓中盡曉妝，望仙樓上望君王。", "鎖銜金獸連環冷，水滴銅龍晝漏長。", "雲髻罷梳還對鏡，羅衣欲換更添香。", "遙窺正殿簾開處，袍袴宮人掃御牀。"]'),
('84754054-2454-4cd3-9e91-ca20bf4f857a','長安春日','薛逢','唐','唐诗','tang','','[]','窮途日日困泥沙，上苑年年好物華。',64,'全唐诗/poet.tang.30000.json','["窮途日日困泥沙，上苑年年好物華。", "荆棘不當車馬道，管弦長奏綺羅家。", "王孫草上悠揚蝶，少女風前爛熳花。", "嬾出任從遊子笑，入門還是舊生涯。"]'),
('80277dbc-3144-475e-a8ec-e73c55eb0620','韋壽博書齋','薛逢','唐','唐诗','tang','','[]','玄晏先生已白頭，不隨鵷鷺狎羣鷗。',64,'全唐诗/poet.tang.30000.json','["玄晏先生已白頭，不隨鵷鷺狎羣鷗。", "元卿謝免開三逕，平仲朝歸臥一裘。", "醉後獨知殷甲子，病來猶作晉春秋。", "塵纓未濯今如此，野水無情處處流。"]'),
('db6aea33-c0f0-48f2-bf57-45378d3ed956','潼關河亭','薛逢','唐','唐诗','tang','','["\u6292\u60c5", "\u5730\u65b9", "\u5199\u666f"]','重岡如抱嶽如蹲，屈曲秦川勢自尊。',64,'全唐诗/poet.tang.30000.json','["重岡如抱嶽如蹲，屈曲秦川勢自尊。", "天地併功開帝宅，山河相湊束龍門。", "櫓聲嘔軋中流渡，柳色微茫遠岸村。", "滿眼波濤終古事，年來惆悵與誰論。"]'),
('6890770d-3fbf-4b79-95c6-7d34f4557fc5','送衢州崔員外','薛逢','唐','唐诗','tang','','[]','笑分銅虎別京師，嶺下山川想到時。',64,'全唐诗/poet.tang.30000.json','["笑分銅虎別京師，嶺下山川想到時。", "紅樹暗藏殷浩宅，綠蘿深覆偃王祠。", "風茅向暖抽書帶，露竹迎風舞釣絲。", "休指巖西數歸日，知君已負白雲期。"]'),
('74b46808-0fd0-4887-85d7-a1a7e9a4ba9e','開元後樂','薛逢','唐','唐诗','tang','','[]','莫奏開元舊樂章，樂中歌曲斷人腸。',64,'全唐诗/poet.tang.30000.json','["莫奏開元舊樂章，樂中歌曲斷人腸。", "鄶王玉笛三更咽，虢國金車十里香。", "一自犬戎生蘇北，便從征戰老汾陽。", "中原駿馬搜求盡，沙苑年來草又芳。"]'),
('137b41ce-9cd7-4095-9c7d-d975f8e44d2f','漢武宮辭','薛逢','唐','唐诗','tang','','[]','漢武清齋夜築壇，自斟明水醮仙官。',64,'全唐诗/poet.tang.30000.json','["漢武清齋夜築壇，自斟明水醮仙官。", "殿前玉女移香案，雲際金人捧露盤。", "絳節幾時還入夢，碧桃何處更驂鸞？", "茂陵煙雨埋弓劒，石馬無聲蔓草寒。"]'),
('58a5a604-ed17-4c12-96b0-a4bec56c35e4','潼關驛亭','薛逢','唐','唐诗','tang','','[]','河上關門日日開，古今名利旋堪哀。',64,'全唐诗/poet.tang.30000.json','["河上關門日日開，古今名利旋堪哀。", "終軍壯節埋黃土，楊震豐碑翳綠苔。", "寸祿應知霑有分，一官常懼處非才。", "猶驚往歲同袍者，尚逐江東計吏來。"]'),
('e965659f-a5b3-4a5d-991d-8c24b35d23e3','五峯隠者','薛逢','唐','唐诗','tang','','[]','煙霞壁立水溶溶，路轉崖回旦暮中。',64,'全唐诗/poet.tang.30000.json','["煙霞壁立水溶溶，路轉崖回旦暮中。", "鸂鶒畏人沈澗月，山羊投石挂巖松。", "高齋既許陪雲宿，晚稻何妨爲客舂。", "今日見君嘉遯處，悔將名利役疎慵。"]'),
('1784cb92-b5fb-4807-9534-e4e1bef1bed1','上吏部崔相公','薛逢','唐','唐诗','tang','','[]','龍門曾共戰驚瀾，雷電浮雲出濬湍。',64,'全唐诗/poet.tang.30000.json','["龍門曾共戰驚瀾，雷電浮雲出濬湍。", "紫府有名同羽化，碧霄無路却泥蟠。", "公車未結王生襪，客路虛彈貢禹冠。", "今日罏錘任真宰，暫回風水不應難。"]'),
('761e760f-4273-498e-a16b-db8103063604','送劉郎中牧杭州','薛逢','唐','唐诗','tang','','[]','一州橫制浙江灣，臺榭參差積翠間。',64,'全唐诗/poet.tang.30000.json','["一州橫制浙江灣，臺榭參差積翠間。", "樓下潮回滄海浪，枕邊雲起剡溪山。", "吳江水色連隄闊，越俗舂聲隔岸還。", "聖代牧人無遠近，好將能事濟清閑。"]'),
('4bfc547e-9d40-41b7-8657-732438d3a94a','貧女吟','薛逢','唐','唐诗','tang','','[]','殘妝滿面淚闌干，幾許幽情欲話難。',64,'全唐诗/poet.tang.30000.json','["殘妝滿面淚闌干，幾許幽情欲話難。", "雲髻嬾梳愁拆鳳，翠蛾羞照恐驚鸞。", "南鄰送女初鳴珮，北里迎妻已夢蘭。", "惟有深閨顦顇質，年年長凭繡牀看。"]'),
('ea79dd90-e7c9-4670-8b12-b719b6017adc','夜宴觀妓','薛逢','唐','唐诗','tang','','[]','燈火熒煌醉客豪，捲簾羅綺豔仙桃。',64,'全唐诗/poet.tang.30000.json','["燈火熒煌醉客豪，捲簾羅綺豔仙桃。", "纖腰怕束金蟬斷，鬢髪宜簪白燕高。", "愁傍翠蛾深八字，笑回丹臉利雙刀。", "無因得薦陽臺夢，願拂餘香到緼袍。"]'),
('7d0b8eb1-c46c-4712-a990-58dac6e315aa','送西川杜司空赴鎮','薛逢','唐','唐诗','tang','','[]','黑眉玄髪尚依然，紫綬金章五十年。',64,'全唐诗/poet.tang.30000.json','["黑眉玄髪尚依然，紫綬金章五十年。", "三入鳳池操國柄，八分龍節付兵權。", "東周城闕中天外，西蜀樓臺落日邊。", "莫遣洪罏曠真宰，九流人物待陶甄。"]'),
('83a43f0f-fe2b-43fa-aa38-dfcef972561f','長安夜雨','薛逢','唐','唐诗','tang','','["\u5199\u96e8", "\u6292\u6000", "\u5199\u666f", "\u96e8"]','滯雨通宵又徹明，百憂如草雨中生。',64,'全唐诗/poet.tang.30000.json','["滯雨通宵又徹明，百憂如草雨中生。", "心關桂玉天難曉，運落風波夢亦驚。", "壓樹早鴉飛不散，到窗寒鼓濕無聲。", "當年志氣俱消盡，白髮新添四五莖。"]'),
('262b4f83-7832-4869-b1ca-b9e976b516c6','獵騎','薛逢','唐','唐诗','tang','','[]','兵印對封入衛稀，碧空雲盡早霜微。',64,'全唐诗/poet.tang.30000.json','["兵印對封入衛稀，碧空雲盡早霜微。", "滻川桑落鵰初下，渭曲禾收兔正肥。", "陌上管弦清似語，草頭弓馬疾如飛。", "豈知萬里黃雲戍，血迸金瘡臥鐵衣。"]'),
('e9f1da0e-55fc-4cb7-b93f-f001875badd7','金城宮','薛逢','唐','唐诗','tang','','[]','憶昔明皇初御天，玉輿頻此駐神仙。',64,'全唐诗/poet.tang.30000.json','["憶昔明皇初御天，玉輿頻此駐神仙。", "龍盤藻井噴紅豔，獸坐金牀吐碧煙。", "雲外笙歌岐薛醉，月中臺榭后妃眠。", "自從戎馬生河雒，深鎖篷萊一百年。"]'),
('844f3fbc-a8b3-4e49-8913-d47695aa2a56','驚秋','薛逢','唐','唐诗','tang','','[]','露竹風蟬昨夜秋，百年心事付東流。',64,'全唐诗/poet.tang.30000.json','["露竹風蟬昨夜秋，百年心事付東流。", "明霜義分成虛話，阜俗文章惜暗投。", "長笑李斯稱溷鼠，每多莊叟喻犧牛。", "五湖煙水盈歸夢，蘆荻花中一釣舟。"]'),
('dea0c397-51f7-4b44-ae9a-b641b0921b64','六街塵','薛逢','唐','唐诗','tang','','[]','六街塵起鼓鼕鼕，馬足車輸在處通。',64,'全唐诗/poet.tang.30000.json','["六街塵起鼓鼕鼕，馬足車輸在處通。", "百役並驅衣食內，四民長走路岐中。", "年光與物隨流水，世事如花落曉風。", "名利到身無了日，不知今古旋成空。"]'),
('e1282111-bc60-450c-991d-21cda510cb5b','悼古','薛逢','唐','唐诗','tang','','[]','細推今古事堪愁，貴賤同歸土一丘。',64,'全唐诗/poet.tang.30000.json','["細推今古事堪愁，貴賤同歸土一丘。", "漢武玉堂人豈在，石家金谷水空流。", "光陰自旦還將暮，草木從春又到秋。", "閑事與時俱不了，且將身暫醉鄉遊。"]'),
('6f35d619-7910-4914-82cc-1ee193b68b2e','九華觀廢月池','薛逢','唐','唐诗','tang','','[]','曾發簫聲水檻前，夜蟾寒沼兩嬋娟。',64,'全唐诗/poet.tang.30000.json','["曾發簫聲水檻前，夜蟾寒沼兩嬋娟。", "微波有恨終歸海，明月無情却上天。", "白鳥帶將林外雪，綠荷枯盡渚中蓮。", "榮華不肯人間住，須讀莊生第一篇。"]'),
('d9b924bc-a4be-4698-bfc1-09490ec8208a','社日遊開元觀','薛逢','唐','唐诗','tang','','[]','松栢當軒蔓桂籬，古壇衰草暮風吹。',64,'全唐诗/poet.tang.30000.json','["松栢當軒蔓桂籬，古壇衰草暮風吹。", "荒涼院宇無人到，寂寞煙霞只自知。", "浪漬法堂餘像設，水存虛殿半科儀。", "因求天寶年中夢，故事分明載折碑。"]'),
('4122ca02-e173-4081-9cd7-4e9ddb0eaddd','九日曲池遊眺','薛逢','唐','唐诗','tang','','[]','陌上秋風動酒旗，江頭絲竹競相追。',64,'全唐诗/poet.tang.30000.json','["陌上秋風動酒旗，江頭絲竹競相追。", "正當海晏河清日，便是修文偃武時。", "繡轂盡爲行樂伴，豔歌皆屬太平詩。", "微臣辛忝頒堯曆，一望郊原愜所思。"]'),
('d655fe8d-a977-4a12-8eb4-59a7e9107929','九日郡齋有感','薛逢','唐','唐诗','tang','','[]','白日貪長夜更長，百般無意更思量。',64,'全唐诗/poet.tang.30000.json','["白日貪長夜更長，百般無意更思量。", "三冬不見秦中雪，九日惟添鬢畔霜。", "霞泛水文沈暮色，樹凌金氣發秋光。", "樓前野菊無多少，一雨重開一番黃。"]'),
('41dd47a5-48d2-43b0-a7d0-0af96d204781','九日嘉州發軍亭即事','薛逢','唐','唐诗','tang','','[]','三江分注界平沙，何處雲山是我家？',64,'全唐诗/poet.tang.30000.json','["三江分注界平沙，何處雲山是我家？", "無鶴洲中翻白浪，掬金灘上折黃花。", "不愁故國歸無日，却恨浮名苦有涯。", "向暮灑酣賓客散，水天狼籍變餘霞。"]'),
('b7d3d061-240d-4a68-926c-940f6cad8ab6','九日雨中言懷','薛逢','唐','唐诗','tang','','["\u957f\u6c5f"]','餻果盈前益自愁，那堪風雨滯刀州。',64,'全唐诗/poet.tang.30000.json','["餻果盈前益自愁，那堪風雨滯刀州。", "單牀冷席他鄉夢，紫榝黃花故國秋。", "萬里音書何寂寂，百年生計甚悠悠。", "潛將滿眼思家淚，灑寄長江東北流。"]'),
('892c452f-6c23-4f2f-a23e-26c2fe94e268','題劒門先寄上西蜀杜司徒','薛逢','唐','唐诗','tang','','[]','峭壁橫空限一隅，劃開元氣建洪樞。',64,'全唐诗/poet.tang.30000.json','["峭壁橫空限一隅，劃開元氣建洪樞。", "梯航百貨通邦計，鍵閉諸蠻屏帝都。", "西蹙犬戎威北狄，南吞荆郢制東吳。", "千年管鑰誰熔範，只自先天造化爐。"]'),
('fda76f96-b6f7-4f89-8a63-0c769a123c95','八月初一駕幸延喜樓看冠帶降戎','薛逢','唐','唐诗','tang','','[]','城頭旭日照闌干，城下降戎綵仗攢。',64,'全唐诗/poet.tang.30000.json','["城頭旭日照闌干，城下降戎綵仗攢。", "九陌塵埃千騎合，萬方臣妾一聲歡。", "樓臺乍仰中天易，衣服初迴左袵難。", "清水莫教波浪濁，從今赤嶺屬長安。"]'),
('7956dc78-719c-467f-952d-66d722286cc2','送司徒相公赴闕','薛逢','唐','唐诗','tang','','[]','丞相銜恩赴闕時，錦城寒菊始離披。',64,'全唐诗/poet.tang.30000.json','["丞相銜恩赴闕時，錦城寒菊始離披。", "龍媒舊識朝天路，雞樹長虛入夢枝。", "十載殿廷連步武，雨來庸蜀撫疲羸。", "莫愁中土無人識，自有明明聖主知。"]'),
('99eb076d-def1-4ef2-a55f-3ff3b29e12d3','送靈州田尚書','薛逢','唐','唐诗','tang','','[]','陰風獵獵滿旗竿，白草颼颼劒氣攢。',64,'全唐诗/poet.tang.30000.json','["陰風獵獵滿旗竿，白草颼颼劒氣攢。", "九姓羌渾隨漢節，六州蕃落從戎鞍。", "霜中入塞琱弓硬，月下翻營玉帳寒。", "今曰路傍誰不指，穰苴門戶慣登壇。"]'),
('aa45e9c6-4aff-400b-ba98-83b47165def2','座中走筆送前蕭使君','薛逢','唐','唐诗','tang','','[]','笙歌慘慘咽離筵，槐柳陰陰五月天。',64,'全唐诗/poet.tang.30000.json','["笙歌慘慘咽離筵，槐柳陰陰五月天。", "未學蘇秦榮佩印，却思平子賦歸田。", "芙蓉欲綻溪邊蘂，楊柳初迷渡口煙。", "自笑無成今老大，送君垂淚郭門前。"]'),
('2cd547fa-bda2-4ac3-abf5-e8d7d0c2f952','重送徐州李從事商隠','薛逢','唐','唐诗','tang','','[]','曉乘征騎帶犀渠，醉別都門慘袂初。',64,'全唐诗/poet.tang.30000.json','["曉乘征騎帶犀渠，醉別都門慘袂初。", "蓮府望高秦御史，柳營官重漢尚書。", "斬蛇澤畔人煙曉，戲馬臺前樹影疎。", "尺組挂身何用處，古來名利盡丘墟。"]'),
('3397705d-20b5-4616-b211-351595710999','醉中聞甘州','薛逢','唐','唐诗','tang','','["\u9ec4\u6cb3"]','老聽笙歌亦解愁，醉中因遣合甘州。',64,'全唐诗/poet.tang.30000.json','["老聽笙歌亦解愁，醉中因遣合甘州。", "行追赤嶺千山外，坐想黃河一曲流。", "日暮豈堪征婦怨，路傍能結旅人愁。", "左綿刺史心先死，淚滿朱弦催白頭。"]'),
('c1b268ab-3f09-4a31-ad7f-8d2dc7c0c463','北亭醉後敘舊贈東川陳書記','薛逢','唐','唐诗','tang','','[]','二十年前事盡空，半隨波浪半隨風。',64,'全唐诗/poet.tang.30000.json','["二十年前事盡空，半隨波浪半隨風。", "謀身喜斷韓雞尾，辱命羞攜楚鵲籠。", "符竹謬分錦水外，妻孥猶隔散關東。", "臨岐莫怪朱弦絕，曾是君家入爨桐。"]'),
('d0fb739a-d8c0-4a6c-8c83-0b3db4d16f1c','宣政殿前陪位觀冊順宗憲宗皇帝尊號','薛逢','唐','唐诗','tang','','[]','樓頭鐘鼓遰相催，曙色當衙曉仗開。',64,'全唐诗/poet.tang.30000.json','["樓頭鐘鼓遰相催，曙色當衙曉仗開。", "孔雀扇分香案出，兖龍衣動冊函來。", "金泥照耀傳中旨，玉節從容引上台。", "盛禮永尊徽號畢，聖慈南面不勝哀。"]'),
('ef00ac2c-afcc-400c-817f-bbbe94cf5349','元日樓前觀仗 一','薛逢','唐','唐诗','tang','','[]','千門曙色鏁寒梅，五夜疎鐘曉箭催。',64,'全唐诗/poet.tang.30000.json','["千門曙色鏁寒梅，五夜疎鐘曉箭催。", "寶馬占隄朝闕去，香車爭路進名來。", "天臨玉几班初合，日照金雞仗欲迴。", "更傍紫微瞻北斗，上林佳氣滿樓臺。"]'),
('295f8a4c-3034-4df6-b4f4-fb1de6c6aeaf','元日樓前觀仗 二','薛逢','唐','唐诗','tang','','[]','曈曈初日照樓臺，漠漠祥雲雉扇開。',64,'全唐诗/poet.tang.30000.json','["曈曈初日照樓臺，漠漠祥雲雉扇開。", "星駐冕旒三殿曉，雲翻珠翠六宮來。", "山呼聖壽煙霞動，風轉金章鳥獸迴。", "欲識普恩無遠近，萬方歡忭一聲雷。"]'),
('e9d762c8-8e3d-48b1-ace5-4181634c2be3','醉中看花因思去歲之任','薛逢','唐','唐诗','tang','','[]','去歲乘軺出上京，軍機旦暮促前程。',64,'全唐诗/poet.tang.30000.json','["去歲乘軺出上京，軍機旦暮促前程。", "狂花野草途中恨，春月秋風劒外情。", "愁見瘴煙遮路色，厭聞溪水下灘聲。", "不辭醉伴諸年少，羞對紅妝白髮生。"]'),
('96108962-a252-499d-b7ff-146a354f6c09','題白馬驛','薛逢','唐','唐诗','tang','','[]','晚麥芒乾風似秋，旅人方作蜀門遊。',64,'全唐诗/poet.tang.30000.json','["晚麥芒乾風似秋，旅人方作蜀門遊。", "家林漸隔梁山遠，客路長依漢水流。", "滿壁存亡俱是夢，百年榮辱盡堪愁。", "胸中憤氣文難遣，強指豐碑哭武侯。"]'),
('7aa9d8cf-dbf6-46bb-9ed1-48b489a8625d','題籌筆驛','薛逢','唐','唐诗','tang','','[]','天地三分魏蜀吳，武侯倔起贊訐謨。',64,'全唐诗/poet.tang.30000.json','["天地三分魏蜀吳，武侯倔起贊訐謨。", "身依豪杰傾心術，目對雲山演陣圖。", "赤伏運衰功莫就，皇綱力振命先徂。", "出師表上留遺懇，猶自千年激壯夫。"]'),
('94ac5ef8-fa10-465b-a629-939653523713','賀楊收作相','薛逢','唐','唐诗','tang','','[]','闕下憧憧車馬塵，沈浮相次宦遊身。',64,'全唐诗/poet.tang.30000.json','["闕下憧憧車馬塵，沈浮相次宦遊身。", "須知金印朝天客，同是沙隄避路人。", "威鳳偶時因瑞聖，應龍無水謾通神。", "立門不是趨時客，始向窮途學問津。"]'),
('dd70acae-5721-4c7b-ae07-e13eea441f49','元日田家','薛逢','唐','唐诗','tang','','[]','南村晴雪北村梅，樹裏茅簷曉盡開。',64,'全唐诗/poet.tang.30000.json','["南村晴雪北村梅，樹裏茅簷曉盡開。", "蠻榼出門兒婦去，烏龍迎路女郎來。", "相逢但祝新正壽，對舉那愁暮景催。", "長笑士林因宦別，一官輕是十年迴。"]'),
('6d7fa106-862f-43a4-96ae-0a2f9ae8d066','送慶上人歸湖州因寄道儒座主','薛逢','唐','唐诗','tang','','[]','上人今去白蘋洲，霅水苕溪我舊遊。',64,'全唐诗/poet.tang.30000.json','["上人今去白蘋洲，霅水苕溪我舊遊。", "夜雨暗江漁火出，夕陽沈浦鴈花收。", "閑聽別鳥啼紅樹，醉看歸僧櫂碧流。", "若見儒公憑寄語，數莖霜鬢已驚秋。"]'),
('57c68237-4db2-4b29-b7b9-939975ff9171','早發剡山','薛逢','唐','唐诗','tang','','[]','正懷何謝俯長流，更覽餘封識嵊州。',64,'全唐诗/poet.tang.30000.json','["正懷何謝俯長流，更覽餘封識嵊州。", "樹色老依官舍晚，溪聲涼傍客衣秋。", "南巖氣爽橫郛郭，天姥雲晴拂寺樓。", "日暮不堪還上馬，蓼花風起路悠悠。"]'),
('24ca27ef-6e52-446c-9685-0d82b9098910','題春臺觀','薛逢','唐','唐诗','tang','','[]','殿前松柏晦蒼蒼，杏遶仙壇水遶廊。',64,'全唐诗/poet.tang.30000.json','["殿前松柏晦蒼蒼，杏遶仙壇水遶廊。", "垂露額題精思院，博山爐褭降真香。", "苔侵古碣迷陳事，雲到中峯失上方。", "便擬尋溪弄花去，洞天誰更待劉郎。"]'),
('5dc7a7a3-27ed-4b56-b96d-1167b1279057','春晚東園曉思','薛逢','唐','唐诗','tang','','[]','劒外春餘日更長，東園留醉樂高張。',64,'全唐诗/poet.tang.30000.json','["劒外春餘日更長，東園留醉樂高張。", "松杉露滴無情淚，桃杏風飄不語香。", "鶯戀葉深啼綠樹，燕窺巢穩坐彫梁。", "也知留滯年華晚，爭那罇前樂未央。"]'),
('c17fd378-8147-4a0f-971a-26f6be7d1963','芙蓉溪送前資州裴使君歸京寧拜戶部裴侍郎','薛逢','唐','唐诗','tang','','[]','桑柘林枯𪍷麥乾，欲分離袂百憂攢。',64,'全唐诗/poet.tang.30000.json','["桑柘林枯𪍷麥乾，欲分離袂百憂攢。", "臨溪莫話前途遠，舉酒須歌後會難。", "薄宦未甘霜髪改，夾衣猶耐水風寒。", "遙知阮巷歸寧日，幾院兒童候馬看。"]'),
('a0f26ab9-6bb2-4715-98b7-5d5db8e6c99e','伏聞令公疾愈對見延英因有賀詩遠封投獻','薛逢','唐','唐诗','tang','','[]','吉語云云海外傳，令公疾愈起朝天。',64,'全唐诗/poet.tang.30000.json','["吉語云云海外傳，令公疾愈起朝天。", "皇風再扇寰區內，人鏡重開日月邊。", "光啓四門通壽域，深疏萬頃溉情田。", "陪臣自訝迷津久，願識方舟濟巨川。"]'),
('4655da21-244c-4436-8345-7373bba1c0f1','題獨孤處士村居','薛逢','唐','唐诗','tang','','[]','江上園盧荆作扉，男驅耕犢婦鳴機。',64,'全唐诗/poet.tang.30000.json','["江上園盧荆作扉，男驅耕犢婦鳴機。", "林巒當戶蔦蘿暗，桑柘繞村薑芋肥。", "幾畝稻田還謂業，兩間茆舍亦言歸。", "何如一被風塵染，到老云云相是非。"]'),
('d7ed0761-f51d-4b84-9869-2110ce293502','題上皇觀','薛逢','唐','唐诗','tang','','[]','狂寇窮兵犯帝畿，上皇曾此振戎衣。',64,'全唐诗/poet.tang.30000.json','["狂寇窮兵犯帝畿，上皇曾此振戎衣。", "門前衛士傳清警，砌下奚官掃翠微。", "雲駐壽宮三洞啓，日迴仙仗六龍歸。", "當時丹鳳銜書處，老柏蒼蒼已合圍。"]'),
('35efc93b-b880-4dd2-9414-0e33c08ea56f','奉和僕射相公送東川李支使歸使府夏侯相公','薛逢','唐','唐诗','tang','','[]','兩地交通布政和，上台深喜使星過。',64,'全唐诗/poet.tang.30000.json','["兩地交通布政和，上台深喜使星過。", "歡留白日千鐘酒，調入青雲一曲歌。", "寒柳翠添微雨重，臘梅香綻細枝多。", "平津萬一言卑散，莫忘高松寄女蘿。"]'),
('6f04518b-de2d-482e-a487-9384dcee97a0','送封尚書節制興元','薛逢','唐','唐诗','tang','','[]','大封茅土鎮襃中，醉出都門殺氣雄。',64,'全唐诗/poet.tang.30000.json','["大封茅土鎮襃中，醉出都門殺氣雄。", "陌上晚花迎虎節，馬前新月學彎弓。", "珂臨響澗聲先合，斾到春山色更紅。", "欲識真心報天子，滿旗全是發生風。"]'),
('717c4918-44a8-43a3-9d6b-7ac1185e16ab','送西川梁常侍之新築龍山城幷錫賚兩州刺史及部落酋長等','薛逢','唐','唐诗','tang','','[]','聖主憂夷貊，屯師翦束欽。',168,'全唐诗/poet.tang.30000.json','["聖主憂夷貊，屯師翦束欽。", "皇家思眷祐，星使忽登臨。", "用命期開國，違天必釁碪。", "化須均草樹，恩不間飛沈。", "束馬凌蒼壁，捫蘿上碧岑。", "瘴川風自熱，劒閣氣長陰。", "迅瀨從天急，喬松入地深。", "仰觀唯一逕，俯瞰即千尋。", "水作新城帶，山爲故壘襟。", "東開洞君聽，南闢納蠻心。", "渥澤濡三部，衣冠化雨林。", "帶文雕白玉，符理篆黃金。", "鳥道經邛𤏡，星纏過觜參。", "迴軒如睿獎，休作苦辛吟。"]'),
('c1651595-e5a0-4960-a1ce-3373f5e3726b','河滿子','薛逢','唐','唐诗','tang','','[]','繫馬宮槐老，持杯店菊黃。',24,'全唐诗/poet.tang.30000.json','["繫馬宮槐老，持杯店菊黃。", "故交今不見，流恨滿川光。"]'),
('e3ea1c9d-0de9-4738-97fb-034154b7b740','題黃花驛','薛逢','唐','唐诗','tang','','[]','孤戍迢迢蜀路長，鳥鳴山館客思鄉。',32,'全唐诗/poet.tang.30000.json','["孤戍迢迢蜀路長，鳥鳴山館客思鄉。", "更看絕頂煙霞外，數樹巖花照夕陽。"]'),
('b8f5de04-887e-48ca-93f6-693c7b50cb66','涼州詞','薛逢','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u7231\u56fd"]','昨夜蕃兵報國讐，沙州都護破涼州。',32,'全唐诗/poet.tang.30000.json','["昨夜蕃兵報國讐，沙州都護破涼州。", "黃河九曲今歸漢，塞外縱橫戰血流。"]'),
('1d2a89fa-22d5-4234-9887-3fbf2d63f419','嘉陵江','薛逢','唐','唐诗','tang','','[]','備問嘉陵江水湄，百川東去爾西之。',32,'全唐诗/poet.tang.30000.json','["備問嘉陵江水湄，百川東去爾西之。", "但教清淺源流在，天路朝宗會有期。"]'),
('ba6b993b-d939-4323-8fde-af6076038270','觀獵','薛逢','唐','唐诗','tang','','[]','馬縮寒毛鷹落臕，角弓初暖箭新調。',32,'全唐诗/poet.tang.30000.json','["馬縮寒毛鷹落臕，角弓初暖箭新調。", "平原踏盡無禽出，竟日翻身望碧霄。"]'),
('2b5e2faf-1985-40a5-9ef0-2ee294ff10dc','狼煙','薛逢','唐','唐诗','tang','','[]','三道狼煙過磧來，受降城上探旗開。',32,'全唐诗/poet.tang.30000.json','["三道狼煙過磧來，受降城上探旗開。", "傳聲却報邊無事，自是官軍入抄回。"]'),
('0c8b8c1d-335d-42e2-90ff-550d3e636427','俠少年','薛逢','唐','唐诗','tang','','[]','綠眼胡鷹踏錦韝，五花騘馬白貂裘。',32,'全唐诗/poet.tang.30000.json','["綠眼胡鷹踏錦韝，五花騘馬白貂裘。", "往來三市無人識，倒把金鞭上酒樓。"]'),
('ce7aafb9-dee8-4ab8-9235-5883ad901200','感塞','薛逢','唐','唐诗','tang','','[]','滿塞旌旗鎮上遊，各分天子一方憂。',32,'全唐诗/poet.tang.30000.json','["滿塞旌旗鎮上遊，各分天子一方憂。", "無因得見哥舒翰，可惜西山十八州。"]'),
('c283ce18-2602-4c05-817f-cab9beb010fc','聽曹剛彈琵琶','薛逢','唐','唐诗','tang','','[]','禁曲新翻下玉都，四弦掁觸五音殊。',32,'全唐诗/poet.tang.30000.json','["禁曲新翻下玉都，四弦掁觸五音殊。", "不知天上彈多少，金鳳銜花尾半無。"]'),
('ea58bf4b-57a5-4ba4-8036-5d0ee013a3e9','定山寺','薛逢','唐','唐诗','tang','','[]','十里松蘿映碧苔，一川晴色鏡中開。',32,'全唐诗/poet.tang.30000.json','["十里松蘿映碧苔，一川晴色鏡中開。", "遙聞上界翻經處，片片香雲出院來。"]'),
('cf86bb4d-bbf3-42ce-9bcf-de6a79a451f5','越王樓送高梓州入朝','薛逢','唐','唐诗','tang','','["\u957f\u6c5f"]','乘遞初登建外州，傾心喜事富人侯。',64,'全唐诗/poet.tang.30000.json','["乘遞初登建外州，傾心喜事富人侯。", "方當游藝依仁日，便到攀轅臥轍秋。", "容聽巴歌消子夜，許陪仙躅上危樓。", "欲知恨戀情深處，聽取長江旦暮流。"]'),
('f660fabc-1b8d-44f5-b403-b8089a3e538e','送李蘊赴鄭州因獻盧郎中','薛逢','唐','唐诗','tang','','[]','僕射陂西想到時，滿川晴色見旌旗。',64,'全唐诗/poet.tang.30000.json','["僕射陂西想到時，滿川晴色見旌旗。", "馬融閑臥笛聲遠，王粲醉吟樓影移。", "幾日賦詩秋水寺，經年草詔白雲司。", "唯君此去人多羨，却是恩深自不知。"]'),
('068fe2b7-df0f-4f4d-af57-9b88d02f9373','送裴評事','薛逢','唐','唐诗','tang','','[]','塞垣從事識兵機，只擬平戎不擬歸。',64,'全唐诗/poet.tang.30000.json','["塞垣從事識兵機，只擬平戎不擬歸。", "入夜茄聲含白髪，報秋榆葉落征衣。", "城臨戰壘黃雲晚，馬渡寒沙夕照微。", "此別不應書斷絕，滿天霜雪有鴻飛。"]'),
('8e608ce8-b69e-4a37-bf82-766b0eb22432','送沈單作尉江都','薛逢','唐','唐诗','tang','','[]','煬帝都城春水邊，笙歌夜上木蘭船。',64,'全唐诗/poet.tang.30000.json','["煬帝都城春水邊，笙歌夜上木蘭船。", "三千宮女自塗地，十萬人家如洞天。", "焰焰花枝官舍晚，重重雲影寺牆連。", "少年作尉須矜慎，莫向樓前墜馬鞭。"]'),
('db3b36f8-1dee-48d3-9cd3-03a379d57661','送薛耽先輩歸謁漢南','薛逢','唐','唐诗','tang','','[]','雲繞千峰驛路長，謝家聯句待檀郎。',64,'全唐诗/poet.tang.30000.json','["雲繞千峰驛路長，謝家聯句待檀郎。", "手持碧落新攀桂，月在東軒舊選牀。", "幾日旌幢延駿馬，到時冰玉動華堂。", "孔門多少風流處，不遣顏回識醉鄉。"]'),
('c0d46b44-5cb0-4329-9502-3a9d0d38066e','送同年鄭祥先輩歸漢南','薛逢','唐','唐诗','tang','','[]','年來驚喜兩心知，高處同攀次第枝。',64,'全唐诗/poet.tang.30000.json','["年來驚喜兩心知，高處同攀次第枝。", "人倚繡屏閑賞夜，馬嘶花徑醉歸時。", "聲名本自文章得，藩溷曾勞筆硯隨。", "家去恩門四千里，只應從此夢旌旗。"]'),
('8129e38c-8c5e-4dc3-ba35-996a33fce0cf','李先輩擢第東歸有贈送','薛逢','唐','唐诗','tang','','[]','金榜前頭無是非，平人分得一枝歸。',64,'全唐诗/poet.tang.30000.json','["金榜前頭無是非，平人分得一枝歸。", "正憐日暖雲飄路，何處宴迴風滿衣？", "門掩長淮心更遠，渡連芳草馬如飛。", "茂陵自笑猶多病，空有書齋在翠微。"]'),
('5261ef8d-9fc4-46ca-8883-dd41faf375db','送韓絳歸淮南寄韓綽先輩','薛逢','唐','唐诗','tang','','[]','島上花枝繫釣船，隋家宮畔水連天。',64,'全唐诗/poet.tang.30000.json','["島上花枝繫釣船，隋家宮畔水連天。", "江帆自落鳥飛外，月觀靜依春色邊。", "門巷草生車轍在，朝廷恩及鴈行聯。", "相逢且問昭州事，曾鼓莊盆對逝川。"]'),
('5001bf44-e94e-4a2b-a2b9-cbc65005f72a','送盧緘歸揚州','薛逢','唐','唐诗','tang','','[]','曾向雷塘寄掩扉，荀家燈火有餘輝。',64,'全唐诗/poet.tang.30000.json','["曾向雷塘寄掩扉，荀家燈火有餘輝。", "關河日暮望空極，楊柳渡頭人獨歸。", "隋苑荒臺風褭褭，灞陵殘雨夢依依。", "今年春色還相悞，爲我江邊謝釣磯。"]'),
('67df2e07-66ce-47f6-95e0-75181be40d17','送剡客','薛逢','唐','唐诗','tang','','[]','兩重江外片帆斜，數里林塘遶一家。',64,'全唐诗/poet.tang.30000.json','["兩重江外片帆斜，數里林塘遶一家。", "門掩右軍餘水石，路橫諸謝舊煙霞。", "扁舟幾處逢溪雪，長笛何人怨柳花。", "若到天台洞陽觀，葛洪丹井在雲涯。"]'),
('cf8ff989-88db-4ccd-a094-c86bb3257a80','涼州詞 一','薛逢','唐','唐诗','tang','','[]','千里東歸客，無心憶舊遊。',24,'全唐诗/poet.tang.30000.json','["千里東歸客，無心憶舊遊。", "挂帆遊□水，高枕到青州。"]'),
('29ba8d42-de85-4626-bf54-5046c009b325','涼州詞 二','薛逢','唐','唐诗','tang','','[]','君住孤山下，煙深夜徑長。',24,'全唐诗/poet.tang.30000.json','["君住孤山下，煙深夜徑長。", "轅門渡綠水，遊苑遶垂楊。"]'),
('731ea082-111e-490a-80eb-dbd4fd75edad','涼州詞 三','薛逢','唐','唐诗','tang','','[]','樹發花如錦，鶯啼柳若絲。',24,'全唐诗/poet.tang.30000.json','["樹發花如錦，鶯啼柳若絲。", "更遊懽宴地，愁見別離時。"]'),
('fb779100-51f8-4314-ac06-5993764d9462','送蕭俛相公歸山','薛逢','唐','唐诗','tang','','[]','眼前軒冕是鴻毛，天上人情謾自勞。',32,'全唐诗/poet.tang.30000.json','["眼前軒冕是鴻毛，天上人情謾自勞。", "脫却朝衣便東去，青雲不及白雲高。"]'),
('9160e6a2-5837-44ec-b796-1800b90b3274','石膏枕','薛逢','唐','唐诗','tang','','[]','表裏通明不假彫，冷於春雪白於瑤。',32,'全唐诗/poet.tang.30000.json','["表裏通明不假彫，冷於春雪白於瑤。", "朝來送在涼牀上，只怕風吹日炙銷。"]'),
('4b0d6ae4-1064-4928-9530-ba4af4bc4023','句','薛逢','唐','唐诗','tang','','[]','草荒留客院，泥臥餵生臺。',64,'全唐诗/poet.tang.30000.json','["草荒留客院，泥臥餵生臺。", "碧碎鴛鴦瓦，香埋菡萏罏。", "初日暉暉上彩旄。", "金鞍俯鞚塵開處，銀鏑離弦中處聲。", "昨日鴻毛萬鈞重，今朝山岳一朝輕。"]'),
('750af26d-4d14-4e58-a736-8efcfd9dc01b','汾上宴別','趙嘏','唐','唐诗','tang','','[]','雲物如故鄉，山川知異路。',48,'全唐诗/poet.tang.30000.json','["雲物如故鄉，山川知異路。", "年來未歸客，馬上春色暮。", "一尊花下酒，殘日水西樹。", "不待管弦終，搖鞭背花去。"]'),
('c20a6e02-376a-4edb-9891-99f728e54cae','書齋雪後','趙嘏','唐','唐诗','tang','','[]','擁褐坐茅簷，春晴喜初日。',72,'全唐诗/poet.tang.30000.json','["擁褐坐茅簷，春晴喜初日。", "微風入桃徑，爽氣歸縹帙。", "頻時苦風雪，就景理巾櫛。", "樹暖高鳥來，窗閑曙雲出。", "鄉遙路難越，道蹇時易失。", "欲靜又不能，東山負芝朮。"]'),
('f0b26d34-d1b8-42a9-99b4-d911b5365c17','寄道者','趙嘏','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭先生歸路長，海雲望極春茫茫。',32,'全唐诗/poet.tang.30000.json','["洞庭先生歸路長，海雲望極春茫茫。", "別來幾度向蓬島，自傍瑤臺折靈草。"]'),
('b9191631-5a5a-40b4-b7fc-a24dc25e1fb5','虎丘寺贈漁處士','趙嘏','唐','唐诗','tang','','[]','蘭若雲深處，前年客重過。',48,'全唐诗/poet.tang.30000.json','["蘭若雲深處，前年客重過。", "巖空秋色動，水闊夕陽多。", "早負江湖志，今如鬢髮何。", "唯思閑勝我，釣艇在煙波。"]'),
('1c9ce09e-61c1-4826-9528-ed1635445f9d','陪崔璞侍御和崔㻂春日有懷','趙嘏','唐','唐诗','tang','','[]','詩家本多感，況值廣陵春。',48,'全唐诗/poet.tang.30000.json','["詩家本多感，況值廣陵春。", "暖駐含窗日，香餘醉袖塵。", "浮名皆有分，一笑最關身。", "自此容依託，清才兩故人。"]'),
('b9c71dec-c57a-4933-b5d1-034692239055','昔昔鹽二十首 垂柳覆金堤','趙嘏','唐','唐诗','tang','','[]','新年垂柳色，嫋嫋對空閨。',48,'全唐诗/poet.tang.30000.json','["新年垂柳色，嫋嫋對空閨。", "不畏芳菲好，自緣離別啼。", "因風飄玉戶，向日映金堤。", "驛使何時度，還將贈隴西。"]'),
('984a653c-4bf1-4110-8fda-66ddccb1d8f6','昔昔鹽二十首 蘼蕪葉復齊','趙嘏','唐','唐诗','tang','','[]','提筐紅葉下，度日採蘼蕪。',48,'全唐诗/poet.tang.30000.json','["提筐紅葉下，度日採蘼蕪。", "掬翠香盈袖，看花憶故夫。", "葉齊誰復見，風暖恨偏孤。", "一被春光累，容顏與昔殊。"]'),
('941c324b-08d0-4ecf-9ee7-62d71dd86afd','昔昔鹽二十首 水溢芙蓉沼','趙嘏','唐','唐诗','tang','','[]','淥沼春光後，青青草色濃。',48,'全唐诗/poet.tang.30000.json','["淥沼春光後，青青草色濃。", "綺羅驚翡翠，暗粉妬芙蓉。", "雲遍窗前見，荷翻鏡裏逢。", "將心託流水，終日渺無從。"]'),
('5c6cf3ab-1dcb-445f-b3b2-300ff32f67ae','昔昔鹽二十首 花飛桃李蹊','趙嘏','唐','唐诗','tang','','[]','遠期難可託，桃李自依依。',48,'全唐诗/poet.tang.30000.json','["遠期難可託，桃李自依依。", "花徑無容跡，戎裘未下機。", "隨風開又落，度日掃還飛。", "欲折枝枝贈，那知歸不歸。"]'),
('09972a8e-d749-4d05-b29a-571d09882c43','昔昔鹽二十首 採桑秦氏女','趙嘏','唐','唐诗','tang','','[]','南陌採桑出，誰知妾姓秦。',48,'全唐诗/poet.tang.30000.json','["南陌採桑出，誰知妾姓秦。", "獨憐傾國貌，不負早鶯春。", "珠履盪花濕，龍鉤折桂新。", "使君那駐馬，自有侍中人。"]'),
('6fb2cf8f-61e7-41a3-a169-ddff2b7ec09a','昔昔鹽二十首 織錦竇家妻','趙嘏','唐','唐诗','tang','','[]','當年誰不羨，分作竇家妻。',48,'全唐诗/poet.tang.30000.json','["當年誰不羨，分作竇家妻。", "錦字行行苦，羅幃日日啼。", "豈知登隴遠，秪恨下機迷。", "直候陽關使，殷勤寄海西。"]'),
('666459a4-0a5a-4b67-a33b-b6c85e1ea9f6','昔昔鹽二十首 關山別蕩子','趙嘏','唐','唐诗','tang','','[]','那堪聞蕩子，迢遞涉關山。',48,'全唐诗/poet.tang.30000.json','["那堪聞蕩子，迢遞涉關山。", "腸爲馬嘶斷，衣從淚滴斑。", "愁看塞上路，詎惜鏡中顏。", "儻見征西雁，應傳一字還。"]'),
('cb77eb12-7a8f-42eb-8549-4146401ca024','昔昔鹽二十首 風月守空閨','趙嘏','唐','唐诗','tang','','[]','良人猶遠戍，耿耿夜閨空。',48,'全唐诗/poet.tang.30000.json','["良人猶遠戍，耿耿夜閨空。", "繡戶流宵月，羅幃坐晚風。", "魂飛沙帳北，腸斷玉關中。", "尚自無消息，錦衾那得同。"]'),
('a6b50da8-c9e3-4606-9053-44c1cb81e657','昔昔鹽二十首 恆歛千金笑','趙嘏','唐','唐诗','tang','','[]','玉顏恆自歛，羞出鏡臺前。',48,'全唐诗/poet.tang.30000.json','["玉顏恆自歛，羞出鏡臺前。", "早惑陽城客，今悲華錦筵。", "從軍人更遠，投喜鵲空傳。", "夫壻交河北，迢迢路幾千。"]'),
('686b0d8b-be2b-4a99-a6e9-878c755414dc','昔昔鹽二十首 長垂雙玉啼','趙嘏','唐','唐诗','tang','','[]','雙雙紅淚墮，度日暗中啼。',48,'全唐诗/poet.tang.30000.json','["雙雙紅淚墮，度日暗中啼。", "雁出居延北，人猶遼海西。", "向燈垂玉枕，對月灑金閨。", "不惜羅衣濕，惟愁歸意迷。"]'),
('c1719bc8-c733-478c-bbd8-cf58722747cd','昔昔鹽二十首 蟠龍隨鏡隱','趙嘏','唐','唐诗','tang','','[]','鸞鏡無由照，蛾眉豈忍看。',48,'全唐诗/poet.tang.30000.json','["鸞鏡無由照，蛾眉豈忍看。", "不知愁髮換，空見隱龍蟠。", "那愜紅顏改，偏傷白日殘。", "今朝窺玉匣，雙淚落闌干。"]'),
('1fc4fd2c-09bd-43cc-82a0-72e173fbfacb','昔昔鹽二十首 彩鳳逐帷低','趙嘏','唐','唐诗','tang','','[]','巧繡雙飛鳳，朝朝伴下帷。',48,'全唐诗/poet.tang.30000.json','["巧繡雙飛鳳，朝朝伴下帷。", "春花那見照，暮色已頻欺。", "欲卷思君處，將啼裛淚時。", "何年征戍客，傳語報佳期。"]'),
('f336f2a5-6bad-4246-a5b7-dd65e0288b07','昔昔鹽二十首 驚魂同夜鵲','趙嘏','唐','唐诗','tang','','[]','萬里無人見，衆情難與論。',48,'全唐诗/poet.tang.30000.json','["萬里無人見，衆情難與論。", "思君常入夢，同鵲屢驚魂。", "孤寢紅羅帳，雙啼玉筯痕。", "妾心甘自保，豈復暫忘恩。"]'),
('8f93ea6e-2b5d-48e4-b706-2dcc35a74b0c','昔昔鹽二十首 倦寢聽晨雞','趙嘏','唐','唐诗','tang','','[]','去去邊城騎，愁眠掩夜閨。',48,'全唐诗/poet.tang.30000.json','["去去邊城騎，愁眠掩夜閨。", "披衣窺落月，拭淚待鳴雞。", "不憤連年別，那看長夜啼。", "功成應自恨，早晚發遼西。"]'),
('8cdfada8-4a2b-473a-8a0c-5ff207a989dc','昔昔鹽二十首 暗牑懸蛛網','趙嘏','唐','唐诗','tang','','[]','暗中蛛網織，歷亂綺窗前。',48,'全唐诗/poet.tang.30000.json','["暗中蛛網織，歷亂綺窗前。", "萬里終無信，一條徒自懸。", "分從珠露滴，愁見隟風牽。", "妾意何聊賴，看看劇斷絃。"]'),
('c2ac50d7-24ae-48a7-9750-ce28e41d0f7b','昔昔鹽二十首 空梁落燕泥','趙嘏','唐','唐诗','tang','','[]','春至今朝燕，花時伴獨啼。',48,'全唐诗/poet.tang.30000.json','["春至今朝燕，花時伴獨啼。", "飛斜珠箔隔，語近畫梁低。", "帷卷閑窺戶，牀空暗落泥。", "誰能長對此，雙去復雙栖。"]'),
('58dfc7b8-98f9-480c-8a1c-36352ddbece5','昔昔鹽二十首 前年過代北','趙嘏','唐','唐诗','tang','','[]','代北幾千里，前年又復經。',48,'全唐诗/poet.tang.30000.json','["代北幾千里，前年又復經。", "燕山雲自合，胡塞草應青。", "鐵馬喧鼙鼓，蛾眉怨錦屏。", "不知羌笛曲，掩淚若爲聽。"]'),
('ec27579f-94f1-45a2-a179-43b20f8ec354','昔昔鹽二十首 今歲往遼西','趙嘏','唐','唐诗','tang','','[]','萬里飛書至，聞君已渡遼。',48,'全唐诗/poet.tang.30000.json','["萬里飛書至，聞君已渡遼。", "秪諳新別苦，忘却舊時嬌。", "烽戍年將老，紅顏日向彫。", "胡沙兼漢苑，相望幾迢迢。"]'),
('03fd9418-5670-4794-b5f0-562a90cbcaa4','昔昔鹽二十首 一去無還意','趙嘏','唐','唐诗','tang','','[]','良人征絕域，一去不言還。',48,'全唐诗/poet.tang.30000.json','["良人征絕域，一去不言還。", "百戰攻胡虜，三冬阻玉關。", "蕭蕭邊馬思，獵獵戍旗閑。", "獨抱千重恨，連年未解顏。"]'),
('e2bbe4d4-f485-4424-be34-83249854b040','昔昔鹽二十首 那能惜馬蹄','趙嘏','唐','唐诗','tang','','[]','雲中路杳杳，江畔草淒淒。',48,'全唐诗/poet.tang.30000.json','["雲中路杳杳，江畔草淒淒。", "妾久垂珠淚，君何惜馬蹄。", "邊風悲曉角，營月怨春鼙。", "未道休征戰，愁眉又復低。"]'),
('5d7a2c8f-8fd7-498d-aa4c-764a7435f121','送韋處士歸省朔方','趙嘏','唐','唐诗','tang','','[]','映柳見行色，故山當落暉。',48,'全唐诗/poet.tang.30000.json','["映柳見行色，故山當落暉。", "青雲知已歿，白首一身歸。", "滿袖蕭關雨，連沙塞雁飛。", "到家翻有喜，借取老萊衣。"]'),
('28a80f28-64e4-4523-87a2-73557f3d2650','送權先輩歸覲信安','趙嘏','唐','唐诗','tang','','[]','衣綵獨歸去，一枝蘭更香。',48,'全唐诗/poet.tang.30000.json','["衣綵獨歸去，一枝蘭更香。", "馬嘶芳草渡，門掩百花塘。", "野色亭臺晚，灘聲枕簟涼。", "小齋松島上，重葉覆書堂。"]'),
('5b8f05b1-60cf-446c-bedf-c0304d8f8239','風蟬','趙嘏','唐','唐诗','tang','','[]','風蟬旦夕鳴，伴夜送秋聲。',48,'全唐诗/poet.tang.30000.json','["風蟬旦夕鳴，伴夜送秋聲。", "故里客歸盡，水邊身獨行。", "噪軒高樹合，驚枕暮山橫。", "聽處無人見，塵埃滿甑生。"]'),
('95470506-477b-4e96-bf9b-0925265e2b10','重寄盧中丞','趙嘏','唐','唐诗','tang','','[]','賤子來還去，何人伴使君。',48,'全唐诗/poet.tang.30000.json','["賤子來還去，何人伴使君。", "放歌迎晚醉，指路上高雲。", "此夜雁初至，空山雨獨聞。", "別多頭欲白，惆悵惜餘醺。"]'),
('477002e1-7de4-489f-ba72-592956c84f56','曉發','趙嘏','唐','唐诗','tang','','[]','旅行宜蚤發，況復是南歸。',48,'全唐诗/poet.tang.30000.json','["旅行宜蚤發，況復是南歸。", "月影緣山盡，鐘聲隔浦微。", "星殘螢共映，葉落鳥驚飛。", "去去渡南渚，樹深人出稀。"]'),
('49647d41-0df8-4022-a289-37fcf8e34c9d','送友人鄭州歸覲','趙嘏','唐','唐诗','tang','','[]','爲有趨庭戀，應忘道路賒。',48,'全唐诗/poet.tang.30000.json','["爲有趨庭戀，應忘道路賒。", "風消滎澤凍，雨靜圃田沙。", "古陌人來遠，遙天雁勢斜。", "園林新到日，春酒酌梨花。"]'),
('213266f4-ff87-4322-be24-26dd6832d75c','洛中逢盧郢石歸覲','趙嘏','唐','唐诗','tang','','[]','不堪俱失意，相送出東周。',48,'全唐诗/poet.tang.30000.json','["不堪俱失意，相送出東周。", "緣切倚門戀，倍添爲客愁。", "春山和雪靜，寒水帶冰流。", "別後期君處，靈源紫閣秋。"]'),
('50e5ef86-c74f-46ff-9adf-c27b7b2e4c8c','贈越客','趙嘏','唐','唐诗','tang','','["\u957f\u6c5f"]','故國波濤隔，明時心久留。',48,'全唐诗/poet.tang.30000.json','["故國波濤隔，明時心久留。", "獻書雙闕晚，看月五陵秋。", "南棹何當返，長江憶共遊。", "定知釣魚伴，相望在汀州。"]'),
('5684ca6d-deb6-4095-8c06-82a92e2bd47a','經無錫縣醉後吟','趙嘏','唐','唐诗','tang','','[]','客過無名姓，扁舟繫柳陰。',48,'全唐诗/poet.tang.30000.json','["客過無名姓，扁舟繫柳陰。", "窮秋南國淚，殘日故鄉心。", "京洛衣塵在，江湖酒病深。", "何須覓陶令，乘醉自橫琴。"]'),
('ea4cf60d-9597-42d1-86e4-5fd02035666f','東歸道中二首 一','趙嘏','唐','唐诗','tang','','[]','平生事行役，今日始知非。',48,'全唐诗/poet.tang.30000.json','["平生事行役，今日始知非。", "歲月老將至，江湖春未歸。", "傳家有天爵，主祭用儒衣。", "何必勞知己，無名亦息機。"]'),
('2deb36e1-2d84-4980-8e79-99e1a24d5a56','東歸道中二首 二','趙嘏','唐','唐诗','tang','','[]','未明喚僮僕，江上憶殘春。',48,'全唐诗/poet.tang.30000.json','["未明喚僮僕，江上憶殘春。", "風雨落花夜，山川驅馬人。", "星星一鏡髮，草草百年身。", "此日念前事，滄洲情更親。"]'),
('4522bb34-84f7-4f12-8d09-38b25e245d0a','旅次商山','趙嘏','唐','唐诗','tang','','[]','役役依山水，何曾似問津。',48,'全唐诗/poet.tang.30000.json','["役役依山水，何曾似問津。", "斷崖如避馬，芳樹欲留人。", "日夕猿鳥伴，古今京洛塵。", "一枝甘已失，辜負故園春。"]'),
('46e2a51b-8282-4c12-97b7-1ab20147d9cb','長洲','趙嘏','唐','唐诗','tang','','[]','扁舟殊不繫，浩蕩路纔分。',48,'全唐诗/poet.tang.30000.json','["扁舟殊不繫，浩蕩路纔分。", "范蠡湖中樹，吳王苑外雲。", "悲心人望月，獨夜雁離羣。", "明發還驅馬，關城見日曛。"]'),
('fafdd7ec-8783-4d1f-89b7-4eede7db4601','江邊','趙嘏','唐','唐诗','tang','','[]','終日勞車馬，江邊款竹扉。',48,'全唐诗/poet.tang.30000.json','["終日勞車馬，江邊款竹扉。", "殘花春浪闊，小酒故人稀。", "戍鼓客帆遠，津雲夕照微。", "何由兄與弟，俱及暮春歸。"]'),
('ae61e80c-ef5d-48c9-bd7e-3be34251fbd0','宿靈巖寺','趙嘏','唐','唐诗','tang','','["\u592a\u6e56"]','明月溪頭寺，蟲聲滿橘洲。',48,'全唐诗/poet.tang.30000.json','["明月溪頭寺，蟲聲滿橘洲。", "倚欄香徑晚，移石太湖秋。", "古樹雲歸盡，荒臺水更流。", "無人見惆悵，獨上最高樓。"]'),
('9ccc71df-4c60-40d5-ae79-ff570ff78bc2','越中寺居','趙嘏','唐','唐诗','tang','','[]','遲客疎林下，斜溪小艇通。',48,'全唐诗/poet.tang.30000.json','["遲客疎林下，斜溪小艇通。", "野橋連寺月，高竹半樓風。", "水靜魚吹浪，枝閑鳥下空。", "數峰相向綠，日夕郡城東。"]'),
('690b8a03-5007-48c1-8640-5855bd14081e','贈金剛三藏','趙嘏','唐','唐诗','tang','','[]','心法云無住，流沙歸復來。',48,'全唐诗/poet.tang.30000.json','["心法云無住，流沙歸復來。", "錫隨山鳥動，經附海船回。", "洗足柳遮寺，坐禪花委苔。", "惟將一童子，又欲過天台。"]'),
('0c00b5eb-220d-47e6-8a06-74d057ef8365','長安晚秋','趙嘏','唐','唐诗','tang','','["\u601d\u5f52", "\u79cb\u5929", "\u83ca\u82b1", "\u82b1", "\u5199\u82b1"]','雲物淒涼拂曙流，漢家宮闕動高秋。',64,'全唐诗/poet.tang.30000.json','["雲物淒涼拂曙流，漢家宮闕動高秋。", "殘星幾點雁橫塞，長笛一聲人倚樓。", "紫豔半開籬菊靜，紅衣落盡渚蓮愁。", "鱸魚正美不歸去，空戴南冠學楚囚。"]'),
('f78bdf71-ee02-4c13-8713-4f62d3c748fd','齊安早秋','趙嘏','唐','唐诗','tang','','[]','流年堪惜又堪驚，砧杵風來滿郡城。',48,'全唐诗/poet.tang.30000.json','["流年堪惜又堪驚，砧杵風來滿郡城。", "高鳥過時秋色動，征帆落處暮雲平。", "思家正歎江南景，聽角仍含塞北情。"]'),
('9cf809e1-2947-4d06-804b-27c4a01583e3','東望','趙嘏','唐','唐诗','tang','','[]','楚江橫在草堂前，楊柳洲西載酒船。',64,'全唐诗/poet.tang.30000.json','["楚江橫在草堂前，楊柳洲西載酒船。", "兩見梨花歸不得，每逢寒食一潸然。", "斜陽映閣山當寺，微綠含風月滿川。", "同郡故人攀桂盡，把詩吟向泬寥天。"]'),
('ea115d6a-234e-4d04-914d-a42e5bd261d1','長安月夜與友人話故山','趙嘏','唐','唐诗','tang','','[]','宅邊秋水浸苔磯，日日持竿去不歸。',64,'全唐诗/poet.tang.30000.json','["宅邊秋水浸苔磯，日日持竿去不歸。", "楊柳風多潮未落，蒹葭霜冷雁初飛。", "重嘶匹馬吟紅葉，却聽疎鐘憶翠微。", "今夜秦城滿樓月，故人相見一沾衣。"]'),
('afade0d6-6e8e-4b1e-854e-a3fb8705aa20','題橫水驛雙峰院松','趙嘏','唐','唐诗','tang','','[]','故園溪上雪中別，野館門前雲外逢。',64,'全唐诗/poet.tang.30000.json','["故園溪上雪中別，野館門前雲外逢。", "白髮漸多何事苦，清陰長在好相容。", "迎風幾拂朝天騎，帶月猶含度嶺鐘。", "更憶葛洪丹井畔，數株臨水欲成龍。"]'),
('dd685c23-ce86-40b1-b806-37ebb155034c','發剡中','趙嘏','唐','唐诗','tang','','[]','正懷何謝俯長流，更覽餘封識嵊州。',64,'全唐诗/poet.tang.30000.json','["正懷何謝俯長流，更覽餘封識嵊州。", "樹色老依官舍晚，溪聲涼傍客衣秋。", "南巖氣爽橫郛郭，天姥雲晴拂寺樓。", "日暮不堪還上馬，蓼花風起路悠悠。"]'),
('fb131ccc-3dcd-472b-b13f-bcb1d72d89d6','登安陸西樓','趙嘏','唐','唐诗','tang','','[]','樓上華筵日日開，眼前人事祗堪哀。',64,'全唐诗/poet.tang.30000.json','["樓上華筵日日開，眼前人事祗堪哀。", "征車自入紅塵去，遠水長穿綠樹來。", "雲雨暗更歌舞伴，山川不盡別離杯。", "無由併寫春風恨，欲下鄖城首重回。"]'),
('d654208b-ae8d-4b62-8c21-d2b81192685f','九日陪越州元相燕龜山寺','趙嘏','唐','唐诗','tang','','[]','佳晨何處泛花遊，丞相筵開水上頭。',64,'全唐诗/poet.tang.30000.json','["佳晨何處泛花遊，丞相筵開水上頭。", "雙影斾搖山雨霽，一聲歌動寺雲秋。", "林光靜帶高城晚，湖色寒分半檻流。", "共賀萬家逢此節，可憐風物似荆州。"]'),
('43391dcb-30ce-48ab-898e-7ca699a0bf6d','經漢武泉','趙嘏','唐','唐诗','tang','','[]','芙蓉苑裏起清秋，漢武泉聲落御溝。',64,'全唐诗/poet.tang.30000.json','["芙蓉苑裏起清秋，漢武泉聲落御溝。", "他日江山映蓬鬢，二年楊柳別漁舟。", "竹間駐馬題詩去，物外何人識醉遊。", "盡把歸心付紅葉，晚來隨水向東流。"]'),
('d92ae3aa-8a63-4f1c-bfd8-b19fa3a92c92','曲江春望懷江南故人','趙嘏','唐','唐诗','tang','','[]','杜若洲邊人未歸，水寒煙暖想柴扉。',64,'全唐诗/poet.tang.30000.json','["杜若洲邊人未歸，水寒煙暖想柴扉。", "故園何處風吹柳，新雁南來雪滿衣。", "目極思隨原草遍，浪高書到海門稀。", "此時愁望情多少，萬里春流遶釣磯。"]'),
('e854f8a4-bcaa-49bd-91e6-d677c815de08','上令狐相公','趙嘏','唐','唐诗','tang','','[]','鶚在卿雲冰在壺，代天才業奉訏謨。',64,'全唐诗/poet.tang.30000.json','["鶚在卿雲冰在壺，代天才業奉訏謨。", "榮同伊陟傳朱戶，秀比王商入畫圖。", "昨夜星辰回劍履，前年風月滿江湖。", "不知機務時多暇，猶許詩家屬和無。"]'),
('3f782781-8f3c-4ccc-98ae-a719d5e269a9','憶山陽','趙嘏','唐','唐诗','tang','','[]','家在枚臯舊宅邊，竹軒晴與楚坡連。',64,'全唐诗/poet.tang.30000.json','["家在枚臯舊宅邊，竹軒晴與楚坡連。", "芰荷香遶垂鞭袖，楊柳風橫弄笛船。", "城礙十洲煙島路，寺臨千頃夕陽川。", "可憐時節堪歸去，花落猿啼又一年。"]'),
('c6d3789e-3b3c-42a2-b08e-8c44a67b1f26','二','趙嘏','唐','唐诗','tang','','[]','折柳城邊起暮愁，可憐春色獨懷憂。',64,'全唐诗/poet.tang.30000.json','["折柳城邊起暮愁，可憐春色獨懷憂。", "傷心正歎人間事，回首更慚江上鷗。", "鶗鴂聲中寒食雨，芙蓉花外夕陽樓。", "憑高滿眼送清渭，去傍故山山下流。"]'),
('dec141df-ee86-4131-8ddc-194c82469e7d','送僧歸廬山','趙嘏','唐','唐诗','tang','','["\u5e90\u5c71"]','禪棲忽憶五峰遊，去著方袍謝列侯。',64,'全唐诗/poet.tang.30000.json','["禪棲忽憶五峰遊，去著方袍謝列侯。", "經啓樓臺千葉曙，錫含風雨一枝秋。", "題詩片石侵雲在，洗鉢香泉覆菊流。", "却憶前年別師處，馬嘶殘月虎溪頭。"]'),
('0b47acf7-d4b6-4d70-a7fe-beb79b54c9c8','贈天卿寺神亮上人','趙嘏','唐','唐诗','tang','','[]','五看春盡此江濆，花自飄零日自曛。',64,'全唐诗/poet.tang.30000.json','["五看春盡此江濆，花自飄零日自曛。", "空有慈悲隨物念，已無蹤跡在人羣。", "迎秋日色簷前見，入夜鐘聲竹外聞。", "笑指白蓮心自得，世間煩惱是浮雲。"]'),
('307d584e-b839-4f4c-a11e-708bbf515eee','降虜','趙嘏','唐','唐诗','tang','','[]','廣武溪頭降虜稀，一聲寒角怨金微。',64,'全唐诗/poet.tang.30000.json','["廣武溪頭降虜稀，一聲寒角怨金微。", "河湟不在春風地，歌舞空裁雪夜衣。", "鐵馬半嘶邊草去，狼煙高映塞鴻飛。", "揚雄尚白相如吃，今日何人從獵歸。"]'),
('ec639249-6714-4af1-8451-1670adb37227','平戎','趙嘏','唐','唐诗','tang','','[]','邊聲一夜殷秋鼙，牙帳連烽擁萬蹄。',64,'全唐诗/poet.tang.30000.json','["邊聲一夜殷秋鼙，牙帳連烽擁萬蹄。", "武帝未能忘塞北，董生纔足使膠西。", "冰橫曉渡胡兵合，雪滿窮沙漢騎迷。", "自古平戎有良策，將軍不用倚雲梯。"]'),
('23f92364-8920-49e3-9b7f-d9c70cfcbf95','宿楚國寺有懷','趙嘏','唐','唐诗','tang','','[]','風動衰荷寂寞香，斷煙殘月共蒼蒼。',64,'全唐诗/poet.tang.30000.json','["風動衰荷寂寞香，斷煙殘月共蒼蒼。", "寒生晚寺波搖壁，紅墮疎林葉滿牀。", "起雁似驚南浦棹，陰雲欲護北樓霜。", "江邊松菊荒應盡，八月長安夜正長。"]'),
('9e2b1384-6bb1-43ae-b12f-447998c8b84a','早發剡中石城寺','趙嘏','唐','唐诗','tang','','[]','暫息勞生樹色間，平明機慮又相關。',64,'全唐诗/poet.tang.30000.json','["暫息勞生樹色間，平明機慮又相關。", "吟辭宿處煙霞去，心負秋來水石閒。", "竹戶半開鐘未絕，松枝靜霽鶴初還。", "明朝一倍堪惆悵，回首塵中見此山。"]'),
('d4f8653d-f4d9-4668-9df6-b164483cc8ea','寄歸','趙嘏','唐','唐诗','tang','','[]','三年踏盡化衣塵，只見長安不見春。',64,'全唐诗/poet.tang.30000.json','["三年踏盡化衣塵，只見長安不見春。", "馬過雪街天未曙，客迷關路淚空頻。", "桃花塢接啼猿寺，野竹庭通畫鷁津。", "早晚相酬身事了，水邊歸去一閒人。"]'),
('f8c6d737-9301-4233-91d1-2f031b753f08','獻淮南李相公','趙嘏','唐','唐诗','tang','','[]','傅巖高靜見台星，廟畧當時討不庭。',64,'全唐诗/poet.tang.30000.json','["傅巖高靜見台星，廟畧當時討不庭。", "萬里有雲歸碧落，百川無浪到滄溟。", "軍中老將傳兵術，江上諸侯受政經。", "聞道國人思再入，鎔金新鑄鶴儀形。"]'),
('7109d871-873f-4c45-a1a1-77e694702be5','宛陵寓居上沈大夫二首 一','趙嘏','唐','唐诗','tang','','[]','滿耳歌謠滿眼山，宛陵城郭翠微間。',64,'全唐诗/poet.tang.30000.json','["滿耳歌謠滿眼山，宛陵城郭翠微間。", "人情已覺春長在，溪戶仍將水共閒。", "曉色入樓紅藹藹，夜聲尋砌碧潺潺。", "幽雲高鳥俱無事，晚伴西風醉客還。"]'),
('56c3e46b-4df7-4303-86c8-37e7ffd3b9ad','宛陵寓居上沈大夫二首 二','趙嘏','唐','唐诗','tang','','[]','溪樹參差綠可攀，謝家雲水滿東山。',64,'全唐诗/poet.tang.30000.json','["溪樹參差綠可攀，謝家雲水滿東山。", "能忘天上他年貴，來結林中一日閒。", "醉叩玉盤歌褭褭，暖鳴幽澗鳥關關。", "觥籌不盡須歸去，路在春風縹緲間。"]'),
('45b15ad4-1038-4d60-b99a-7f9ef2b9c4c7','淮信賀滕邁台州','趙嘏','唐','唐诗','tang','','[]','凋瘵民思太古風，上賢綏輯副宸衷。',64,'全唐诗/poet.tang.30000.json','["凋瘵民思太古風，上賢綏輯副宸衷。", "舟移清鏡禹祠北，路轉翠屏天姥東。", "旌斾影前橫竹馬，詠歌聲裏樂樵童。", "遙知到郡滄波晏，三島離離一望中。"]'),
('add078e7-486f-4602-87d3-3e5948303cdd','下第寄宣城幕中諸公','趙嘏','唐','唐诗','tang','','[]','一醉曾將萬事齊，暫陪歡去便如泥。',64,'全唐诗/poet.tang.30000.json','["一醉曾將萬事齊，暫陪歡去便如泥。", "黃花李白墓前路，碧浪桓彝宅後溪。", "九月霜中隨計吏，十年江上灌春畦。", "莫言春盡不惆悵，自有閒眠到日西。"]'),
('38323138-3009-48f3-851b-0b8eee404c58','送令狐郎中赴郢州','趙嘏','唐','唐诗','tang','','[]','佐幕才多始拜侯，一門清貴動神州。',64,'全唐诗/poet.tang.30000.json','["佐幕才多始拜侯，一門清貴動神州。", "霜蹄曉駐秦雲斷，野斾晴翻郢樹秋。", "幾處塵生隨候騎，半江帆盡見分流。", "大馮罷相吟詩地，莫惜頻登白雪樓。"]'),
('3e0c08a0-faf0-483e-a682-b5e8f4b82d38','送盧緘歸揚州','趙嘏','唐','唐诗','tang','','[]','曾向雷塘寄掩扉，荀家燈火有餘輝。',64,'全唐诗/poet.tang.30000.json','["曾向雷塘寄掩扉，荀家燈火有餘輝。", "關河日暮望空極，楊柳渡頭人獨歸。", "隋苑荒臺風褭褭，灞陵殘雨夢依依。", "今年春色還相悞，爲我江邊謝釣磯。"]'),
('b9b37602-b2a6-44d5-9d33-2eb7d40266f7','送李裴評事','趙嘏','唐','唐诗','tang','','[]','塞垣從事識兵機，只擬平戎不擬歸。',64,'全唐诗/poet.tang.30000.json','["塞垣從事識兵機，只擬平戎不擬歸。", "入夜笳聲含白髮，報秋榆葉落征衣。", "城臨戰壘黃雲晚，馬渡寒沙夕照微。", "此別不應書斷絕，滿天霜雪有鴻飛。"]'),
('d96ab8f4-d899-42fc-a251-261b08c09eea','別麻氏','趙嘏','唐','唐诗','tang','','[]','曉哭呱呱動四隣，于君我作負心人。',64,'全唐诗/poet.tang.30000.json','["曉哭呱呱動四隣，于君我作負心人。", "出門便涉東西路，回首初驚枕席塵。", "滿眼淚珠和語咽，舊窗風月更誰親。", "分離況值花時節，從此東風不似春。"]'),
('12b7bac3-a96f-4d07-a287-6bc8c02a5887','代人贈別','趙嘏','唐','唐诗','tang','','[]','月自斜窗夢自驚，衷腸中有萬愁生。',64,'全唐诗/poet.tang.30000.json','["月自斜窗夢自驚，衷腸中有萬愁生。", "清猿處處三聲盡，碧落悠悠一水橫。", "平子定情詞麗絕，詩人匪石誓分明。", "會須攜手乘鸞去，簫史樓臺在玉京。"]'),
('248db898-c5cc-48a0-b6a9-eed682ac3e75','寒食新豐別友人','趙嘏','唐','唐诗','tang','','[]','一百五日家未歸，新豐雞犬獨依依。',64,'全唐诗/poet.tang.30000.json','["一百五日家未歸，新豐雞犬獨依依。", "滿樓春色傍人醉，半夜雨聲前計非。", "繚繞溝塍含綠晚，荒涼樹石向川微。", "東風吹淚對花落，憔悴故交相見稀。"]'),
('f45078c0-53c5-465b-8678-bb2b97da0413','李侍御歸山同宿華嚴寺','趙嘏','唐','唐诗','tang','','[]','家有青山近玉京，風流柱史早知名。',64,'全唐诗/poet.tang.30000.json','["家有青山近玉京，風流柱史早知名。", "園林手植自含綠，霄漢眼看當去程。", "處處白雲迷駐馬，家家紅樹近流鶯。", "相逢一宿最高寺，夜夜翠微泉落聲。"]'),
('a6cd87e3-70ae-4eec-b61e-854434eb0c92','今年新先輩以遏密之際每有讌集必資清談書此奉賀','趙嘏','唐','唐诗','tang','','[]','天上高高月桂叢，分明三十一枝風。',64,'全唐诗/poet.tang.30000.json','["天上高高月桂叢，分明三十一枝風。", "滿懷春色向人動，遮路亂花迎馬紅。", "鶴馭迴飄雲雨外，蘭亭不在管絃中。", "居然自是前賢事，何必青樓倚翠空。"]'),
('1f9739d7-4af2-46a6-ba68-3891e083f3af','自遣','趙嘏','唐','唐诗','tang','','[]','晚樹疎蟬起別愁，遠人回首憶滄洲。',64,'全唐诗/poet.tang.30000.json','["晚樹疎蟬起別愁，遠人回首憶滄洲。", "江連故國無窮恨，日帶殘雲一片秋。", "久客轉諳時態薄，多情只共酒淹留。", "到頭生長煙霞者，須向煙霞老始休。"]'),
('5b6e8726-4351-4c95-b2a1-450b20181604','浙東陪元相公遊雲門寺','趙嘏','唐','唐诗','tang','','[]','松下山前一徑通，燭迎千騎滿山紅。',64,'全唐诗/poet.tang.30000.json','["松下山前一徑通，燭迎千騎滿山紅。", "溪雲乍歛幽巖雨，曉氣初高大斾風。", "小檻宴花容客醉，上方看竹與僧同。", "歸來吹盡嚴城角，路轉橫塘亂水東。"]'),
('b0c73b27-7c27-4af7-9ffc-1b526ada9f03','陪韋中丞宴扈都頭花園','趙嘏','唐','唐诗','tang','','[]','門下煙橫載酒船，謝家攜客醉華筵。',64,'全唐诗/poet.tang.30000.json','["門下煙橫載酒船，謝家攜客醉華筵。", "尋花偶坐將軍樹，飲水方重刺史天。", "幾曲豔歌春色裏，斷行高鳥暮雲邊。", "分明聽得輿人語，願及行春更一年。"]'),
('dfab9241-05d2-496c-81ab-be6e173d6e3d','花園即事呈常中丞','趙嘏','唐','唐诗','tang','','[]','煙煖池塘柳覆臺，百花園裏看花來。',64,'全唐诗/poet.tang.30000.json','["煙煖池塘柳覆臺，百花園裏看花來。", "燒衣焰席三千樹，破鼻醒愁一萬杯。", "不肯爲歌隨拍落，却因令舞帶香迴。", "山公仰爾延賓客，好傍春風次第開。"]'),
('4b40e046-40a9-4736-b39d-5edbe81a8288','宿何書記先輩延福新居','趙嘏','唐','唐诗','tang','','[]','松下有琴閑未收，一燈高爲石叢留。',64,'全唐诗/poet.tang.30000.json','["松下有琴閑未收，一燈高爲石叢留。", "詩情似到山家夜，樹色輕含御水秋。", "小榼提攜終永日，半斑容鬢漫生愁。", "因君撫掌問時俗，紫閣堆簷不舉頭。"]'),
('1d459b23-682a-4d1e-8734-1435a0089730','秦中逢王處士','趙嘏','唐','唐诗','tang','','[]','萬水東流去不迴，先生獨自負仙才。',64,'全唐诗/poet.tang.30000.json','["萬水東流去不迴，先生獨自負仙才。", "蘂宮橫浪海邊別，鶴翅駐雲天上來。", "幾處吹簫森羽衛，誰家殘月下樓臺。", "春風正好分瓊液，乞取當時白玉杯。"]'),
('3f90c14b-26a6-4ba0-bf1d-f457599f4b48','江上逢許逸人','趙嘏','唐','唐诗','tang','','[]','是非處處生塵埃，唯君襟抱無嫌猜。',64,'全唐诗/poet.tang.30000.json','["是非處處生塵埃，唯君襟抱無嫌猜。", "收帆依雁湓浦宿，帶雨別僧衡嶽迴。", "芳罇稍駐落日唱，醉袖更拂長雲開。", "清秋華髮好相似，却把釣竿歸去來。"]'),
('86c257e7-faed-4e51-a543-9e1e16f7d3dd','和令狐補闕春日獨遊西街','趙嘏','唐','唐诗','tang','','[]','左掖初辭近侍班，馬嘶尋得過街閑。',64,'全唐诗/poet.tang.30000.json','["左掖初辭近侍班，馬嘶尋得過街閑。", "映鞭柳色微遮水，隨步花枝欲礙山。", "暖泛鳥聲來席上，醉從詩句落人間。", "此時失意哀吟客，更覺風流不可攀。"]'),
('70e4febc-6541-4809-a89c-29c5dcbea490','廣陵答崔琛','趙嘏','唐','唐诗','tang','','[]','棹倚隋家舊院墻，柳金梅雪撲簷香。',64,'全唐诗/poet.tang.30000.json','["棹倚隋家舊院墻，柳金梅雪撲簷香。", "朱樓映日重重晚，碧水含光灩灩長。", "八斗已聞傳姓字，一枝何足計行藏。", "聲名官職應前定，且把旌麾入醉鄉。"]'),
('fa22703c-5da1-4b6e-8b05-968dedc109cc','答友人','趙嘏','唐','唐诗','tang','','[]','詩家才子酒家仙，遊宦曾依積水邊。',64,'全唐诗/poet.tang.30000.json','["詩家才子酒家仙，遊宦曾依積水邊。", "窗戶動搖三島樹，琴尊安穩五湖船。", "羅浮道士分瓊液，錦席佳人豔楚蓮。", "今日相逢朗吟罷，滿城砧杵一燈前。"]'),
('2be3378c-691c-41a1-914b-1e4b417d7bf4','送張又新除溫州','趙嘏','唐','唐诗','tang','','[]','東晉江山稱永嘉，莫辭紅斾向天涯。',64,'全唐诗/poet.tang.30000.json','["東晉江山稱永嘉，莫辭紅斾向天涯。", "凝絃夜醉松亭月，歇馬曉尋溪寺花。", "地與剡川分水石，境將蓬島共煙霞。", "却愁明詔徵非晚，不得秋來見海槎。"]'),
('023b37fe-fa4a-4bc7-8f9d-56c46966edae','送滕邁郎中赴睦州','趙嘏','唐','唐诗','tang','','[]','郡齋秋盡一江橫，頻命郎官地更清。',64,'全唐诗/poet.tang.30000.json','["郡齋秋盡一江橫，頻命郎官地更清。", "星月去隨新詔動，旌旗遙映故山明。", "詩尋片石依依晚，帆挂孤雲杳杳輕。", "想到釣臺逢竹馬，只應歌詠伴猿聲。"]'),
('5a123f5b-5525-4a18-9487-8a556d84ae55','送剡客','趙嘏','唐','唐诗','tang','','[]','兩重江外片帆斜，數里林塘遶一家。',64,'全唐诗/poet.tang.30000.json','["兩重江外片帆斜，數里林塘遶一家。", "門掩右軍餘水石，路橫諸謝舊煙霞。", "扁舟幾處逢溪雪，長笛何人怨柳花。", "若到天台洞陽觀，葛洪丹井在雲涯。"]'),
('f690b93a-075c-47b6-8ced-efb42f55cb90','李先輩擢第東歸有贈送','趙嘏','唐','唐诗','tang','','[]','金榜前頭無是非，平人分得一枝歸。',64,'全唐诗/poet.tang.30000.json','["金榜前頭無是非，平人分得一枝歸。", "正憐日煖雲飄路，何處宴迴風滿衣？", "門掩長淮心更遠，渡連芳草馬如飛。", "茂陵自笑猶多病，空有書齋在翠微。"]'),
('2347547e-3d3e-42a4-a21d-b5719416ae18','送同年鄭祥先輩歸漢南','趙嘏','唐','唐诗','tang','','[]','年來驚喜兩心知，高處同攀次第枝。',64,'全唐诗/poet.tang.30000.json','["年來驚喜兩心知，高處同攀次第枝。", "人倚繡屏閑賞夜，馬嘶花徑醉歸時。", "聲名本是文章得，藩閫曾勞筆硯隨。", "家去恩門四千里，只應從此夢旌旗。"]'),
('b9ab718a-6cf2-4b9e-a6d7-8e6f79254e26','送沈單作尉江都','趙嘏','唐','唐诗','tang','','[]','煬帝都城春水邊，笙歌夜上木蘭船。',64,'全唐诗/poet.tang.30000.json','["煬帝都城春水邊，笙歌夜上木蘭船。", "三千宮女自塗地，十萬人家如洞天。", "焰焰花枝官舍晚，重重雲影寺墻連。", "少年作尉須矜慎，莫向樓前墜馬鞭。"]'),
('39e35ec5-7dfb-458b-81d4-0c4efb54706c','送李蘊赴鄭州因獻盧郎中俶','趙嘏','唐','唐诗','tang','','[]','僕射陂西想到時，滿川晴色見旌旗。',64,'全唐诗/poet.tang.30000.json','["僕射陂西想到時，滿川晴色見旌旗。", "馬融閑臥笛聲遠，王粲醉吟樓影移。", "幾日賦詩秋水寺，經年草詔白雲司。", "唯君此去人多羨，却是恩深自不知。"]'),
('c6b1ba77-fee7-4750-a37e-42f0676f1e66','送韓絳歸淮南寄韓綽先輩','趙嘏','唐','唐诗','tang','','[]','島上花枝繫釣船，隋家宮畔水連天。',64,'全唐诗/poet.tang.30000.json','["島上花枝繫釣船，隋家宮畔水連天。", "江帆自落鳥飛外，月觀靜依春色邊。", "門巷草生車轍在，朝廷恩及雁行聯。", "相逢且問昭州事，曾鼓莊盆對逝川。"]'),
('26a53744-e898-418d-9766-7156ec45c03a','送薛耽先輩歸謁漢南','趙嘏','唐','唐诗','tang','','[]','雲繞千峰驛路長，謝家聯句待檀郎。',64,'全唐诗/poet.tang.30000.json','["雲繞千峰驛路長，謝家聯句待檀郎。", "手持碧落新攀桂，月在東軒舊選牀。", "幾日旌幢延駿馬，到時冰玉動華堂。", "孔門多少風流處，不遣顏回識醉鄉。"]'),
('bddcc5c2-70c6-4669-9a1e-abe08ba0489e','送陳嘏登第作尉歸覲','趙嘏','唐','唐诗','tang','','[]','千峰歸去舊林塘，溪縣門前即故鄉。',64,'全唐诗/poet.tang.30000.json','["千峰歸去舊林塘，溪縣門前即故鄉。", "曾把桂誇春里巷，重憐身稱錦衣裳。", "洲迷翠羽雲遮檻，露濕紅蕉月滿廊。", "就養舉朝人共羨，清資讓却校書郎。"]'),
('02c1d955-fd23-4b83-9af5-e92df0c462ee','送裴延翰下第歸覲滁州','趙嘏','唐','唐诗','tang','','[]','失意何曾恨解攜，問安歸去秣陵西。',64,'全唐诗/poet.tang.30000.json','["失意何曾恨解攜，問安歸去秣陵西。", "郡斜楊柳春風岸，山映樓臺明月溪。", "江上詩書懸素業，日邊門戶倚丹梯。", "一枝攀折回頭是，莫向清秋惜馬蹄。"]'),
('d59a4f22-98aa-4d54-93a8-58bc761bd066','題崇聖寺簡雲端僧錄','趙嘏','唐','唐诗','tang','','[]','暮塵飄盡客愁長，來扣禪關月滿廊。',64,'全唐诗/poet.tang.30000.json','["暮塵飄盡客愁長，來扣禪關月滿廊。", "宋玉逢秋空雪涕，淨名無地可容牀。", "高雲覆檻千巖樹，疎磬含風一夜霜。", "回首故園紅葉外，只將多病告醫王。"]'),
('21709e78-e494-49ab-b445-14410d174796','越中寺居寄上主人','趙嘏','唐','唐诗','tang','','[]','野寺初容訪靜來，晚晴江上見樓臺。',64,'全唐诗/poet.tang.30000.json','["野寺初容訪靜來，晚晴江上見樓臺。", "中林有路到花盡，一日無人看竹迴。", "自曬詩書經雨後，別留門戶爲僧開。", "苦心若是酬恩事，不敢吟春憶酒杯。"]'),
('65354c7f-8518-482d-b69a-f2b2b306dd3e','早出洞仙觀','趙嘏','唐','唐诗','tang','','[]','露濃如水灑蒼苔，洞口煙蘿密不開。',64,'全唐诗/poet.tang.30000.json','["露濃如水灑蒼苔，洞口煙蘿密不開。", "殘月色低當戶後，曉鐘聲逈隔山來。", "春生藥圃芝猶短，夜醮齋壇鶴未迴。", "愁是獨尋歸路去，人間步步是塵埃。"]'),
('8dd06c4e-59ce-4c65-bbc4-6c01026b0f0b','題昭應王明府溪亭','趙嘏','唐','唐诗','tang','','[]','靖節何須彭澤逢，菊洲松島水悠溶。',64,'全唐诗/poet.tang.30000.json','["靖節何須彭澤逢，菊洲松島水悠溶。", "行人自折門前柳，高鳥不離溪畔峰。", "曉渭度簷帆的的，晚原含雨樹重重。", "軒車過盡無公事，枕上一聲長樂鐘。"]'),
('228f838e-18e4-4983-a185-57c93643867f','贈王先生','趙嘏','唐','唐诗','tang','','[]','太一真人隱翠霞，早年曾降蔡經家。',64,'全唐诗/poet.tang.30000.json','["太一真人隱翠霞，早年曾降蔡經家。", "羽衣使者峭於鶴，鳥爪侍娘飄若花。", "九鼎欄干歸馬齒，三山窕窈步雲涯。", "時因弟子偷靈藥，散落人間駐物華。"]'),
('e050d8e2-333b-4bf1-a4c7-c06e2af93116','贈道者','趙嘏','唐','唐诗','tang','','[]','華蓋飄飄綠鬢翁，往來朝謁蘂珠宮。',64,'全唐诗/poet.tang.30000.json','["華蓋飄飄綠鬢翁，往來朝謁蘂珠宮。", "幾年山下陰陽鼎，盡日澗邊桃李風。", "野跡似雲無處著，仙容如水與誰同。", "應憐有客外妻子，思在長生一顧中。"]'),
('256134eb-9636-4d33-96af-cae6ec56a121','王先生不別而去','趙嘏','唐','唐诗','tang','','[]','仙翁歸袖拂煙霓，一卷素書還獨攜。',64,'全唐诗/poet.tang.30000.json','["仙翁歸袖拂煙霓，一卷素書還獨攜。", "劚藥滿囊身不病，抱琴何處鶴同棲？", "霑衣盡日看山坐，搔首殘春向路迷。", "樹樹白雲幽徑絕，短船空倚武陵溪。"]'),
('fe6a66ee-688b-4fd2-98a8-78a10bb77134','山陽盧明府以雙鶴寄遺白氏以詩回答因寄和','趙嘏','唐','唐诗','tang','','[]','緱山雙去羽翰輕，應爲仙家好弟兄。',64,'全唐诗/poet.tang.30000.json','["緱山雙去羽翰輕，應爲仙家好弟兄。", "茅固枕前秋對舞，陸雲溪上夜同鳴。", "紫泥封處曾回首，碧落歸時莫問程。", "自笑滄江一漁叟，何由似爾到層城。"]'),
('884f2266-b4af-4c36-8dbe-e3658e5cc46a','贈李秘書','趙嘏','唐','唐诗','tang','','[]','束帶臨風氣調新，孔門才業獨誰倫。',64,'全唐诗/poet.tang.30000.json','["束帶臨風氣調新，孔門才業獨誰倫。", "杉松韻冷雪溪暗，鸞鶴勢高天路春。", "美玉韞來休問價，芳枝攀去正無塵。", "莫將芸閣輕科第，須作人間第一人。"]'),
('2e92e9d5-e384-480c-9a59-1521d47c28a3','迴於道中寄舒州李珏相公','趙嘏','唐','唐诗','tang','','[]','都無鄙吝隔塵埃，昨日丘門避席來。',64,'全唐诗/poet.tang.30000.json','["都無鄙吝隔塵埃，昨日丘門避席來。", "靜語乍臨清廟瑟，披風如在九層臺。", "幾煩命妓浮溪棹，再許論詩注酒杯。", "從此微塵知感戀，七真臺上望三台。"]'),
('cbead6b6-992c-4c90-a631-93ecfe2d31a2','舒州獻李相公','趙嘏','唐','唐诗','tang','','[]','野人留得五湖船，丞相興歌郡國年。',64,'全唐诗/poet.tang.30000.json','["野人留得五湖船，丞相興歌郡國年。", "醉筆倚風飄澗雪，靜襟披月坐樓天。", "鶴歸華表山河在，氣返青雲雨露全。", "聞說萬方思舊德，一時傾望重陶甄。"]'),
('275b88fc-4319-4748-a9e8-b763024d50e2','成名年獻座主僕射兼呈同年','趙嘏','唐','唐诗','tang','','[]','拂煙披月羽毛新，千里初辭九陌塵。',66,'全唐诗/poet.tang.30000.json','["拂煙披月羽毛新，千里初辭九陌塵。", "曾失玄珠求[象罔]，不將雙耳負伶倫。", "賈嵩詞賦相如手，楊乘歌篇李白身。", "除却今年仙侶外，堂堂又見兩三春。"]'),
('66aa669c-304d-41c4-b4ac-59a90328149b','抒懷上歙州盧中丞宣州杜侍郎','趙嘏','唐','唐诗','tang','','[]','東來珠履與旌旗，前者登朝亦一時。',64,'全唐诗/poet.tang.30000.json','["東來珠履與旌旗，前者登朝亦一時。", "竹馬迎呼逢稚子，柏臺長告見男兒。", "花飄舞袖樓相倚，角送歸軒客盡隨。", "獨有賤夫懷感激，十年兩地負恩知。"]'),
('0d526273-3e89-4d5e-8f89-5ed442ecfccd','山陽韋中丞罷郡因獻','趙嘏','唐','唐诗','tang','','[]','笙歌只是舊笙歌，腸斷風流奈別何。',64,'全唐诗/poet.tang.30000.json','["笙歌只是舊笙歌，腸斷風流奈別何。", "照物二年春色在，感恩千室淚痕多。", "盡將魂夢隨西去，猶望旌旗暫一過。", "今日尊前無限思，萬重雲月隔煙波。"]'),
('008ee9a3-bded-4277-b1fb-abed94d1c941','山陽即席獻裴中丞','趙嘏','唐','唐诗','tang','','[]','早年天上見清塵，今日樓中醉一春。',64,'全唐诗/poet.tang.30000.json','["早年天上見清塵，今日樓中醉一春。", "暫肯剖符臨水石，幾曾焚筆動星辰。", "瓊臺雪映迢迢鶴，蓬島波橫浩浩津。", "好是仙家羽衣使，欲敎垂涕問何人。"]'),
('11ccd723-89cc-4c2b-8e0a-007d30285fc1','西峰即事獻沈大夫','趙嘏','唐','唐诗','tang','','[]','松竹閑遊道路身，衣襟落盡往來塵。',64,'全唐诗/poet.tang.30000.json','["松竹閑遊道路身，衣襟落盡往來塵。", "山連謝宅餘霞在，水映琴溪舊浪春。", "拂榻從容今有地，酬恩寂寞久無人。", "安知不及屠沽者，曾對青萍淚滿巾。"]'),
('baddcc92-7920-4b9b-946e-f44542a75daa','杜陵貽杜牧侍御','趙嘏','唐','唐诗','tang','','[]','紫陌塵多不可尋，南溪酒熟一披襟。',64,'全唐诗/poet.tang.30000.json','["紫陌塵多不可尋，南溪酒熟一披襟。", "山高晝枕石牀隱，泉落夜窗煙樹深。", "白首尋人嗟問計，青雲無路覓知音。", "唯君懷抱安如水，他日門墻許醉吟。"]'),
('98b09337-420d-435f-81f9-f73e367e45ba','下第後上李中丞','趙嘏','唐','唐诗','tang','','[]','落第逢人慟哭初，平生志業欲何如。',64,'全唐诗/poet.tang.30000.json','["落第逢人慟哭初，平生志業欲何如。", "鬢毛灑盡一枝桂，淚血滴來千里書。", "谷外風高摧羽翮，江邊春在憶樵漁。", "唯應感激知恩地，不待功成死有餘。"]'),
('92c0a903-8597-4d36-8934-32253df3efd1','淛東贈李副使員外','趙嘏','唐','唐诗','tang','','[]','妙盡戎機佐上台，少年清苦自霜臺。',64,'全唐诗/poet.tang.30000.json','["妙盡戎機佐上台，少年清苦自霜臺。", "馬嘶深竹閑宜貴，花拂朱衣美稱才。", "早入半緣分務重，晚吟多是看山迴。", "名高漸少翻飛伴，幾度煙霄獨去來。"]'),
('b7bbcd9e-7b1e-462e-984d-b5b3d94b9bf2','寄淮南幕中劉員外','趙嘏','唐','唐诗','tang','','[]','郎官何遜最風流，愛月憐山不下樓。',64,'全唐诗/poet.tang.30000.json','["郎官何遜最風流，愛月憐山不下樓。", "三佐戎旃換朱紱，一辭蘭省見清秋。", "桂生巖石本瀟灑，鶴到煙空更自由。", "休向西齋久閑臥，滿朝傾蓋是依劉。"]'),
('cc0602d8-7606-4e6f-a993-739027884900','薛廷範從事自宣城至因贈','趙嘏','唐','唐诗','tang','','[]','少年從事霍嫖姚，來自楓林度柳橋。',64,'全唐诗/poet.tang.30000.json','["少年從事霍嫖姚，來自楓林度柳橋。", "金管別筵樓灼灼，玉溪回首馬蕭蕭。", "清風氣調真君輩，知己風流滿聖朝。", "獨有故人愁欲死，晚簷疎雨動空瓢。"]'),
('be03ae8e-223c-474d-9369-8bbe0c4692d8','寄潯陽趙校書','趙嘏','唐','唐诗','tang','','["\u5e90\u5c71"]','簾下秋江夜影空，倚樓人在月明中。',64,'全唐诗/poet.tang.30000.json','["簾下秋江夜影空，倚樓人在月明中。", "不將行止問朝列，唯脫衣裳與釣翁。", "幾處別巢悲去燕，十年回首送歸鴻。", "那應更結廬山社，見說心閒勝遠公。"]'),
('34d3ded9-d202-430b-b9a6-fa46bb591496','贈李從貴','趙嘏','唐','唐诗','tang','','[]','白馬嘶風何處還，鞭梢拂地看南山。',64,'全唐诗/poet.tang.30000.json','["白馬嘶風何處還，鞭梢拂地看南山。", "珠簾捲盡不回首，春色欲闌休閉關。", "花外鳥歸殘雨暮，竹邊人語夕陽閑。", "知君舊隱嵩雲下，巖桂從今幾更攀。"]'),
('e6331512-d4a6-4822-889b-7e3688aa4999','贈陳正字','趙嘏','唐','唐诗','tang','','[]','魯儒今日意何如，名挂春官選籍初。',64,'全唐诗/poet.tang.30000.json','["魯儒今日意何如，名挂春官選籍初。", "野艇幾曾尋水去，故山從此與雲疎。", "吟憐受露花陰足，行覺嘶風馬力餘。", "聞說晚心心更靜，竹間依舊臥看書。"]'),
('503a5f1a-5c76-4b43-ba8c-77fa90b9fe28','洞庭寄所思','趙嘏','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','目斷蘭臺空望歸，錦衾香冷夢來稀。',64,'全唐诗/poet.tang.30000.json','["目斷蘭臺空望歸，錦衾香冷夢來稀。", "書中自報刀頭約，天上三看破鏡飛。", "孤浪謾疑紅臉笑，輕雲忽似舞羅衣。", "遙知不語坐相憶，寂寞洞房寒燭微。"]'),
('7b17508b-8cf2-4132-bac9-cc2ab268dfed','代人贈杜牧侍御','趙嘏','唐','唐诗','tang','','[]','郎作東臺御史時，妾長西望歛雙眉。',64,'全唐诗/poet.tang.30000.json','["郎作東臺御史時，妾長西望歛雙眉。", "一從詔下人皆羨，豈料恩衰不自知。", "高闕如天縈曉夢，華筵似水隔秋期。", "坐來情態猶無限，更向樓前舞柘枝。"]'),
('b42b5315-07b0-4120-bc49-7445752fc293','旅館聞雁別友人','趙嘏','唐','唐诗','tang','','[]','路遶秋塘首獨搔，背羣燕雁正呼號。',64,'全唐诗/poet.tang.30000.json','["路遶秋塘首獨搔，背羣燕雁正呼號。", "故關何處重相失，碧落有雲終自高。", "旅宿去緘他日恨，單飛誰見此生勞。", "行衣濕盡千山雪，腸斷金籠好羽毛。"]'),
('bd05ebbd-fe4d-4a79-9758-bcacf6d63d3c','泊鳧磯江館','趙嘏','唐','唐诗','tang','','[]','風雪晴來歲欲除，孤舟晚下意何如。',64,'全唐诗/poet.tang.30000.json','["風雪晴來歲欲除，孤舟晚下意何如。", "月當軒色湖平後，雁斷雲聲夜起初。", "傍曉管絃何處靜，犯寒楊柳遶津疎。", "三間茅屋東溪上，歸去生涯竹與書。"]'),
('adfdf949-0b83-4855-9f27-00ac40fd4a5f','春盡獨遊慈恩寺南池','趙嘏','唐','唐诗','tang','','[]','竹外池塘煙雨收，送春無伴亦遲留。',64,'全唐诗/poet.tang.30000.json','["竹外池塘煙雨收，送春無伴亦遲留。", "秦城馬上半年客，潘鬢水邊今日愁。", "氣變晚雲紅映闕，風含高樹碧遮樓。", "杏園花落遊人盡，獨爲圭峰一舉頭。"]'),
('6ab7aff2-45b5-443c-abc0-54cfcb1afded','重遊楚國寺','趙嘏','唐','唐诗','tang','','[]','往事飄然去不迴。',64,'全唐诗/poet.tang.30000.json','["往事飄然去不迴。", "空餘山色在樓臺，池塘風暖雁尋去。", "松桂寺高人獨來，莊叟著書真達者。", "賈生揮涕信悠哉，老僧心地閑於水。", "猶被流年日日催。"]'),
('e8ded480-d885-4be9-9556-4b420b07f40f','三像寺酬元秘書','趙嘏','唐','唐诗','tang','','[]','官總芸香閣署崇，可憐詩句落春風。',64,'全唐诗/poet.tang.30000.json','["官總芸香閣署崇，可憐詩句落春風。", "偶然侍坐水聲裏，還許醉吟松影中。", "車馬照來紅樹合，煙霞詠盡翠微空。", "不因高寺閑回首，誰識飄飄一塞翁。"]'),
('ee543ced-fbcd-4ad9-8a2c-bbf1a7631982','獻淮南李僕射','趙嘏','唐','唐诗','tang','','["\u957f\u6c5f"]','早年曾謁富民侯，今日難甘失鵠羞。',64,'全唐诗/poet.tang.30000.json','["早年曾謁富民侯，今日難甘失鵠羞。", "新諾似山無力負，舊恩如水滿身流。", "馬嘶紅葉蕭蕭晚，日照長江灩灩秋。", "功德萬重知不惜，一言拋得百生愁。"]'),
('091b1861-398f-4266-ba9d-2512b320ce39','江亭晚望','趙嘏','唐','唐诗','tang','','[]','碧江涼冷雁來疎，閒望江雲思有餘。',64,'全唐诗/poet.tang.30000.json','["碧江涼冷雁來疎，閒望江雲思有餘。", "秋館池亭荷葉歇，野人籬落豆花初。", "無愁自得仙翁術，多病能忘太史書。", "聞說故園香稻熟，片帆歸去就鱸魚。"]'),
('9adced95-50e0-4add-b15d-9d4f64edb50a','贈曹處士幽居','趙嘏','唐','唐诗','tang','','[]','勾漏先生冰玉然，曾將八石問羣仙。',64,'全唐诗/poet.tang.30000.json','["勾漏先生冰玉然，曾將八石問羣仙。", "中山暫醉一千日，南苑往來三百年。", "碁局不收花滿洞，霓旌欲別浪翻天。", "何須更學鴟夷子，頭白江湖一短船。"]'),
('63079530-4219-4af8-b780-cf16bedbb310','重陽日示舍弟','趙嘏','唐','唐诗','tang','','[]','多少鄉心入酒杯，野塘今日菊花開。',64,'全唐诗/poet.tang.30000.json','["多少鄉心入酒杯，野塘今日菊花開。", "新霜何處雁初下，故國窮秋首正迴。", "漸老向人空感激，一生驅馬傍塵埃。", "侯門無路提攜爾，虛共扁舟萬里來。"]'),
('adb27b34-0f01-48b7-a406-4b743715970a','客至','趙嘏','唐','唐诗','tang','','[]','得路逢津更俊才，可憐鞍馬照春來。',64,'全唐诗/poet.tang.30000.json','["得路逢津更俊才，可憐鞍馬照春來。", "殘花幾日小齋閉，大笑一聲幽抱開。", "袖拂碧溪寒繚繞，冠欹紅樹晚裴回。", "相逢少別更堪恨，何必秋風江上臺。"]'),
('2451e7c1-68dd-44cd-a113-07120b3056d0','歲暮江軒寄盧端公','趙嘏','唐','唐诗','tang','','[]','積水生高浪，長風自北時。',144,'全唐诗/poet.tang.30000.json','["積水生高浪，長風自北時。", "萬艘俱擁棹，上客獨吟詩。", "路以重湖阻，心將小謝期。", "渚雲愁正斷，江雁重驚悲。", "笑憶遊星子，歌尋罷貴池。", "夢來孤島在，醉醒百憂隨。", "戍逈煙生晚，江寒鳥過遲。", "問山樵者對，經雨釣船移。", "敢歎今留滯，猶勝曩別離。", "醉從陶令得，善必丈人知。", "道蹇才何取，恩深劍不疑。", "此身同岸柳，只待變寒枝。"]'),
('0b786f7c-5a8b-4302-8350-a1990224c4a7','秋日吳中觀貢藕','趙嘏','唐','唐诗','tang','','[]','野艇幾西東，清泠映碧空。',72,'全唐诗/poet.tang.30000.json','["野艇幾西東，清泠映碧空。", "褰衣來水上，捧玉出泥中。", "葉亂田田綠，蓮餘片片紅。", "激波纔入選，就日已生風。", "御潔玲瓏膳，人懷拔擢功。", "梯山謾多品，不與世流同。"]'),
('1dc19ddd-357b-4a1a-b5b2-260954fde2a4','華清宮和杜舍人','趙嘏','唐','唐诗','tang','','[]','五十年天子，離宮仰峻墻。',288,'全唐诗/poet.tang.30000.json','["五十年天子，離宮仰峻墻。", "登封時正泰，御宇日何長。", "上位先名實，中興事憲章。", "起戎輕甲胄，餘地復河湟。", "道帝玄元祖，儒封孔子王。", "因緣百司署，藂會一人湯。", "渭水波搖綠，秦郊草半黃。", "馬馴金勒細，鷹健玉鈴鏘。", "下箭朱弓滿，鳴鞭皓腕攘。", "畋思獲呂望，諫祇避周昌。", "兔跡貪前逐，梟心不早防。", "幾添鸚鵡勸，先賜荔枝嘗。", "月鎖千門靜，天吹一笛涼。", "細音搖羽珮，輕步宛霓裳。", "禍亂基潛結，升平意遽忘。", "衣冠逃犬虜，鼙鼓動漁陽。", "外戚心殊迫，中途事可量。", "血埋妃子豔，刅斷祿兒腸。", "近侍煙塵隔，前蹤輦路荒。", "益知迷寵佞，遺恨喪賢良。", "北闕尊明主，南宮遜上皇。", "禁清餘鳳吹，池冷睡龍光。", "祝壽山猶在，流年水共傷。", "杜鵑魂厭蜀，蝴蝶夢悲莊。"]'),
('4a7304d2-9568-4718-b19e-b27223071ece','下第','趙嘏','唐','唐诗','tang','','[]','南溪抱瓮客，失意自懷羞。',24,'全唐诗/poet.tang.30000.json','["南溪抱瓮客，失意自懷羞。", "晚路誰攜手，殘春自白頭。"]'),
('e37422f9-a0eb-4593-8b8b-cde70dd03dcd','到家','趙嘏','唐','唐诗','tang','','[]','童稚苦相問，歸來何太遲。',24,'全唐诗/poet.tang.30000.json','["童稚苦相問，歸來何太遲。", "共誰爭歲月，贏得鬢邊絲。"]'),
('fcd93539-7f6d-4bda-ae35-3db7176cf8b5','春釀','趙嘏','唐','唐诗','tang','','[]','春釀正風流，梨花莫問愁。',24,'全唐诗/poet.tang.30000.json','["春釀正風流，梨花莫問愁。", "馬卿思一醉，不惜鷫鸘裘。"]'),
('e1064aa9-4b66-4a1a-9f95-8675b1141fb7','寒塘','趙嘏','唐','唐诗','tang','','[]','曉髮梳臨水，寒塘坐見秋。',24,'全唐诗/poet.tang.30000.json','["曉髮梳臨水，寒塘坐見秋。", "鄉心正無限，一雁度南樓。"]'),
('df71e847-2c43-4330-93b6-d9746cc9ce74','寄前黃州竇使君','趙嘏','唐','唐诗','tang','','[]','池上笙歌寂不聞，樓中愁殺碧虛雲。',32,'全唐诗/poet.tang.30000.json','["池上笙歌寂不聞，樓中愁殺碧虛雲。", "玉壺凝盡重重淚，寄與風流舊使君。"]'),
('d66a9cf4-daff-4508-b3df-92cbe4bb95dd','八月二十九日宿懷','趙嘏','唐','唐诗','tang','','[]','秋天晴日菊還香，獨坐書齋思已長。',32,'全唐诗/poet.tang.30000.json','["秋天晴日菊還香，獨坐書齋思已長。", "無奈風光易流轉，強須傾酒一杯觴。"]'),
('b88c0412-546b-454c-a373-d88b4da95816','泗上奉送相公','趙嘏','唐','唐诗','tang','','[]','語堪銘座默含春，西漢公卿絕比倫。',32,'全唐诗/poet.tang.30000.json','["語堪銘座默含春，西漢公卿絕比倫。", "今日抱轅留不得，欲揮雙涕學舒人。"]'),
('5d16083f-c5eb-4774-9855-305a256961c6','贈桐鄉丞','趙嘏','唐','唐诗','tang','','[]','舟觸長松岸勢回，潺湲一夜繞亭臺。',32,'全唐诗/poet.tang.30000.json','["舟觸長松岸勢回，潺湲一夜繞亭臺。", "若敎靖節先生見，不肯更吟歸去來。"]'),
('3c286345-cf35-410e-b8b4-e95a51466009','哭李進士','趙嘏','唐','唐诗','tang','','[]','牽馬街中哭送君，靈車輾雪隔城聞。',32,'全唐诗/poet.tang.30000.json','["牽馬街中哭送君，靈車輾雪隔城聞。", "唯有山僧與樵客，共舁孤櫬入幽墳。"]'),
('2c472d1b-af32-48e0-9c86-37c69fcd4427','重陽','趙嘏','唐','唐诗','tang','','[]','節逢重九海門外，家在五湖煙水東。',32,'全唐诗/poet.tang.30000.json','["節逢重九海門外，家在五湖煙水東。", "還向秋山覓詩句，伴僧吟對菊花風。"]'),
('d36b2c8d-b365-4bf8-8b85-5a8a518b31d4','重陽日即事','趙嘏','唐','唐诗','tang','','[]','病酒堅辭綺席春，菊花空伴水邊身。',32,'全唐诗/poet.tang.30000.json','["病酒堅辭綺席春，菊花空伴水邊身。", "由來舉止非閑雅，不是龍山落帽人。"]'),
('55d37a59-81c0-4c02-adab-5ec0a29b67c4','十無詩寄桂府楊中丞 一','趙嘏','唐','唐诗','tang','','[]','琴酒曾將風月須，謝公名跡滿江湖。',32,'全唐诗/poet.tang.30000.json','["琴酒曾將風月須，謝公名跡滿江湖。", "不知貴擁旌旗後，猶暇憐詩愛酒無。"]'),
('0c0451bc-4866-4dd2-822c-106698e044ed','十無詩寄桂府楊中丞 二','趙嘏','唐','唐诗','tang','','[]','東省南宮興不孤，幾因詩酒謬招呼。',32,'全唐诗/poet.tang.30000.json','["東省南宮興不孤，幾因詩酒謬招呼。", "一從開署芙蓉幕，曾向風前記得無。"]'),
('fdfbac87-6a5c-42cb-8fab-98bae5fe4c07','十無詩寄桂府楊中丞 三','趙嘏','唐','唐诗','tang','','[]','遙聞桂水遶城隅，城上江山滿畫圖。',32,'全唐诗/poet.tang.30000.json','["遙聞桂水遶城隅，城上江山滿畫圖。", "爲問訾家洲畔月，清秋擬許醉狂無。"]'),
('d36e1851-faa2-40ed-855c-0784cd99b7b4','十無詩寄桂府楊中丞 四','趙嘏','唐','唐诗','tang','','[]','日暮江邊一小儒，空憐未有白髭鬚。',32,'全唐诗/poet.tang.30000.json','["日暮江邊一小儒，空憐未有白髭鬚。", "馬融已貴諸生老，猶自容窺絳帳無。"]'),
('998b0e98-59c2-4036-b0ae-4ea8424d7c6f','十無詩寄桂府楊中丞 五','趙嘏','唐','唐诗','tang','','[]','一種吟詩號孔徒，滄江有客獨疎愚。',32,'全唐诗/poet.tang.30000.json','["一種吟詩號孔徒，滄江有客獨疎愚。", "初筵盡辟知名士，許到風前月下無。"]'),
('9ba15920-f15e-4d0f-a239-6ac06fd075eb','十無詩寄桂府楊中丞 六','趙嘏','唐','唐诗','tang','','[]','望斷南雲日已晡，便應憑夢過重湖。',32,'全唐诗/poet.tang.30000.json','["望斷南雲日已晡，便應憑夢過重湖。", "不知自古登龍者，曾有因詩泥得無。"]'),
('627c1d99-08a3-4b6c-b93a-8bc420b4fdb5','十無詩寄桂府楊中丞 七','趙嘏','唐','唐诗','tang','','[]','早游門館一樵夫，祗愛吟詩傍藥爐。',32,'全唐诗/poet.tang.30000.json','["早游門館一樵夫，祗愛吟詩傍藥爐。", "旌斾滿江身不見，思言記得穎川無。"]'),
('4ae3c442-0ede-47d5-b311-e230a0de0c5f','十無詩寄桂府楊中丞 八','趙嘏','唐','唐诗','tang','','[]','孔融襟抱稱名儒，愛物憐才與世殊。',32,'全唐诗/poet.tang.30000.json','["孔融襟抱稱名儒，愛物憐才與世殊。", "今日賓堦忘姓字，當時省記薦雄無。"]'),
('acd0c10e-587a-4b45-91a3-34ae63bd9658','十無詩寄桂府楊中丞 九','趙嘏','唐','唐诗','tang','','[]','僻愛江山俯坐隅，人間不是便爲圖。',32,'全唐诗/poet.tang.30000.json','["僻愛江山俯坐隅，人間不是便爲圖。", "尊前爲問神仙伴，肯向三清慰薦無。"]'),
('21c2e074-4b54-4742-83af-3a05c76be088','十無詩寄桂府楊中丞 十','趙嘏','唐','唐诗','tang','','[]','膺門不避額逢珠，絕境由來卷軸須。',32,'全唐诗/poet.tang.30000.json','["膺門不避額逢珠，絕境由來卷軸須。", "早忝阿戎詩友契，趨庭曾薦禰生無。"]'),
('e48666fa-7a93-4116-bffb-d97fb415b83a','寄山僧','趙嘏','唐','唐诗','tang','','[]','雲裏幽僧不置房，橡花藤葉蓋禪牀。',32,'全唐诗/poet.tang.30000.json','["雲裏幽僧不置房，橡花藤葉蓋禪牀。", "朝來逢著山中伴，聞說新移最上方。"]'),
('c8aa719b-824f-4082-94f7-27d904718d68','喜張濆及第','趙嘏','唐','唐诗','tang','','[]','九轉丹成最上仙，青天暖日踏雲軒。',32,'全唐诗/poet.tang.30000.json','["九轉丹成最上仙，青天暖日踏雲軒。", "春風賀喜無言語，排比花枝滿杏園。"]'),
('a24d8a04-59dd-4729-820d-2553759d1ccd','贈張濆榜頭被駮落','趙嘏','唐','唐诗','tang','','[]','莫向花前泣酒杯，謫仙依舊是仙才。',32,'全唐诗/poet.tang.30000.json','["莫向花前泣酒杯，謫仙依舊是仙才。", "猶堪與世爲祥瑞，曾到蓬山頂上來。"]'),
('5c83dafb-da9d-4c87-b3cd-cb4e835d2098','悼亡二首 一','趙嘏','唐','唐诗','tang','','[]','一燭從風到奈何，二年衾枕逐流波。',32,'全唐诗/poet.tang.30000.json','["一燭從風到奈何，二年衾枕逐流波。", "雖知不得公然淚，時泣闌干恨更多。"]'),
('ff4284b9-7b5e-4c32-b6ff-ddd71b422ee5','悼亡二首 二','趙嘏','唐','唐诗','tang','','[]','明月蕭蕭海上風，君歸泉路我飄蓬。',32,'全唐诗/poet.tang.30000.json','["明月蕭蕭海上風，君歸泉路我飄蓬。", "門前雖有如花貌，爭奈如花心不同。"]'),
('1c135ff0-a6f5-4ecb-a7f9-0d7c10710581','宮烏栖','趙嘏','唐','唐诗','tang','','[]','宮烏棲處玉樓深，微月生簷夜夜心。',32,'全唐诗/poet.tang.30000.json','["宮烏棲處玉樓深，微月生簷夜夜心。", "香輦不回花自落，春來空佩辟寒金。"]'),
('1b5a070c-e194-4cef-b8e0-fa1a15f9b4d0','長信宮','趙嘏','唐','唐诗','tang','','[]','君恩已盡欲何歸，猶有殘香在舞衣。',32,'全唐诗/poet.tang.30000.json','["君恩已盡欲何歸，猶有殘香在舞衣。", "自恨身輕不如燕，春來長遶御簾飛。"]'),
('d4f72b44-1624-4663-bbe8-31242962ccd5','廣陵城','趙嘏','唐','唐诗','tang','','[]','紅映高臺綠繞城，城邊春草傍墻生。',32,'全唐诗/poet.tang.30000.json','["紅映高臺綠繞城，城邊春草傍墻生。", "隋家不向此中盡，汴水應無東去聲。"]'),
('65b32e14-32af-489d-b17a-482733889713','冷日過驪山','趙嘏','唐','唐诗','tang','','[]','冷日微煙渭水愁，翠華宮樹不勝秋。',32,'全唐诗/poet.tang.30000.json','["冷日微煙渭水愁，翠華宮樹不勝秋。", "霓裳一曲千門鎖，白盡梨園弟子頭。"]'),
('5db0b23a-1dc1-40db-b1f8-941de2fc2614','下第後歸永樂里自題二首 一','趙嘏','唐','唐诗','tang','','[]','無地無媒只一身，歸來空拂滿牀塵。',32,'全唐诗/poet.tang.30000.json','["無地無媒只一身，歸來空拂滿牀塵。", "尊前盡日誰相對，唯有南山似故人。"]'),
('9a806597-f7f6-4f1e-b033-57b757ce1bfd','下第後歸永樂里自題二首 二','趙嘏','唐','唐诗','tang','','[]','玄髮侵愁忽似翁，暖塵寒袖共東風。',32,'全唐诗/poet.tang.30000.json','["玄髮侵愁忽似翁，暖塵寒袖共東風。", "公卿門戶不知處，立馬九衢春影中。"]'),
('9f1414de-02df-465b-840a-31570cb16e0e','出試日獨遊曲江','趙嘏','唐','唐诗','tang','','[]','江莎漸映花邊綠，樓日自開池上春。',32,'全唐诗/poet.tang.30000.json','["江莎漸映花邊綠，樓日自開池上春。", "雙鶴遶空來又去，不知臨水有愁人。"]'),
('dfe5d78a-8fc0-46ab-916c-6afacddc4ff0','題曹娥廟','趙嘏','唐','唐诗','tang','','[]','青娥埋沒此江濱，江樹颼飀慘暮雲。',32,'全唐诗/poet.tang.30000.json','["青娥埋沒此江濱，江樹颼飀慘暮雲。", "文字在碑碑已墮，波濤辜負色絲文。"]'),
('9f937e33-dc40-4ae8-a244-55cfbfa8f813','題段氏中臺','趙嘏','唐','唐诗','tang','','[]','看山臺下水無塵，碧篠前頭曲水春。',32,'全唐诗/poet.tang.30000.json','["看山臺下水無塵，碧篠前頭曲水春。", "獨對一尊風雨夜，不知家有早朝人。"]'),
('06c9e6d5-f91d-497d-b40e-471f4c289d67','華州座中獻盧給事','趙嘏','唐','唐诗','tang','','[]','送迎皆到三峰下，滿面煙霜滿馬塵。',32,'全唐诗/poet.tang.30000.json','["送迎皆到三峰下，滿面煙霜滿馬塵。", "自是追攀認知己，青雲不假送迎人。"]'),
('ea49850f-bc2d-492a-96d5-92bee9655ba5','商山道中','趙嘏','唐','唐诗','tang','','[]','和如春色淨如秋，五月商山是勝遊。',32,'全唐诗/poet.tang.30000.json','["和如春色淨如秋，五月商山是勝遊。", "當晝火雲生不得，一溪縈作萬重愁。"]'),
('601e3e64-7d56-4e5b-9ba4-7ff6162e1f10','贈歙州妓','趙嘏','唐','唐诗','tang','','[]','灩灩橫波思有餘，庾樓明月墮雲初。',32,'全唐诗/poet.tang.30000.json','["灩灩橫波思有餘，庾樓明月墮雲初。", "揚州寒食春風寺，看遍花枝盡不如。"]'),
('026890c8-c99f-48ac-9cd9-77cd215dcb99','贈王明府','趙嘏','唐','唐诗','tang','','[]','五柳逢秋影漸微，陶潛戀酒不知歸。',32,'全唐诗/poet.tang.30000.json','["五柳逢秋影漸微，陶潛戀酒不知歸。", "但存物外醉鄉在，誰向人間問是非。"]'),
('24ad7bfb-5fb3-4175-a11c-8f7f881ef756','呂校書雨中見訪','趙嘏','唐','唐诗','tang','','[]','竹閣斜溪小檻明，惟君來賞見山情。',32,'全唐诗/poet.tang.30000.json','["竹閣斜溪小檻明，惟君來賞見山情。", "馬嘶風雨又歸去，獨聽子規千萬聲。"]'),
('41a1eea7-0cd8-415f-9dec-91638ecaa5b4','千秋嶺下','趙嘏','唐','唐诗','tang','','[]','知有巖前萬樹桃，未逢搖落思空勞。',32,'全唐诗/poet.tang.30000.json','["知有巖前萬樹桃，未逢搖落思空勞。", "年年盛發無人見，三十六溪春水高。"]'),
('0f3cc689-1a60-43d5-a2a7-6f1227e0ca16','歙州道中僕逃','趙嘏','唐','唐诗','tang','','[]','去跳風雨幾奔波，曾共辛勤奈若何。',32,'全唐诗/poet.tang.30000.json','["去跳風雨幾奔波，曾共辛勤奈若何。", "莫遣窮歸不知處，秋山重疊戍旗多。"]'),
('95512aed-4fe7-4e32-b698-d68e8fa28dc0','重陽日寄韋舍人','趙嘏','唐','唐诗','tang','','[]','節過重陽菊委塵，江邊病起杖扶身。',32,'全唐诗/poet.tang.30000.json','["節過重陽菊委塵，江邊病起杖扶身。", "不知此日龍山會，誰是風流落帽人。"]'),
('b10ee1ae-744a-4af9-933a-05ca3cd49c06','贈薛勛下第','趙嘏','唐','唐诗','tang','','[]','一擲雖然未得盧，驚人不用繞牀呼。',32,'全唐诗/poet.tang.30000.json','["一擲雖然未得盧，驚人不用繞牀呼。", "牢之坐被青雲逼，祗問君能酷似無。"]'),
('a3e20bc3-b48a-4439-8c12-da9489021df5','宛陵望月寄沈學士','趙嘏','唐','唐诗','tang','','[]','一川如畫敬亭東，待詔閑遊處處同。',32,'全唐诗/poet.tang.30000.json','["一川如畫敬亭東，待詔閑遊處處同。", "天竺山前鏡湖畔，何如今日庾樓中。"]'),
('40b14c6a-1ee6-4703-ba08-780fa7d023b9','翡翠巖','趙嘏','唐','唐诗','tang','','[]','芙蓉幕裏千場醉，翡翠巖前半日閑。',32,'全唐诗/poet.tang.30000.json','["芙蓉幕裏千場醉，翡翠巖前半日閑。", "惆悵晉朝人不到，謝公拋力上東山。"]'),
('742eb740-805e-4e63-bd6c-a86eb5bb661b','發新安後途中寄盧中丞二首 一','趙嘏','唐','唐诗','tang','','[]','樓上風流庾使君，笙歌曾醉此中聞。',32,'全唐诗/poet.tang.30000.json','["樓上風流庾使君，笙歌曾醉此中聞。", "目前已是陵陽路，回首叢山滿眼雲。"]'),
('cec64e0f-fe44-4486-9a72-5f2918eca31d','發新安後途中寄盧中丞二首 二','趙嘏','唐','唐诗','tang','','[]','晚樹蕭蕭促織愁，風簾似水滿牀秋。',32,'全唐诗/poet.tang.30000.json','["晚樹蕭蕭促織愁，風簾似水滿牀秋。", "千山不礙笙歌月，誰伴羊公上夜樓。"]'),
('0376ad8f-cf2c-4088-93e3-482c8395e20e','留題興唐寺','趙嘏','唐','唐诗','tang','','[]','滿水樓臺滿寺山，七年今日共躋攀。',32,'全唐诗/poet.tang.30000.json','["滿水樓臺滿寺山，七年今日共躋攀。", "月高對菊問行客，去折芳枝早晚還。"]'),
('dc71446e-1119-464f-a37a-070cad1ab353','廣陵道','趙嘏','唐','唐诗','tang','','[]','鬬雞臺邊花照塵，煬帝陵下水含春。',32,'全唐诗/poet.tang.30000.json','["鬬雞臺邊花照塵，煬帝陵下水含春。", "青雲回翅北歸雁，白首哭途何處人。"]'),
('3d99abf1-bc08-41b0-b347-2f0b340d6634','茅山道中','趙嘏','唐','唐诗','tang','','[]','溪樹重重水亂流，馬嘶殘雨晚程秋。',32,'全唐诗/poet.tang.30000.json','["溪樹重重水亂流，馬嘶殘雨晚程秋。", "門前便是仙山路，目送歸雲不得遊。"]'),
('e8dbee52-3fc7-4f5f-9d65-8817156d0460','江上與兄別','趙嘏','唐','唐诗','tang','','[]','楚國湘江兩渺瀰，暖川晴雁背帆飛。',32,'全唐诗/poet.tang.30000.json','["楚國湘江兩渺瀰，暖川晴雁背帆飛。", "人間離別盡堪哭，何況不知何日歸。"]'),
('62dbebd9-bd38-42e0-9747-1c8ac17f9eb9','落第','趙嘏','唐','唐诗','tang','','[]','九陌初晴處處春，不能回避看花塵。',32,'全唐诗/poet.tang.30000.json','["九陌初晴處處春，不能回避看花塵。", "由來得喪非吾事，本是釣魚船上人。"]'),
('c78d4a35-d541-449a-a7e0-373adff95945','宛陵館冬青樹','趙嘏','唐','唐诗','tang','','[]','碧樹如煙覆晚波，清秋欲盡客重過。',32,'全唐诗/poet.tang.30000.json','["碧樹如煙覆晚波，清秋欲盡客重過。", "故園亦有如煙樹，鴻雁不來風雨多。"]'),
('459acb00-3fd5-4061-9c51-d7d3fcd73699','贈五老韓尊師','趙嘏','唐','唐诗','tang','','[]','有客齋心事玉晨，對山鬚鬢綠無塵。',32,'全唐诗/poet.tang.30000.json','["有客齋心事玉晨，對山鬚鬢綠無塵。", "住山道士年如鶴，應識當時五老人。"]'),
('3e75a42e-ffa6-4c5f-8e4a-da82361c0464','經汾陽舊宅','趙嘏','唐','唐诗','tang','','[]','門前不改舊山河，破虜曾輕馬伏波。',32,'全唐诗/poet.tang.30000.json','["門前不改舊山河，破虜曾輕馬伏波。", "今日獨經歌舞地，古槐疎冷夕陽多。"]'),
('cb2535d9-d47f-4975-bec5-4cc216403169','寄盧中丞','趙嘏','唐','唐诗','tang','','[]','葉覆清溪灩灩紅，路橫秋色馬嘶風。',32,'全唐诗/poet.tang.30000.json','["葉覆清溪灩灩紅，路橫秋色馬嘶風。", "獨攜一榼郡齋酒，吟對青山憶謝公。"]'),
('63b4fd17-3860-4666-8aa2-e0e8e4697298','途中','趙嘏','唐','唐诗','tang','','[]','故園回首雁初來，馬上千愁付一杯。',32,'全唐诗/poet.tang.30000.json','["故園回首雁初來，馬上千愁付一杯。", "惟有新詩似相識，暮山吟處共徘徊。"]'),
('9f26c917-df1f-494b-822b-673770a3d6fd','寄裴瀾','趙嘏','唐','唐诗','tang','','[]','綺雲初墮亭亭月，錦席惟橫灩灩波。',32,'全唐诗/poet.tang.30000.json','["綺雲初墮亭亭月，錦席惟橫灩灩波。", "宋玉逢秋正高臥，一篇吟盡奈情何。"]'),
