('c6266414-0f25-4679-b5d6-d620701d9c5b','過噴玉泉','趙嘏','唐','唐诗','tang','','[]','平生半爲山淹留，馬上欲去還回頭。',32,'全唐诗/poet.tang.30000.json','["平生半爲山淹留，馬上欲去還回頭。", "兩京塵路一雙鬢，不見玉泉千萬秋。"]'),
('b09746fa-a6d8-42a1-a0e6-b803d7d90ed4','漢陰庭樹','趙嘏','唐','唐诗','tang','','[]','掘溝引水澆蔬圃，插竹爲籬護藥苗。',32,'全唐诗/poet.tang.30000.json','["掘溝引水澆蔬圃，插竹爲籬護藥苗。", "楊柳如絲風易亂，梅花似雪日難消。"]'),
('a2cf855a-cd7f-426b-97c8-c4df04325628','送王龜拾遺謝官後歸滻水山居','趙嘏','唐','唐诗','tang','','[]','水邊殘雪照亭臺，臺上風襟向雪開。',32,'全唐诗/poet.tang.30000.json','["水邊殘雪照亭臺，臺上風襟向雪開。", "還似當時姓丁鶴，羽毛成後一歸來。"]'),
('ec48c8d1-d8ac-488f-b5b6-dc702d74a9cd','宿長水主人','趙嘏','唐','唐诗','tang','','[]','白雲溪北叢巖東，樹石夜與潺湲通。',32,'全唐诗/poet.tang.30000.json','["白雲溪北叢巖東，樹石夜與潺湲通。", "行人一宿翠微月，二十五絃聲滿風。"]'),
('d5914d2a-193a-4c4d-915a-079a6c2bbccd','寒食離白沙','趙嘏','唐','唐诗','tang','','[]','莫驚客路已經年，尚有青春一半妍。',32,'全唐诗/poet.tang.30000.json','["莫驚客路已經年，尚有青春一半妍。", "試上方垣望春野，萬條楊柳拂青天。"]'),
('91e694bc-0a6a-4b8c-8d0a-c1c723a78000','將發循州社日于所居館宴送','趙嘏','唐','唐诗','tang','','[]','浪花如雪疊江風，社過高秋萬恨中。',32,'全唐诗/poet.tang.30000.json','["浪花如雪疊江風，社過高秋萬恨中。", "明日便隨江燕去，依依俱是故巢空。"]'),
('9aae63bc-43db-4428-865c-61655fa0d5e6','句','趙嘏','唐','唐诗','tang','','[]','浮雲悲晚翠，落日泣秋風。',88,'全唐诗/poet.tang.30000.json','["浮雲悲晚翠，落日泣秋風。", "語風雙燕立，褭樹百勞飛。", "松島鶴歸書信絕，橘洲風起夢魂香。", "徒知六國隨斤斧，莫有羣儒定是非。", "一千里色中秋月，十萬軍聲半夜潮。", "梁王舊館已秋色，珠履少年輕繡衣。"]'),
('cb1cb4d4-b158-4534-ba22-3b8198b0d8b6','漢堤詩','盧肇','唐','唐诗','tang','','[]','陰沴姦陽，來暴於襄。',245,'全唐诗/poet.tang.30000.json','["陰沴姦陽，來暴於襄。", "洎入大郛，波端若鋩。", "觸厚摧高，不知其防。", "駭潰顛委，萬室皆毀。", "竈登蛟鼉，堂集鱣鮪。", "惟恩若讎，母不能子。", "洪潰既涸，閈閎其虛。", "以隳我堵，以剝我廬。", "酸傷顧望，若踐丘墟。", "帝曰念嗟，朕日南顧。", "流災降慝，天曷台怒。", "滔滔襄郊，捽我嬰孺。", "於惟餘甿，飢傷喘呼。", "斯爲淫痍，孰往膏傅。", "惟汝元寮，僉舉明哲。", "我公用諧，苴茅杖節。", "來視襄人，噢咻提挈。", "不日不月，咍乎抃悅。", "乃泳故隄，陷於沙泥。", "缺落坳圯，由東訖西。", "公曰嗚呼，漢之有隄。", "實命襄人，不力乃力，則及乃身。", "具鍤與畚，漢隄其新。", "帝廩有粟，帝府有緡。"]'),
('ce218e95-f182-49c9-b256-402c0ea4a0ba','題甘露寺','盧肇','唐','唐诗','tang','','[]','北固巖端寺，佳名自上台。',120,'全唐诗/poet.tang.30000.json','["北固巖端寺，佳名自上台。", "地從京口斷，山到海門迴。", "曙色煙中滅，潮聲日下來。", "一隅通雉堞，千仞聳樓臺。", "林暗疑降虎，江空想度杯。", "福庭增氣象，仙磬落昭回。", "覺路花非染，流年景謾催。", "隋宮凋綠草，晉室散黃埃。", "西蜀波湍盡，東溟日月開。", "如登最高處，應得見蓬萊。"]'),
('abd4140e-ba4f-45ee-85e7-20059eee6bd3','江陵府初試澄心如水','盧肇','唐','唐诗','tang','','[]','丹心何所喻，唯水並清虛。',72,'全唐诗/poet.tang.30000.json','["丹心何所喻，唯水並清虛。", "莫測千尋底，難知一勺初。", "內明非有物，上善本無魚。", "澹泊隨高下，波瀾逐卷舒。", "養蒙方浩浩，出險每徐徐。", "若灌情田裏，常流盡不如。"]'),
('b95fdfcb-149d-46e7-a72c-5279ad03975b','風不鳴條','盧肇','唐','唐诗','tang','','[]','習習和風至，過條不自鳴。',72,'全唐诗/poet.tang.30000.json','["習習和風至，過條不自鳴。", "暗通青律起，遠傍白蘋生。", "拂樹花仍落，經林鳥自驚。", "幾牽蘿蔓動，潛惹柳絲輕。", "入谷迷松響，開窗失竹聲。", "薰弦方在御，萬國仰皇情。"]'),
('8159f17b-e5dd-4f1c-8347-cc576023ab17','別宜春赴舉','盧肇','唐','唐诗','tang','','[]','秋天草木正蕭疎，西望秦關別舊居。',64,'全唐诗/poet.tang.30000.json','["秋天草木正蕭疎，西望秦關別舊居。", "筵上芳樽今日酒，篋中黃卷古人書。", "辭鄉且伴銜蘆雁，入海終爲戴角魚。", "長短九霄飛直上，不敎毛羽落空虛。"]'),
('03242a8b-2d7e-4677-bb24-24708db0f371','射策後作','盧肇','唐','唐诗','tang','','[]','射策明時愧不才，敢期青律變寒灰。',64,'全唐诗/poet.tang.30000.json','["射策明時愧不才，敢期青律變寒灰。", "晴憐斷雁侵雲去，暖見醯雞傍酒來。", "箭發尚憂楊葉遠，愁生只恐杏花開。", "曲江春淺人游少，盡日看山醉獨回。"]'),
('2928212e-c708-48b1-8ee6-184e09ebd4da','和主司王起','盧肇','唐','唐诗','tang','','[]','嵩高降德爲時生，洪筆三題造化名。',64,'全唐诗/poet.tang.30000.json','["嵩高降德爲時生，洪筆三題造化名。", "鳳詔佇歸專北極，驪珠搜得盡東瀛。", "褒衣已換金章貴，禁掖曾隨玉樹榮。", "明日定知同相印，青衿新列柳間營。"]'),
('f5ed3d65-746c-4a9c-9f26-2608b486af0a','及第送潘圖歸宜春','盧肇','唐','唐诗','tang','','[]','三載皇都恨食貧，北溟今日化窮鱗。',64,'全唐诗/poet.tang.30000.json','["三載皇都恨食貧，北溟今日化窮鱗。", "青雲乍喜逢知己，白社猶悲送故人。", "對酒共驚千里別，看花自感一枝春。", "君歸爲說龍門寺，雷雨初生電遶身。"]'),
('103988e1-bd51-4114-b08b-af14f1cf2224','將歸宜春留題新安館','盧肇','唐','唐诗','tang','','[]','東里如今號鄭鄉，西家昔日近丘墻。',64,'全唐诗/poet.tang.30000.json','["東里如今號鄭鄉，西家昔日近丘墻。", "芸臺四部添新學，秘殿三年學老郎。", "天外鴛鸞愁不見，山中雲鶴喜相忘。", "猶張皂蓋歸蓬蓽，直謂時無許子將。"]'),
('7788b1f7-db6a-47b6-8e96-0689afff0c8f','競渡詩','盧肇','唐','唐诗','tang','','["\u6000\u5ff5", "\u7aef\u5348\u8282"]','石溪久住思端午，館驛樓前看發機。',66,'全唐诗/poet.tang.30000.json','["石溪久住思端午，館驛樓前看發機。", "鼙鼓動時雷隱隱，獸頭凌處雪微微。", "衝波突出入齊[譀]，躍浪爭先鳥退飛。", "向道是龍剛不信，果然奪得錦標歸。"]'),
('827f90ed-ddc0-45ff-b874-6958be37aabe','除歙州途中寄座主王侍郎','盧肇','唐','唐诗','tang','','[]','忽忝專城奉六條，自憐出谷屢遷喬。',64,'全唐诗/poet.tang.30000.json','["忽忝專城奉六條，自憐出谷屢遷喬。", "驅車雖道還家近，捧日惟愁去國遙。", "朱戶昨經新棨戟，風帆常覺戀簞瓢。", "江天夜夜知消息，長見台星在碧霄。"]'),
('d6609985-8c69-4caa-a71b-20240ff12823','御溝水','盧肇','唐','唐诗','tang','','[]','萬壑朝溟海，縈迴歲月多。',24,'全唐诗/poet.tang.30000.json','["萬壑朝溟海，縈迴歲月多。", "無如此溝水，咫尺奉天波。"]'),
('b5893314-7666-4343-8f5b-596bd10988bd','楊柳枝','盧肇','唐','唐诗','tang','','[]','青鳥泉邊草木春，黃雲塞上是征人。',32,'全唐诗/poet.tang.30000.json','["青鳥泉邊草木春，黃雲塞上是征人。", "歸來若得長條贈，不憚風霜與苦辛。"]'),
('12891135-c82d-4c3f-abfc-abda5d41711d','新植紅茶花偶出被人移去以詩索之','盧肇','唐','唐诗','tang','','[]','嚴恨柴門一樹花，便隨香遠逐香車。',32,'全唐诗/poet.tang.30000.json','["嚴恨柴門一樹花，便隨香遠逐香車。", "花如解語還應道，欺我郎君不在家。"]'),
('8a75702b-396d-448c-916d-0dab9cde542b','戲題','盧肇','唐','唐诗','tang','','[]','神女初離碧玉堦，彤雲猶擁牡丹鞋。',32,'全唐诗/poet.tang.30000.json','["神女初離碧玉堦，彤雲猶擁牡丹鞋。", "知道相公憐玉腕，強將纖手整金釵。"]'),
('3c035017-f98d-4922-9f93-4629cd53d771','成名後作','盧肇','唐','唐诗','tang','','[]','桂在蟾宮不可攀，功成業熟也何難。',32,'全唐诗/poet.tang.30000.json','["桂在蟾宮不可攀，功成業熟也何難。", "今朝折得東歸去，共與鄉閭年少看。"]'),
('c3a01f28-9a95-451d-8764-7cd54d4cbe7c','登祝融寺蘭若','盧肇','唐','唐诗','tang','','[]','祝融絕頂萬餘層，策杖攀蘿步步登。',32,'全唐诗/poet.tang.30000.json','["祝融絕頂萬餘層，策杖攀蘿步步登。", "行到月宮霞外寺，白雲相伴兩三僧。"]'),
('7ea69c75-5aa8-47f9-980d-b65d7cdb01ee','被謫連州','盧肇','唐','唐诗','tang','','[]','黃絹外孫翻得罪，華顛故老莫相嗤。',32,'全唐诗/poet.tang.30000.json','["黃絹外孫翻得罪，華顛故老莫相嗤。", "連州萬里無親戚，舊識唯應有荔枝。"]'),
('8ca8e155-a2e7-466b-b002-509820884ebc','謫後再書一絕','盧肇','唐','唐诗','tang','','[]','崆峒道士悞燒丹，赤鼠黃牙幾許難。',32,'全唐诗/poet.tang.30000.json','["崆峒道士悞燒丹，赤鼠黃牙幾許難。", "墜墮閻浮南斗下，不知何事犯星官。"]'),
('924eca61-cda9-41c2-bcd7-18aaae35802d','題清遠峽觀音院二首 一','盧肇','唐','唐诗','tang','','[]','清潭洞澈深千丈，危岫攀蘿上幾層。',32,'全唐诗/poet.tang.30000.json','["清潭洞澈深千丈，危岫攀蘿上幾層。", "秋盡更無黃葉樹，夜闌唯對白頭僧。"]'),
('f6135c93-7c18-44bb-9d64-bff0773f2f21','題清遠峽觀音院二首 二','盧肇','唐','唐诗','tang','','[]','風入古松添急雨，月臨虛檻背殘燈。',32,'全唐诗/poet.tang.30000.json','["風入古松添急雨，月臨虛檻背殘燈。", "老猨嘯狖還欺客，來撼窗前百尺藤。"]'),
('41de33cc-8047-40b7-8c95-11b2668051e1','喜楊舍人入翰林','盧肇','唐','唐诗','tang','','[]','御筆親批翰長銜，夜開金殿送瑤緘。',32,'全唐诗/poet.tang.30000.json','["御筆親批翰長銜，夜開金殿送瑤緘。", "平明玉案臨宣室，已見龍光出傅巖。"]'),
('1ff189c5-3f65-4f89-a969-6484d7ba1273','謫連州書春牛榜子','盧肇','唐','唐诗','tang','','[]','陽和未解逐民憂，雪滿羣山對白頭。',32,'全唐诗/poet.tang.30000.json','["陽和未解逐民憂，雪滿羣山對白頭。", "不得職田飢欲死，兒儂何事打春牛。"]'),
('fa0121f5-dd8e-4c64-99d8-5b7a547becec','送弟','盧肇','唐','唐诗','tang','','[]','去日家無擔石儲，汝須勤苦事樵漁。',32,'全唐诗/poet.tang.30000.json','["去日家無擔石儲，汝須勤苦事樵漁。", "古人盡向塵中遠，白日耕田夜讀書。"]'),
('65e7bb97-8b44-486d-9046-9a575f9ec7a7','牧童','盧肇','唐','唐诗','tang','','[]','誰人得似牧童心，牛上橫眠秋聽深。',32,'全唐诗/poet.tang.30000.json','["誰人得似牧童心，牛上橫眠秋聽深。", "時復往來吹一曲，何愁南北不知音。"]'),
('92369195-889f-414e-8045-88e4a9e3c3d9','嘲小兒','盧肇','唐','唐诗','tang','','[]','貪生只愛眼前珍，不覺風光度歲頻。',32,'全唐诗/poet.tang.30000.json','["貪生只愛眼前珍，不覺風光度歲頻。", "昨日見來騎竹馬，今朝早是有年人。"]'),
('6a2f667b-51d0-423e-8733-075fe00403b5','金錢花','盧肇','唐','唐诗','tang','','[]','輪郭休誇四字書，紅窠寫出對庭除。',32,'全唐诗/poet.tang.30000.json','["輪郭休誇四字書，紅窠寫出對庭除。", "時時買得佳人笑，本色金錢却不如。"]'),
('654ce2d7-35b0-494a-918b-7d87f8559335','木筆花','盧肇','唐','唐诗','tang','','[]','媆如新竹管初齊，粉膩紅輕樣可攜。',32,'全唐诗/poet.tang.30000.json','["媆如新竹管初齊，粉膩紅輕樣可攜。", "誰與詩人偎檻看，好於牋墨併分題。"]'),
('ba28d02a-0178-475a-9f13-025bbc6b8a34','句','盧肇','唐','唐诗','tang','','[]','君夢涔陽月，中秋憶棹歌。',56,'全唐诗/poet.tang.30000.json','["君夢涔陽月，中秋憶棹歌。", "妙吹應諧鳳，工書定得鵝。", "亭邊古木晝陰陰，亭下寒潭百丈深。", "黃菊舊連陶令宅，青山遙負向平心。"]'),
('f133ced6-8bcb-4a1b-bddb-4a571a3e8000','塞下曲','丁稜','唐','唐诗','tang','','[]','北風鳴晚角，雨雪塞雲低。',36,'全唐诗/poet.tang.30000.json','["北風鳴晚角，雨雪塞雲低。", "烽舉戰軍動，天寒征馬嘶。", "出營紅斾展，過磧暗沙迷。"]'),
('12726193-5bd7-4256-963b-0722e4457ce7','和主司王起','丁稜','唐','唐诗','tang','','[]','公心獨立副天心，三轄春闈冠古今。',64,'全唐诗/poet.tang.30000.json','["公心獨立副天心，三轄春闈冠古今。", "蘭署門生皆入室，蓮峰太守別知音。", "同升翰苑時名重，遍歷朝端主意深。", "新有受恩江海客，坐聽朝夕繼爲霖。"]'),
('df259936-03b8-42cf-8db5-12f4c6c3417a','和主司王起','高退之','唐','唐诗','tang','','[]','昔年桃李已滋榮，今日蘭蓀又發生。',64,'全唐诗/poet.tang.30000.json','["昔年桃李已滋榮，今日蘭蓀又發生。", "葑菲采時皆有道，權衡分處且無情。", "叨陪鴛鷺朝天客，共作門闌出谷鸎。", "何事感恩偏覺重，忽聞金榜扣柴荆。"]'),
('450da1d8-8fdd-473d-ad15-85b7aabfcdb2','和主司王起','孟球','唐','唐诗','tang','','[]','當年門下化龍成，今日餘波進後生。',64,'全唐诗/poet.tang.30000.json','["當年門下化龍成，今日餘波進後生。", "仙籍共知推麗藻，禁垣同得薦嘉名。", "桃蹊早茂誇新萼，菊圃初開耀晚英。", "誰料羽毛方出谷，許敎齊和九臯鳴。"]'),
('6ac42eb7-aca0-40cc-8737-474974bf2849','和主司王起','劉耕','唐','唐诗','tang','','[]','孔門頻建鑄顏功，紫綬青衿感激同。',64,'全唐诗/poet.tang.30000.json','["孔門頻建鑄顏功，紫綬青衿感激同。", "一簣勤勞成太華，三年恩德仰維嵩。", "楊隨前輩穿皆中，桂許平人折欲空。", "慚和周郎應見顧，感知大造竟無窮。"]'),
('78b7af99-f1d7-4db1-b2cf-d2f419c6fd30','和主司王起','裴翻','唐','唐诗','tang','','[]','常將公道選羣生，猶被春闈屈重名。',64,'全唐诗/poet.tang.30000.json','["常將公道選羣生，猶被春闈屈重名。", "文柄久持殊歲紀，恩門三啓動寰瀛。", "雲霄幸接鴛鸞盛，變化欣同草木榮。", "乍得陽和如細柳，參差長近亞夫營。"]'),
('bb0958b4-7b3c-4ba9-bbb2-f2f851a86843','和主司王起','樊驤','唐','唐诗','tang','','[]','滿朝簪髮半門生，又見新書甲乙名。',64,'全唐诗/poet.tang.30000.json','["滿朝簪髮半門生，又見新書甲乙名。", "孤進自今開道路，至公依舊振寰瀛。", "雲飛太華清詞著，花發長安白屋榮。", "忝受恩光同上客，惟將報德是經營。"]'),
('e6b06eaa-d8c0-41d9-b404-8a0d3f57dcf1','和主司王起','崔軒','唐','唐诗','tang','','[]','滿朝朱紫半門生，新榜勞人又得名。',64,'全唐诗/poet.tang.30000.json','["滿朝朱紫半門生，新榜勞人又得名。", "國器舊知收片玉，朝宗轉覺集登瀛。", "同升翰苑三年美，繼入花源九族榮。", "共仰蓮峰聽雪唱，欲賡仙曲意怔營。"]'),
('f2ce8bfc-de62-4c4f-8864-4c42992edaa8','和主司王起','蒯希逸','唐','唐诗','tang','','[]','一振聲華入紫薇，三開秦鏡照春闈。',64,'全唐诗/poet.tang.30000.json','["一振聲華入紫薇，三開秦鏡照春闈。", "龍門舊列金章貴，鶯谷新遷碧落飛。", "恩感風雷宜變化，詩裁錦繡借光輝。", "誰知散質多榮忝，鴛鷺清塵接布衣。"]'),
('549adca9-4e7c-4947-ba37-7577efd1c0da','句','蒯希逸','唐','唐诗','tang','','[]','蟾蜍醉裏破，蛺蝶夢中殘。',28,'全唐诗/poet.tang.30000.json','["蟾蜍醉裏破，蛺蝶夢中殘。", "山險不曾離馬後，酒醒長見在牀前。"]'),
('65ac8e10-2d47-4abf-a30b-019f8053a0be','望九華山','林滋','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','茲山突出何怪奇，上有萬狀無凡姿。',128,'全唐诗/poet.tang.30000.json','["茲山突出何怪奇，上有萬狀無凡姿。", "大者嶙峋若奔兕，小者㠥嵬如嬰兒。", "玉柱金莖相拄枝，干空踰碧勢參差。", "虛中始訝巨靈擘，阧處乍驚愚叟移。", "蘿煙石月相蔽虧，天風褭褭猨咿咿。", "龍潭萬古噴飛溜，虎穴幾人能得窺。", "吁予比年愛靈境，到此始覺魂神馳。", "如何獨得百丈索，直上高峰拋俗羈。"]'),
('dae6f6ea-c871-49b4-932e-5e3e0931714c','春望','林滋','唐','唐诗','tang','','[]','春海鏡長天，青郊麗上年。',48,'全唐诗/poet.tang.30000.json','["春海鏡長天，青郊麗上年。", "林光虛霽曉，山翠薄晴煙。", "氣暖禽聲變，風恬草色鮮。", "散襟披石磴，韶景自深憐。"]'),
('37033da7-e91a-442b-99d0-08013f7f359f','蠡澤旅懷','林滋','唐','唐诗','tang','','[]','誰言行旅日，況復桃花時。',48,'全唐诗/poet.tang.30000.json','["誰言行旅日，況復桃花時。", "水即滄溟遠，星從天漢垂。", "川光獨鳥暮，林色落英遲。", "豈是王程急，偏多游子悲。"]'),
('7c8793db-cd72-4133-9a1d-902fe663291a','宴韋侍御新亭','林滋','唐','唐诗','tang','','[]','煙磴披青靄，風筵藉紫苔。',48,'全唐诗/poet.tang.30000.json','["煙磴披青靄，風筵藉紫苔。", "花香凌桂醑，竹影落藤桮。", "鳴籟將歌遠，飛枝拂舞開。", "未愁留興晚，明月度雲來。"]'),
('b3c9c567-cd90-4a43-b10c-9e1769ed0ee0','人日','林滋','唐','唐诗','tang','','[]','春輝新入碧煙開，芳院初將穆景來。',64,'全唐诗/poet.tang.30000.json','["春輝新入碧煙開，芳院初將穆景來。", "共向花前圖瑞勝，試看池上動輕苔。", "林香半落沾羅幌，蕙色微含近酒桮。", "聞道宸游方命賞，應隨恩賚喜昭回。"]'),
('1bd3313c-f78d-4976-80e5-c6d87addffc6','和主司王起','林滋','唐','唐诗','tang','','[]','龍門一變荷生成，況是三傳不朽名。',64,'全唐诗/poet.tang.30000.json','["龍門一變荷生成，況是三傳不朽名。", "美譽早聞喧北闕，頹波今見走東瀛。", "鴛行既接參差影，雞樹仍同次第榮。", "從此青衿與朱紫，升堂侍宴更何營。"]'),
('8e427cef-2f58-4725-a290-2e3e6f4db072','聽蜀道士琴歌','李宣古','唐','唐诗','tang','','[]','至道不可見，正聲難得聞。',220,'全唐诗/poet.tang.30000.json','["至道不可見，正聲難得聞。", "忽逢羽客抱綠綺，西別峨嵋峰頂雲。", "初排□面躡輕響，似擲細珠鳴玉上。", "忽揮素爪畫七弦，蒼崖劈裂迸碎泉。", "憤聲高，怨聲咽，屈原呌天兩妃絕。", "朝雉飛，雙鶴離，屬玉夜啼獨鶩悲。", "吹我神飛碧霄裏，牽我心靈入秋水。", "有如驅逐太古來，邪淫辟蕩貞心開。", "孝爲子，忠爲臣，不獨語言能敎人。", "前弄嘯，後弄嚬，一舒一慘非冬春。", "從朝至暮聽不足，相將直說瀛洲宿。", "更深彈罷背孤燈，窗雪蕭蕭打寒竹。", "人間豈合值仙蹤，此別多應不再逢。", "抱琴却上瀛洲去，一片白雲千萬峰。"]'),
('0b4854ab-22e7-44f8-9069-7ef8b9ffc114','和主司王起','李宣古','唐','唐诗','tang','','[]','恩光忽逐曉春生，金榜前頭忝姓名。',64,'全唐诗/poet.tang.30000.json','["恩光忽逐曉春生，金榜前頭忝姓名。", "三感至公裨造化，重揚文德振寰瀛。", "佇爲霖雨曾相賀，半在雲霄覺更榮。", "何處新詩添照灼，碧蓮峰下柳間營。"]'),
('ce26a624-d69c-4a08-b37e-f188fbbaabcc','杜司空席上賦','李宣古','唐','唐诗','tang','','[]','紅燈初上月輪高，照見堂前萬朵桃。',64,'全唐诗/poet.tang.30000.json','["紅燈初上月輪高，照見堂前萬朵桃。", "觱栗調清銀象管，琵琶聲亮紫檀槽。", "能歌姹女顏如玉，解引蕭郎眼似刀。", "爭奈夜深拋耍令，舞來挼去使人勞。"]'),
('93bfdbd2-59a7-4d8f-b00a-3d2e7a38bbe1','賦寒食日亥時','李宣古','唐','唐诗','tang','','[]','人定朱門尚未開，初星粲粲照人回。',32,'全唐诗/poet.tang.30000.json','["人定朱門尚未開，初星粲粲照人回。", "此時寒食無煙火，花柳蒼蒼月欲來。"]'),
('e2ff08ae-7a07-4825-9dd3-ef08233463bc','句','李宣古','唐','唐诗','tang','','[]','翠蓋不西來，池上天池歇。',36,'全唐诗/poet.tang.30000.json','["翠蓋不西來，池上天池歇。", "冉冉池上煙，盈盈池上柳。", "生貴非道傍，不斷行人手。"]'),
('7bee6ea7-4c8e-4c50-972a-82cac662b932','風不鳴條','黃頗','唐','唐诗','tang','','[]','五緯起祥飆，無聲瑞聖朝。',72,'全唐诗/poet.tang.30000.json','["五緯起祥飆，無聲瑞聖朝。", "稍開含露蘂，纔轉惹煙條。", "密葉應潛變，低枝幾暗搖。", "林間鶯欲囀，花下蝶微飄。", "初滿沿堤草，因生逐水苗。", "太平無一事，天外奏虞韶。"]'),
('e5ffec39-c0a6-46ca-ae5d-53c32c239bd7','和主司王起','黃頗','唐','唐诗','tang','','[]','二十二年文敎主，三千上士滿皇州。',66,'全唐诗/poet.tang.30000.json','["二十二年文敎主，三千上士滿皇州。", "獨陪宣父蓬瀛奏，方接顏生魯衛遊。", "多羨龍門齊變化，屢看雞樹第名流。", "升堂何處最榮美，朱紫環[尊]幾處酬。"]'),
('ba8bd2fe-2125-4a44-a3e9-25b7ffd4706f','聞宜春諸舉子陪郡主登河梁翫月','黃頗','唐','唐诗','tang','','[]','一年秋半月當空，遙羨飛觴接庾公。',64,'全唐诗/poet.tang.30000.json','["一年秋半月當空，遙羨飛觴接庾公。", "虹影迥分銀漢上，兔輝全寫玉筵中。", "笙歌送盡迎寒漏，冰雪吟消永夜風。", "雖向東堂先折桂，不如賓席此時同。"]'),
('4922f871-64de-47b8-b45c-dee50d277f28','和主司王起','張道符','唐','唐诗','tang','','[]','三開文鏡繼芳聲，暗暗雲霄接去程。',64,'全唐诗/poet.tang.30000.json','["三開文鏡繼芳聲，暗暗雲霄接去程。", "會壓洪波先得路，早陞清禁共垂名。", "蓮峰對處朱輪貴，金榜傳時玉韻成。", "更許下才聽白雪，一枝今過郄詵榮。"]'),
('f7cea501-63bf-4629-be32-2c452d3fa8e0','和主司王起','丘上卿','唐','唐诗','tang','','[]','常將公道選諸生，不是鴛鴻不得名。',64,'全唐诗/poet.tang.30000.json','["常將公道選諸生，不是鴛鴻不得名。", "天上宴回聯步武，禁中麻出滿寰瀛。", "簪裾盡過前賢貴，門館仍叨舊學榮。", "看著鳳池相繼入，都堂那肯滯關營。"]'),
('0df9c129-217f-4c79-9bf7-536b449c9e04','和主司王起','石貫','唐','唐诗','tang','','[]','重德由來爲國生，五朝清顯冠公卿。',64,'全唐诗/poet.tang.30000.json','["重德由來爲國生，五朝清顯冠公卿。", "風波久佇濟川檝，羽翼三遷出谷鶯。", "絳帳青衿同日貴，春蘭秋菊異時榮。", "孔門弟子皆賢哲，誰料窮儒忝一名。"]'),
('765c2296-3b94-4f60-ac6d-b6d55064e36a','和主司王起','李潛','唐','唐诗','tang','','[]','文學宗師心秤平，無私三用佐貞明。',64,'全唐诗/poet.tang.30000.json','["文學宗師心秤平，無私三用佐貞明。", "恩波舊是仙舟客，德宇新添月桂名。", "蘭署崇資金色重，蓮峰高唱玉音清。", "羽毛方荷生成力，難繼鸞皇上漢聲。"]'),
('922c39a1-9e9c-4353-b82c-ce2cf1dd11ec','和主司王起','孟守','唐','唐诗','tang','','[]','科文又主守初時，光顯門生濟會期。',64,'全唐诗/poet.tang.30000.json','["科文又主守初時，光顯門生濟會期。", "美擅東堂登甲乙，榮同內署侍恩私。", "羣鶯共喜新遷木，雙鳳皆當即入池。", "別有倍深知感士，曾經兩度得芳枝。"]'),
('bbe559bd-08aa-4f4b-98bb-792a73aeb220','和主司王起','唐思言','唐','唐诗','tang','','[]','儒雅皆傳德敎行，幾崇浮俗贊文明。',64,'全唐诗/poet.tang.30000.json','["儒雅皆傳德敎行，幾崇浮俗贊文明。", "龍門昔上波濤遠，禁署同登渥澤榮。", "虛散謬當陪杞梓，後先寧異感生成。", "時方側席徵賢急，況說謌謠近帝京。"]'),
('c7ca8540-d994-4db6-93ce-fc4a58771397','風不鳴條','戈牢','唐','唐诗','tang','','[]','旭日懸清景，微風在綠條。',72,'全唐诗/poet.tang.30000.json','["旭日懸清景，微風在綠條。", "入松聲不發，度柳影空搖。", "長養應潛變，扶疎每暗飄。", "有林時嫋嫋，無樹漸蕭蕭。", "慢逐青煙散，輕和瑞氣饒。", "豐年知有待，歌詠美唐堯。"]'),
('02a5e0a7-720c-4c82-9f37-5aef6360fb4c','和主司王起','戈牢','唐','唐诗','tang','','[]','聖乾文德最稱賢，自古儒生少比肩。',64,'全唐诗/poet.tang.30000.json','["聖乾文德最稱賢，自古儒生少比肩。", "再啓龍門將二紀，兩司鶯谷已三年。", "蓬山皆美成榮貴，金榜誰知忝後先。", "正是感恩流涕日，但思旌斾碧峰前。"]'),
('661a011f-b13e-43e3-8ed0-7899fe6d1c17','風不鳴條','金厚載','唐','唐诗','tang','','[]','寂寂曙風生，遲遲散野輕。',72,'全唐诗/poet.tang.30000.json','["寂寂曙風生，遲遲散野輕。", "露華搖有滴，林葉褭無聲。", "暗翦藂芳發，空傳谷鳥鳴。", "悠揚韶景靜，澹蕩霽煙橫。", "遠水波瀾息，荒郊草樹榮。", "吾君垂至化，萬類共澄清。"]'),
('10a0b7cd-4720-4ffb-92d6-0d72359fdf65','和主司王起','金厚載','唐','唐诗','tang','','[]','長慶曾收間世英，果居臺閣冠公卿。',64,'全唐诗/poet.tang.30000.json','["長慶曾收間世英，果居臺閣冠公卿。", "天書再受恩波遠，金榜三開日月明。", "已見差肩趍翰苑，更期連步掌台衡。", "小儒謬蹟雲霄路，心仰蓮峰望太清。"]'),
('54ff208d-be9b-4ed3-9fbc-c8f45a42f941','風不鳴條','王甚夷','唐','唐诗','tang','','[]','聖日祥風起，韶暉助發生。',72,'全唐诗/poet.tang.30000.json','["聖日祥風起，韶暉助發生。", "蒙蒙遙野色，褭褭細條輕。", "荏弱看漸動，怡和吹不鳴。", "枝含餘露濕，林霽曉煙平。", "縹緲春光媚，悠揚景氣晴。", "康哉帝堯代，寰宇共澄清。"]'),
('9b26e5a5-cf1f-4349-8e7f-3a294937ba77','和主司王起','王甚夷','唐','唐诗','tang','','[]','春闈帝念主生成，長慶公聞兩歲名。',64,'全唐诗/poet.tang.30000.json','["春闈帝念主生成，長慶公聞兩歲名。", "有蘊赤心分雨露，無私和氣浹寰瀛。", "龍門乍出難勝幸，鴛侶先行是最榮。", "遙仰高峰看白雪，多慚屬和意屏營。"]'),
('0b3df43d-b443-466e-8850-b800c99ec211','送李潛歸綿州覲省','姚鵠','唐','唐诗','tang','','[]','朱樓對翠微，紅斾出重扉。',48,'全唐诗/poet.tang.30000.json','["朱樓對翠微，紅斾出重扉。", "此地千人望，寥天一鶴歸。", "雪封山崦白，鳥拂棧梁飛。", "誰比趨庭戀，驪珠耀綵衣。"]'),
('ca2f6c8f-6000-403e-8488-a2e31862191b','塞外寄張侍御','姚鵠','唐','唐诗','tang','','[]','千里入黃雲，羈愁日日新。',48,'全唐诗/poet.tang.30000.json','["千里入黃雲，羈愁日日新。", "疎鐘關路曉，遠雨塞山春。", "南眺有歸鴈，北來無故人。", "却思陪宴處，迴望與天隣。"]'),
('078879f1-198b-4373-af92-9be67071767e','曉發','姚鵠','唐','唐诗','tang','','[]','旅行宜早發，況復是南歸。',48,'全唐诗/poet.tang.30000.json','["旅行宜早發，況復是南歸。", "月影緣山盡，鐘聲隔浦微。", "殘星螢共失，落葉鳥和飛。", "去去渡南浦，村中人出稀。"]'),
('77e275cf-2879-446f-92a4-4a57e69f819a','題終南山隱者居','姚鵠','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','開門絕壑旁，躡蘚過花梁。',48,'全唐诗/poet.tang.30000.json','["開門絕壑旁，躡蘚過花梁。", "路入峰巒影，風來芝朮香。", "夜吟明雪牖，春夢閉雲房。", "盡室更何有，一琴兼一觴。"]'),
('0b63cf2d-0b6b-46fa-9be4-cfa9d397dc15','嘉川驛樓晚望','姚鵠','唐','唐诗','tang','','[]','樓壓寒江上，開簾對翠微。',48,'全唐诗/poet.tang.30000.json','["樓壓寒江上，開簾對翠微。", "斜陽諸嶺暮，古渡一僧歸。", "窗逈雲衝起，汀遙鳥背飛。", "誰言坐多倦，目極自忘機。"]'),
('c4b9d040-a851-4b52-9a73-2fa4f0e919d3','送人歸吳','姚鵠','唐','唐诗','tang','','[]','東吳與上國，萬里路迢迢。',48,'全唐诗/poet.tang.30000.json','["東吳與上國，萬里路迢迢。", "爲別晨昏久，全輕水陸遙。", "湘陰島上寺，楚色月中潮。", "到此一長望，知君積恨銷。"]'),
('f7e6633c-de24-4266-b94d-3b588c4001f9','送石貫歸湖州','姚鵠','唐','唐诗','tang','','[]','同志幸同年，高堂君獨還。',48,'全唐诗/poet.tang.30000.json','["同志幸同年，高堂君獨還。", "齊榮恩未報，共隱事應閑。", "訪寺臨湖岸，開樓見海山。", "洛中推二陸，莫久戀鄉關。"]'),
('8cc1b513-d9b8-47ac-ad9b-d05fad839597','送劉耕歸舒州','姚鵠','唐','唐诗','tang','','[]','四座莫紛紛，須臾岐路分。',48,'全唐诗/poet.tang.30000.json','["四座莫紛紛，須臾岐路分。", "自從同得意，誰不惜離羣。", "舊國連青海，歸程在白雲。", "棄繻當日路，應競看終軍。"]'),
('693778c0-81f5-4fa1-97a3-a53246b99651','寄贈許璋少府','姚鵠','唐','唐诗','tang','','[]','若說君高道，何人更得如。',48,'全唐诗/poet.tang.30000.json','["若說君高道，何人更得如。", "公庭唯樹石，生計是琴書。", "詩句峭無敵，文才清有餘。", "不知尺水內，爭滯北溟魚。"]'),
('f8dff789-b8cb-423b-a259-465e5c6f8e69','寄雍陶先輩','姚鵠','唐','唐诗','tang','','[]','知音杳何處，書札寄無由。',48,'全唐诗/poet.tang.30000.json','["知音杳何處，書札寄無由。", "獨宿月中寺，相思天畔樓。", "露凝衰草白，螢度遠煙秋。", "悵望難歸枕，吟勞生夜愁。"]'),
('5a647860-3e15-44de-8557-a01692364456','寄友人','姚鵠','唐','唐诗','tang','','[]','西風又開菊，久客意如何。',48,'全唐诗/poet.tang.30000.json','["西風又開菊，久客意如何。", "舊國天涯遠，清砧月夜多。", "明時難際會，急景易蹉跎。", "抱玉終須獻，誰言戀薜蘿。"]'),
('a74eded6-c668-4055-996b-b238c2531254','感懷陳情','姚鵠','唐','唐诗','tang','','[]','恩重空感激，何門誓殺身。',48,'全唐诗/poet.tang.30000.json','["恩重空感激，何門誓殺身。", "謬曾分玉石，竟自困風塵。", "陰谷非因暖，幽叢豈望春。", "升沈在言下，應念異他人。"]'),
('e6503dc8-2d00-4ee0-a3cd-dc55313bd97d','送程秀才下第歸蜀','姚鵠','唐','唐诗','tang','','[]','鶯遷與鶂退，十載泣岐分。',48,'全唐诗/poet.tang.30000.json','["鶯遷與鶂退，十載泣岐分。", "蜀道重來老，巴猨此去聞。", "曉程侵嶺雪，遠棧入谿雲。", "莫滯趨庭戀，榮親祗待君。"]'),
('83520070-449b-4362-bddf-708f5038024f','旱魚詞上苗相公','姚鵠','唐','唐诗','tang','','[]','似龍鱗已足，唯是欠登門。',48,'全唐诗/poet.tang.30000.json','["似龍鱗已足，唯是欠登門。", "日裏腮猶濕，泥中目未昏。", "乞鋤防蟻穴，望水瀉金盆。", "他日能爲雨，公田報此恩。"]'),
('e041d3f4-bb26-40d0-9252-1826e250ad8e','野寺寓居即事二首 一','姚鵠','唐','唐诗','tang','','[]','南山色當戶，初日半簷時。',48,'全唐诗/poet.tang.30000.json','["南山色當戶，初日半簷時。", "鶴去臥看遠，僧來嫌起遲。", "窗明雲影斷，庭曉樹陰移。", "何處題新句，連谿密葉垂。"]'),
('29f8acdb-25d2-4cdd-90ac-b5028d3fc423','野寺寓居即事二首 二','姚鵠','唐','唐诗','tang','','[]','古寺更何有，當庭唯折幢。',48,'全唐诗/poet.tang.30000.json','["古寺更何有，當庭唯折幢。", "伴僧青蘚榻，對雨白雲窗。", "暝色生前嶺，離魂隔遠江。", "沙洲半藜草，飛鷺白雙雙。"]'),
('edd89a46-2d7a-4510-80db-5bcfbaffa33b','襄州獻盧尚書','姚鵠','唐','唐诗','tang','','[]','立事成功盡遠圖，一方獨與萬方殊。',64,'全唐诗/poet.tang.30000.json','["立事成功盡遠圖，一方獨與萬方殊。", "藩臣皆競師兵畧，相國今多揖廟謨。", "禮樂政行凋弊俗，歌謠聲徹帝王都。", "即隨鳳詔歸何處，祗是操持造化鑪。"]'),
('2b5920c0-c1a7-44c7-8d14-48c22657b8a5','將歸蜀留獻恩地僕射二首 一','姚鵠','唐','唐诗','tang','','[]','自持衡鏡採幽沈，此事常聞曠古今。',64,'全唐诗/poet.tang.30000.json','["自持衡鏡採幽沈，此事常聞曠古今。", "危葉只將終委地，焦桐誰料却爲琴。", "蒿萊詎報生成德，犬馬空懷感戀心。", "明日還家盈眼血，定應迴首即霑襟。"]'),
('35cf4d8e-6ecd-49fe-8a3a-d098f9f32bd9','將歸蜀留獻恩地僕射二首 二','姚鵠','唐','唐诗','tang','','[]','江上長思狎釣翁，此心難與昨心同。',64,'全唐诗/poet.tang.30000.json','["江上長思狎釣翁，此心難與昨心同。", "自承丘壑新恩重，已分煙霞舊隱空。", "龍變偶因資巨浪，鳥飛誰肯借高風。", "應憐死節無門効，永歎潛懷似轉蓬。"]'),
('6ea858a2-2beb-4a9f-945d-d13ae55873bc','隨州獻李侍御二首 一','姚鵠','唐','唐诗','tang','','[]','彩筆曾專造化權，道尊翻向宦途閑。',64,'全唐诗/poet.tang.30000.json','["彩筆曾專造化權，道尊翻向宦途閑。", "端居有地唯栽藥，靜坐無時不憶山。", "德望舊懸霄漢外，政聲新溢路歧間。", "衆知聖主搜賢相，朝夕欲徴黃霸還。"]'),
('19b182ea-c7d2-4b63-9fe0-1a30ce4b7e8c','隨州獻李侍御二首 二','姚鵠','唐','唐诗','tang','','[]','再刖未甘何處說，但垂雙淚出咸秦。',64,'全唐诗/poet.tang.30000.json','["再刖未甘何處說，但垂雙淚出咸秦。", "風塵匹馬來千里，蓬梗全家望一身。", "舊隱每懷空竟夕，愁眉不展幾經春。", "今朝儻降非常顧，倒屐寧惟有古人。"]'),
('3f8d7bec-ed39-4510-b722-72bdb045268c','虢州獻楊抑卿二首 一','姚鵠','唐','唐诗','tang','','[]','蓋世英華更有誰，賦成傳寫遍坤維。',64,'全唐诗/poet.tang.30000.json','["蓋世英華更有誰，賦成傳寫遍坤維。", "名科累中求賢日，苦節高標守郡時。", "樓上呌雲秋鼓角，林間宿鶴夜旌旗。", "徵歸詔下應非久，德望人情在鳳池。"]'),
('c37df6bb-80b8-4100-96fb-bb5e97473b1d','虢州獻楊抑卿二首 二','姚鵠','唐','唐诗','tang','','[]','碧山曾共惜分陰，暗學相如賦上林。',48,'全唐诗/poet.tang.30000.json','["碧山曾共惜分陰，暗學相如賦上林。", "到此敢逾千里恨，歸家且遂十年心。", "疎愚祗怯膺門險，淺薄爭窺孔室深。"]'),
('9533027b-3b0d-43ad-adbb-d79e3d998136','贈邊將','姚鵠','唐','唐诗','tang','','[]','三邊近日往來通，盡是將軍鎮撫功。',64,'全唐诗/poet.tang.30000.json','["三邊近日往來通，盡是將軍鎮撫功。", "兵統萬人爲上將，威加千里懾西戎。", "清笳遶塞吹寒月，紅斾當山肅曉風。", "却恨北荒霑雨露，無因掃盡虜庭空。"]'),
('2b182d19-23c0-49cc-a663-14344b7e22e9','送費[鍊]師供奉赴上都','姚鵠','唐','唐诗','tang','','[]','縮地周遊不計程，古今應只有先生。',64,'全唐诗/poet.tang.30000.json','["縮地周遊不計程，古今應只有先生。", "已同化鶴臨華表，又見驂龍向玉清。", "蘿磴靜攀雲共過，雪壇當醮月孤明。", "無因相逐朝天帝，空羨煙霞得送迎。"]'),
('1f8ac12d-7aee-40e0-842b-1f37e00c53d2','和徐先輩秋日遊涇州南亭呈三二同年','姚鵠','唐','唐诗','tang','','[]','多此歡情泛鷁舟，桂枝同折塞同遊。',64,'全唐诗/poet.tang.30000.json','["多此歡情泛鷁舟，桂枝同折塞同遊。", "聲喧島上巢松鶴，影落杯中過水鷗。", "送日暮鐘交戍嶺，呌雲寒角動城樓。", "酒酣笑語秋風裏，誰道槐花更起愁。"]'),
('abd6f483-2ffd-45c3-b25a-f1f50aef5bf9','送黃頗歸袁','姚鵠','唐','唐诗','tang','','[]','莫倦連期在醉鄉，孔門多戀惜分行。',64,'全唐诗/poet.tang.30000.json','["莫倦連期在醉鄉，孔門多戀惜分行。", "文章聲價從來重，霄漢途程此去長。", "何處聽猨臨萬壑，幾宿因月滯三湘。", "鑪峰若上應相憶，不得同過惠遠房。"]'),
('613c1144-f6d1-4030-b3be-2cf0ac060ae1','和陝州參軍李通微首夏書懷呈同寮張裳段羣二先輩','姚鵠','唐','唐诗','tang','','[]','公門何事更相牽，邵伯優賢任養閑。',64,'全唐诗/poet.tang.30000.json','["公門何事更相牽，邵伯優賢任養閑。", "滿院落花從覆地，半簷初日未開關。", "尋仙鄭谷煙霞裏，避暑柯亭樹石間。", "獨爲高懷誰和繼，掾曹同處桂同攀。"]'),
('29cc3989-63f7-48c0-af2d-f1494809de6f','玉真觀尋趙尊師不遇','姚鵠','唐','唐诗','tang','','[]','羽客朝元晝掩扉，林中一徑雪中微。',64,'全唐诗/poet.tang.30000.json','["羽客朝元晝掩扉，林中一徑雪中微。", "松陰遶院鶴相對，山色滿樓人未歸。", "盡日獨思風馭返，寥天幾望野雲飛。", "凭高目斷無消息，自醉自吟愁落暉。"]'),
('3398d6f2-5628-409b-925e-d590d76ae703','及第後上主司王起','姚鵠','唐','唐诗','tang','','[]','三年竭力向春闈，塞斷浮華衆路岐。',64,'全唐诗/poet.tang.30000.json','["三年竭力向春闈，塞斷浮華衆路岐。", "盛選棟梁非昔日，平均雨露及明時。", "登龍舊美無邪徑，折桂新榮盡直枝。", "莫道只陪金馬貴，相期更在鳳皇池。"]'),
('9f70a421-963d-4afa-bb66-8760f4959ebd','送賀知章入道','姚鵠','唐','唐诗','tang','','[]','若非堯運及垂衣，肯許巢由脫俗機。',64,'全唐诗/poet.tang.30000.json','["若非堯運及垂衣，肯許巢由脫俗機。", "太液始同黃鶴下，仙鄉已駕白雲歸。", "還披舊褐辭金殿，却捧玄珠向翠微。", "羈束慙無仙藥分，隨車空有夢魂飛。"]'),
('ca79976d-55e8-40de-a56f-9e31715405bb','送友人出塞','姚鵠','唐','唐诗','tang','','[]','帝城春色著寒梅，去恨離懷醉不開。',64,'全唐诗/poet.tang.30000.json','["帝城春色著寒梅，去恨離懷醉不開。", "作別欲將何計免，此行應又隔年回。", "入河殘日鵰西盡，卷雪驚蓬馬上來。", "有思莫忘清塞學，衆傳君負佐王才。"]'),
('37ddf027-8dae-4fb9-b08b-b52c49374d70','送僧歸新羅','姚鵠','唐','唐诗','tang','','[]','淼淼萬餘里，扁舟發落暉。',72,'全唐诗/poet.tang.30000.json','["淼淼萬餘里，扁舟發落暉。", "滄溟何歲別，白首此時歸。", "寒暑途中變，人煙嶺外稀。", "驚天巨鰲鬬，蔽日大鵬飛。", "雪入行砂屨，雲生坐石衣。", "漢風深習得，休恨本心違。"]'),
('f56d7c61-30f6-408f-bb9e-16866c1b9c54','奉和秘監從翁夏日陝州河亭晚望','姚鵠','唐','唐诗','tang','','[]','洪河何處望，一境在孤煙。',72,'全唐诗/poet.tang.30000.json','["洪河何處望，一境在孤煙。", "極野如藍日，長波似鏡年。", "卷簾花影裏，倚檻鶴巢邊。", "霞焰侵旌斾，灘聲雜管弦。", "鍾微來疊岫，帆遠落遙天。", "過客多相指，應疑會水仙。"]'),
('217e20a4-f217-4632-9c40-8783c5be5eab','風不鳴條','姚鵠','唐','唐诗','tang','','[]','吾君理化清，上瑞報時平。',72,'全唐诗/poet.tang.30000.json','["吾君理化清，上瑞報時平。", "曉吹何曾歇，柔條自不鳴。", "花香知暗度，柳動覺潛生。", "只見低垂影，那聞擊觸聲。", "大王初溥暢，少女正輕盈。", "幸遇無私力，幽芳願發榮。"]'),
('b6a05d15-81fa-4e16-a387-df81a786aa4c','書情獻知己','姚鵠','唐','唐诗','tang','','[]','日日恨何窮，巴雲舊隱空。',108,'全唐诗/poet.tang.30000.json','["日日恨何窮，巴雲舊隱空。", "一爲棲寓客，二見北歸鴻。", "有道期攀桂，無門息轉蓬。", "賃居將罄比，乞食與僧同。", "花月登臨處，江山悵望中。", "衆皆輕病驥，誰肯救焦桐。", "坐惜春還至，愁吟夜每終。", "谷寒思變律，葉晚怯迴風。", "謁蔡慙王粲，憐衡冀孔融。"]'),
('3b45aa1b-9537-4358-8fa5-0b21e1845559','和工部楊尚書重送絕句','姚鵠','唐','唐诗','tang','','[]','桂枝攀得獻庭闈，何似空懷楚橘歸。',32,'全唐诗/poet.tang.30000.json','["桂枝攀得獻庭闈，何似空懷楚橘歸。", "好控扶搖早迴首，人人思看大鵬飛。"]'),
('656e060a-c7c2-478f-9feb-8a31896b2d08','寄石橋僧','項斯','唐','唐诗','tang','','[]','逢師入山日，道在石橋邊。',48,'全唐诗/poet.tang.30000.json','["逢師入山日，道在石橋邊。", "別後何人見，秋來幾處禪。", "溪中雲隔寺，夜半雪添泉。", "生有天台約，知無却出緣。"]'),
('e6f8831f-8a6e-489a-b3c5-7a47faaaa98b','送歐陽衮歸閩中','項斯','唐','唐诗','tang','','[]','秦城幾年住，猶著故鄉衣。',48,'全唐诗/poet.tang.30000.json','["秦城幾年住，猶著故鄉衣。", "失意時相識，成名後獨歸。", "海秋蠻樹黑，嶺夜瘴禽飛。", "爲學心難滿，知君更掩扉。"]'),
('c3c4668b-11ba-49d3-8500-cccc2a2f6fc1','古觀','項斯','唐','唐诗','tang','','[]','置觀碑已折，看松年不分。',48,'全唐诗/poet.tang.30000.json','["置觀碑已折，看松年不分。", "洞中誰識藥，門外日添墳。", "放去龜隨水，呼來鹿怕薰。", "壇邊見灰火，幾燒祭星文。"]'),
('3945113d-2603-4c26-8739-050a676f2868','題令狐處士谿居','項斯','唐','唐诗','tang','','[]','白髮已過半，無心離此溪。',48,'全唐诗/poet.tang.30000.json','["白髮已過半，無心離此溪。", "病嘗山藥徧，貧起草堂低。", "爲月窗從破，因詩壁重泥。", "近來常夜坐，寂莫與僧齊。"]'),
('806a80d2-a6d3-4180-bf07-e2560c3ae1b5','送僧歸南嶽','項斯','唐','唐诗','tang','','["\u8861\u5c71"]','心知衡嶽路，不怕去人稀。',48,'全唐诗/poet.tang.30000.json','["心知衡嶽路，不怕去人稀。", "船裏誰鳴磬，沙頭自曝衣。", "有家從小別，是寺即言歸。", "料得逢春住，當禪雲滿扉。"]'),
('6147f80e-6161-4a16-aa92-27210e6d856b','寧州春思','項斯','唐','唐诗','tang','','[]','失意離城早，邊城任見花。',48,'全唐诗/poet.tang.30000.json','["失意離城早，邊城任見花。", "初爲斷酒客，舊識賣書家。", "寒寺稀無雪，春風亦有沙。", "思歸頻入夢，即路不言賒。"]'),
('968139f4-44e2-401d-b6fb-198b2e829282','山友贈蘚花冠','項斯','唐','唐诗','tang','','[]','塵汙出華髮，慙君青蘚冠。',48,'全唐诗/poet.tang.30000.json','["塵汙出華髮，慙君青蘚冠。", "此身閑未得，終日戴應難。", "好就松陰挂，宜當枕石看。", "會須尋道士，簪去繞霜壇。"]'),
('4ad81bb9-42e7-4771-8c49-3be1f721acce','蠻家','項斯','唐','唐诗','tang','','[]','領得賣珠錢，還歸銅柱邊。',48,'全唐诗/poet.tang.30000.json','["領得賣珠錢，還歸銅柱邊。", "看兒調小象，打鼓試新船。", "醉後眠神樹，耕時語瘴煙。", "不逢寒便老，相問莫知年。"]'),
('43ee6f2a-01cc-44e1-a732-3a68788368bd','早春題湖上顧氏新居二首 一','項斯','唐','唐诗','tang','','[]','近得水雲看，門長侵早開。',48,'全唐诗/poet.tang.30000.json','["近得水雲看，門長侵早開。", "到時微有雪，行處又無苔。", "勸酒客初醉，留茶僧未來。", "每逢晴暖日，唯見乞花栽。"]'),
('2f0b2bf4-6e70-465f-899a-388237378795','早春題湖上顧氏新居二首 二','項斯','唐','唐诗','tang','','[]','門不當官道，行人到亦稀。',48,'全唐诗/poet.tang.30000.json','["門不當官道，行人到亦稀。", "故從餐後出，方至夜深歸。", "開篋揀書卷，掃牀移褐衣。", "幾時同買宅，相近有柴扉。"]'),
('4fe5fbba-4fe0-4e93-8151-ab491b885164','蒼梧雲氣','項斯','唐','唐诗','tang','','[]','何年化作愁，漠漠便難收。',48,'全唐诗/poet.tang.30000.json','["何年化作愁，漠漠便難收。", "數點山能遠，平鋪水不流。", "濕連湘竹暮，濃蓋舜墳秋。", "亦有思歸客，看來盡白頭。"]'),
('17299dfe-e9be-43d4-a1f8-684d03c32655','晚春花','項斯','唐','唐诗','tang','','[]','陰洞日光薄，花開不及時。',48,'全唐诗/poet.tang.30000.json','["陰洞日光薄，花開不及時。", "當春無半樹，經燒足空枝。", "疎與香風會，細將泉影移。", "此中人到少，開盡幾人知。"]'),
('0f9ac9e3-f35f-44fb-a5ba-dced5b585227','宿胡氏溪亭','項斯','唐','唐诗','tang','','[]','獨住水聲裏，有亭無熱時。',48,'全唐诗/poet.tang.30000.json','["獨住水聲裏，有亭無熱時。", "客來因月宿，牀勢向山移。", "鶴睡松枝定，螢歸葛葉垂。", "寂寥猶欠伴，誰爲報僧知。"]'),
('fc39b9dc-841f-4da9-8ba0-e6c398081166','送華陰隱者','項斯','唐','唐诗','tang','','[]','往往到城市，得非徵藥錢。',48,'全唐诗/poet.tang.30000.json','["往往到城市，得非徵藥錢。", "世人空識面，弟子莫知年。", "自說能醫死，相期更學仙。", "近來移住處，毛女舊峰前。"]'),
('c820c6a4-d11c-445d-bc22-968fb8905c74','落第後寄江南親友','項斯','唐','唐诗','tang','','[]','古巷槐陰合，愁多晝掩扉。',48,'全唐诗/poet.tang.30000.json','["古巷槐陰合，愁多晝掩扉。", "獨存過江馬，強拂看花衣。", "送客心先醉，尋僧夜不歸。", "龍鍾易惆悵，莫遣寄書稀。"]'),
('4849d122-5a12-4463-a2db-1c94f034f23f','欲別','項斯','唐','唐诗','tang','','[]','花時人欲別，每日醉櫻桃。',48,'全唐诗/poet.tang.30000.json','["花時人欲別，每日醉櫻桃。", "買酒金錢盡，彈箏玉指勞。", "歸期無歲月，客路有風濤。", "錦緞裁衣贈，麒麟落剪刀。"]'),
('ba6735c6-9657-4687-9915-4fdd497df3f2','留別張水部籍','項斯','唐','唐诗','tang','','[]','省中重拜別，兼領寄人書。',48,'全唐诗/poet.tang.30000.json','["省中重拜別，兼領寄人書。", "已念此行遠，不應相問疎。", "子城西並宅，御水北同渠。", "要取春前到，乘閑候起居。"]'),
('56cb0805-f673-4961-a7ed-e2ca4dedefc8','小古鏡','項斯','唐','唐诗','tang','','[]','字已無人識，唯應記鑄年。',48,'全唐诗/poet.tang.30000.json','["字已無人識，唯應記鑄年。", "見來深似水，攜去重於錢。", "鸞翅巢空月，菱花徧小天。", "宮中照黃帝，曾得化爲仙。"]'),
('97efefd9-0a91-4d13-9fd8-8910edf544fd','題太白山隱者','項斯','唐','唐诗','tang','','[]','高居在幽嶺，人得見時稀。',48,'全唐诗/poet.tang.30000.json','["高居在幽嶺，人得見時稀。", "寫籙扃虛白，尋僧到翠微。", "掃壇星下宿，收藥雨中歸。", "從服小還後，自疑身解飛。"]'),
('f10abbf2-121a-4f19-9997-ede071aa3c04','病中懷王展先輩在天台','項斯','唐','唐诗','tang','','[]','枕上用心靜，唯應改舊詩。',48,'全唐诗/poet.tang.30000.json','["枕上用心靜，唯應改舊詩。", "強行休去早，暫臥起還遲。", "因說來歸處，却愁初病時。", "赤城山下寺，無計得相隨。"]'),
('925eb6e7-50a8-4683-8f76-155d993df2a2','鯉魚','項斯','唐','唐诗','tang','','[]','似龍鱗又足，只是欠登門。',48,'全唐诗/poet.tang.30000.json','["似龍鱗又足，只是欠登門。", "月裏腮猶濕，泥中目未昏。", "乞鋤防蟻穴，望水寫金盆。", "他日能爲雨，公田報此恩。"]'),
('cd2a40ff-c1c2-47e8-9d2c-91e3a50fd579','子規','項斯','唐','唐诗','tang','','[]','遊魂自相叫，寧復記前身。',48,'全唐诗/poet.tang.30000.json','["遊魂自相叫，寧復記前身。", "飛過人家月，聲連客路春。", "夢邊催曉急，愁外送風頻。", "自有霑花血，相和淚滴新。"]'),
('1d7ebb74-8bcf-4235-8215-e93ad75a9a85','邊州客舍','項斯','唐','唐诗','tang','','[]','開門不成出，麥色徧前坡。',48,'全唐诗/poet.tang.30000.json','["開門不成出，麥色徧前坡。", "自小詩名在，如今白髮多。", "經年無越信，終日厭蕃歌。", "近寺居僧少，春來亦嬾過。"]'),
('1f3c63ce-c129-4339-b35b-9f58b7f68b8c','贈道者','項斯','唐','唐诗','tang','','[]','晏來知養氣，度日語時稀。',48,'全唐诗/poet.tang.30000.json','["晏來知養氣，度日語時稀。", "到處留丹井，終寒不絮衣。", "病鄉多惠藥，鬼俗有符威。", "自說身輕健，今年數夢飛。"]'),
('22b58924-a27b-449a-b0fd-9f224646c2e5','邊游','項斯','唐','唐诗','tang','','[]','古鎮門前去，長安路在東。',48,'全唐诗/poet.tang.30000.json','["古鎮門前去，長安路在東。", "天寒明堠火，日晚裂旗風。", "塞館皆無事，儒裝亦有弓。", "防秋故鄉卒，暫喜語音同。"]'),
('a33fa5fe-7bf9-45dd-95a9-9fcc4b795901','夜泊淮陰','項斯','唐','唐诗','tang','','[]','夜入楚家煙，煙中人未眠。',48,'全唐诗/poet.tang.30000.json','["夜入楚家煙，煙中人未眠。", "望來淮岸盡，坐到酒樓前。", "燈影半臨水，箏聲多在船。", "乘流向東去，別此易經年。"]'),
('8770c779-b6e0-48fe-9e82-3f65d75941a5','遠水','項斯','唐','唐诗','tang','','[]','渺渺浸天色，一邊生晚光。',48,'全唐诗/poet.tang.30000.json','["渺渺浸天色，一邊生晚光。", "闊浮萍思遠，寒入鴈愁長。", "北極連平地，東流即故鄉。", "扁舟來宿處，髣髴似瀟湘。"]'),
('26955633-a9af-48c8-81ce-12bf7f5848cb','黃州暮愁','項斯','唐','唐诗','tang','','[]','凌澌衝淚眼，重疊自西來。',48,'全唐诗/poet.tang.30000.json','["凌澌衝淚眼，重疊自西來。", "即夜寒應合，非春暖不開。", "豈無登陸計，宜棄濟川材。", "願寄浮天外，高風萬里回。"]'),
('6bc63d2f-5dff-4407-be6b-747a651c4505','曉發昭應','項斯','唐','唐诗','tang','','[]','行人見雪愁，初作帝鄉游。',48,'全唐诗/poet.tang.30000.json','["行人見雪愁，初作帝鄉游。", "旅店開偏早，鄉帆去未收。", "燈殘催卷席，手冷怕梳頭。", "是物寒無色，湯泉正自流。"]'),
('8c4607a7-ce8d-49e6-a479-d76ad43ee0db','贈金州姚合使君','項斯','唐','唐诗','tang','','[]','爲郎名更重，領郡是蹉跎。',48,'全唐诗/poet.tang.30000.json','["爲郎名更重，領郡是蹉跎。", "官壁題詩盡，衙庭看鶴多。", "城池連草塹，籬落帶椒坡。", "未覺旗旛貴，閑行觸處過。"]'),
('1a7882ad-97b2-4e10-9380-f4b9631c313b','送殷中丞遊邊','項斯','唐','唐诗','tang','','[]','話別無長夜，燈前聞曙鵶。',48,'全唐诗/poet.tang.30000.json','["話別無長夜，燈前聞曙鵶。", "已行難避雪，何處合逢花？", "野寺門多閉，羌樓酒不賒。", "還須見邊將，誰擬靜塵沙。"]'),
('cb3a1fbf-4d7c-4d65-9c10-b3d8096f7fc7','寄坐夏僧','項斯','唐','唐诗','tang','','[]','坐夏日偏長，知師在律堂。',48,'全唐诗/poet.tang.30000.json','["坐夏日偏長，知師在律堂。", "多因束帶熱，更憶剃頭涼。", "苔色侵經架，松陰到簟牀。", "還應鍊詩句，借臥石池傍。"]'),
('78c85b2e-80de-4b1f-957d-7d36d726e2c8','寄盧式','項斯','唐','唐诗','tang','','[]','到處久南望，未知何日回。',48,'全唐诗/poet.tang.30000.json','["到處久南望，未知何日回。", "寄書頻到海，得夢忽聞雷。", "嶺日當秋暗，蠻花近臘開。", "白身居瘴癘，誰不惜君才。"]'),
('bf4d1d67-24f7-4e25-8672-5bb1ad607810','日東病僧','項斯','唐','唐诗','tang','','[]','雲水絕歸路，來時風送船。',48,'全唐诗/poet.tang.30000.json','["雲水絕歸路，來時風送船。", "不言身後事，猶坐病中禪。", "深壁藏燈影，空窗出艾煙。", "已無鄉土信，起塔寺門前。"]'),
('55c6730d-21b4-4081-94ce-4db0ed748fa0','泛溪','項斯','唐','唐诗','tang','','[]','溪船泛渺瀰，漸覺滅炎輝。',48,'全唐诗/poet.tang.30000.json','["溪船泛渺瀰，漸覺滅炎輝。", "動水花連影，逢人鳥背飛。", "深猶見白石，涼好換生衣。", "未得多詩句，終須隔宿歸。"]'),
('6b52e5f8-5d28-4e1d-9314-1af0b70b9cf5','送顧少府','項斯','唐','唐诗','tang','','[]','作尉年猶少，無辭去路賒。',48,'全唐诗/poet.tang.30000.json','["作尉年猶少，無辭去路賒。", "漁舟縣前泊，山吏日高衙。", "幽景臨谿寺，秋蟬織杼家。", "行程須過越，先醉鏡湖花。"]'),
('1114d88a-b837-45cc-a628-dcc193976081','咸陽別李處士','項斯','唐','唐诗','tang','','[]','古道自迢迢，咸陽離別橋。',48,'全唐诗/poet.tang.30000.json','["古道自迢迢，咸陽離別橋。", "越人聞水處，秦樹帶霜朝。", "駐馬言難盡，分程望易遙。", "秋前未相見，此意轉蕭條。"]'),
('2385716b-4311-4a91-98f8-2c1cc51f99d7','寄流人','項斯','唐','唐诗','tang','','[]','毒草不曾枯，長添客健無。',48,'全唐诗/poet.tang.30000.json','["毒草不曾枯，長添客健無。", "霧開蠻市合，船散海城孤。", "象跡頻藏齒，龍涎遠蔽珠。", "家人秦地老，泣對日南圖。"]'),
('507228b0-2eb8-475a-afa7-5bbc1dbcda4b','華頂道者','項斯','唐','唐诗','tang','','[]','仙人掌中住，生有上天期。',48,'全唐诗/poet.tang.30000.json','["仙人掌中住，生有上天期。", "已廢燒丹處，猶多種杏時。", "養龍於淺水，寄鶴在高枝。", "得道復無事，相逢盡日棊。"]'),
('bfc964a8-833a-4adf-9adf-d985da800e8c','酬從叔聽夜泉見寄','項斯','唐','唐诗','tang','','[]','夢罷更開戶，寒泉聲隔雲。',48,'全唐诗/poet.tang.30000.json','["夢罷更開戶，寒泉聲隔雲。", "共誰尋最遠，獨自坐偏聞。", "巖際和風滴，溪中泛月分。", "豈知當此夜，流念到江濆。"]'),
('5510573a-ce2d-4938-ae21-bb674098d3d5','和李用夫栽小松','項斯','唐','唐诗','tang','','[]','移來未換葉，已勝在空山。',48,'全唐诗/poet.tang.30000.json','["移來未換葉，已勝在空山。", "靜對心標直，遙吟境助閑。", "影侵殘雪際，聲透小窗間。", "即聳凌空幹，翛翛豈易攀。"]'),
('8b52cce3-491c-4aa1-9cd4-0b1792cbc08f','哭南流人','項斯','唐','唐诗','tang','','[]','遙見南來使，江頭哭問君。',48,'全唐诗/poet.tang.30000.json','["遙見南來使，江頭哭問君。", "臨終時有雪，旅葬處無雲。", "官庫空收劒，蠻僧共起墳。", "知名人尚少，誰爲錄遺文。"]'),
('d9e23fe8-91c1-46fa-9d60-38262377c348','經李白墓','項斯','唐','唐诗','tang','','[]','夜郎歸未老，醉死此江邊。',48,'全唐诗/poet.tang.30000.json','["夜郎歸未老，醉死此江邊。", "葬闕官家禮，詩殘樂府篇。", "遊魂應到蜀，小碣豈旌賢。", "身沒猶何罪，遺墳野火燃。"]'),
('91948ae7-8f38-4502-aef0-c2ff582c1307','春夜樊川竹亭陪諸同年讌','項斯','唐','唐诗','tang','','[]','相知皆是舊，每恨獨遊頻。',48,'全唐诗/poet.tang.30000.json','["相知皆是舊，每恨獨遊頻。", "幸此同芳夕，寧辭倒醉身。", "燈光遙映燭，萼粉暗飄茵。", "明月分歸騎，重來更幾春。"]'),
('a4b4f310-d1bb-4568-a9f4-d2ae3a72bb97','送僧','項斯','唐','唐诗','tang','','[]','靈山巡未徧，不作住持心。',48,'全唐诗/poet.tang.30000.json','["靈山巡未徧，不作住持心。", "逢寺暫投宿，是山皆獨尋。", "有時過靜界，在處想空林。", "從小即行脚，出家來至今。"]'),
('c309771b-e84b-4edf-b949-00a2acd530a2','送蘇處士歸西山','項斯','唐','唐诗','tang','','[]','南遊何所爲，一篋又空歸。',48,'全唐诗/poet.tang.30000.json','["南遊何所爲，一篋又空歸。", "守道安清世，無心換白衣。", "深林蟬噪暮，絕頂客來稀。", "早晚重相見，論持更及微。"]'),
('ea3b873e-061f-4ed3-877a-8a6f6e743c04','遊爛柯山','項斯','唐','唐诗','tang','','[]','步步出塵氛，溪山別是春。',48,'全唐诗/poet.tang.30000.json','["步步出塵氛，溪山別是春。", "壇邊時過鶴，碁處寂無人。", "訪古碑多缺，探幽路不真。", "翻疑歸去晚，清世累移晨。"]'),
('12396b57-e35d-4e9f-bff4-5e36bf5579af','送友人之永嘉','項斯','唐','唐诗','tang','','[]','長貧知不易，去計擬何逃。',48,'全唐诗/poet.tang.30000.json','["長貧知不易，去計擬何逃。", "相對人愁別，經過幾處勞。", "城連沙岫遠，山斷夏雲高。", "猶想成詩處，秋燈半照濤。"]'),
('299e6f45-a91e-4790-ad6c-5472640d6f40','巴中逢故人','項斯','唐','唐诗','tang','','[]','勞思空積歲，偶會更無由。',48,'全唐诗/poet.tang.30000.json','["勞思空積歲，偶會更無由。", "以分難相捨，將行且暫留。", "路歧何處極，江峽半猨愁。", "到此分南北，離懷豈易收。"]'),
('502399a1-79a3-4cda-9482-ac4052479b0c','送歸江州友人初下第','項斯','唐','唐诗','tang','','[]','名高不俟召，收採獻君門。',48,'全唐诗/poet.tang.30000.json','["名高不俟召，收採獻君門。", "偶屈應緣數，他人盡爲冤。", "新春城外路，舊隱水邊村。", "歸去無勞久，知君更待論。"]'),
('4f2af79e-69f3-4aa9-8857-9f25d75d8517','舜城懷古','項斯','唐','唐诗','tang','','[]','禪禹遜堯聰，巍巍盛此中。',48,'全唐诗/poet.tang.30000.json','["禪禹遜堯聰，巍巍盛此中。", "四隅咸啓聖，萬古賴成功。", "道德去彌遠，山河勢不窮。", "停車一再拜，帝業即今同。"]'),
('5b4779dc-84b7-41d9-80b9-f7fd0393594f','送劉道士之成都嚴真觀','項斯','唐','唐诗','tang','','[]','嚴君名不朽，道出二經中。',48,'全唐诗/poet.tang.30000.json','["嚴君名不朽，道出二經中。", "歸去精誠懇，還應夢寐通。", "池臺鏡定月，松檜雨餘風。", "想對靈玄憶，人間戀若空。"]'),
('2efaf05d-7f64-478a-9f78-788ce38571be','漢南遇友人','項斯','唐','唐诗','tang','','[]','此身西復東，何計此相逢。',48,'全唐诗/poet.tang.30000.json','["此身西復東，何計此相逢。", "夢盡吳越水，恨深襄漢鐘。", "積雲開去路，曙雪疊前峰。", "誰即知非舊，憐君忽見容。"]'),
('861662ba-6bea-4ab0-aee0-c3fc5b7ffa87','遊頭陀寺上方','項斯','唐','唐诗','tang','','[]','高步陟崔嵬，吟閑路惜迴。',48,'全唐诗/poet.tang.30000.json','["高步陟崔嵬，吟閑路惜迴。", "寺知何代有，僧見梵天來。", "暮靄連沙積，餘霞徧檻開。", "更期招靜者，長嘯上南臺。"]'),
('64072fd7-4160-4f35-ae20-bb2feafab57d','送友人遊河東','項斯','唐','唐诗','tang','','[]','停車曉燭前，一語幾潸然。',48,'全唐诗/poet.tang.30000.json','["停車曉燭前，一語幾潸然。", "路去干戈日，鄉遙饑饉年。", "湖波晴見鴈，槐驛晚無蟬。", "莫縱經時住，東南書信偏。"]'),
('6b16e389-f436-4b74-9de0-fd935f949050','中秋夜懷','項斯','唐','唐诗','tang','','[]','趨馳早晚休，一歲又殘秋。',48,'全唐诗/poet.tang.30000.json','["趨馳早晚休，一歲又殘秋。", "若只如今日，何難至白頭。", "滄波歸處遠，旅食尚邊愁。", "賴見前賢說，窮通不自由。"]'),
('601ffbb9-84ed-43a8-8032-2defdabdf700','寄富春孫路處士','項斯','唐','唐诗','tang','','[]','平生醉與吟，誰是見君心。',48,'全唐诗/poet.tang.30000.json','["平生醉與吟，誰是見君心。", "上國一歸去，滄江閑至今。", "鐘繁秋寺近，峰闊晚濤深。", "疎放長如此，何人長得尋。"]'),
('902a9264-d23b-412d-83a9-704718ac5bf5','送客歸新羅','項斯','唐','唐诗','tang','','[]','君家滄海外，一別見何因。',48,'全唐诗/poet.tang.30000.json','["君家滄海外，一別見何因。", "風土雖知敎，程途自致貧。", "浸天波色晚，橫笛鳥行春。", "明發千檣下，應無更遠人。"]'),
('c54aeaa6-1efe-466c-ab63-67ac67c0dcb5','杭州江亭留題登眺','項斯','唐','唐诗','tang','','[]','處處日馳銷，憑軒夕似朝。',48,'全唐诗/poet.tang.30000.json','["處處日馳銷，憑軒夕似朝。", "漁翁閑鼓櫂，沙鳥戲迎潮。", "樹間津亭密，城連塢寺遙。", "因誰報隱者，向此得耕樵。"]'),
('f6bf1111-0b2a-4a7e-b77a-703fcce54421','荆州夜與友親相遇','項斯','唐','唐诗','tang','','[]','山海兩分歧，停舟偶似期。',48,'全唐诗/poet.tang.30000.json','["山海兩分歧，停舟偶似期。", "別來何限意，相見却無辭。", "坐永神凝夢，愁繁鬢欲絲。", "趨名易遲晚，此去莫經時。"]'),
('1af79ba0-43f1-4521-b2ef-c0255a662a60','送友人遊邊','項斯','唐','唐诗','tang','','[]','方春到帝京，有戀有愁幷。',48,'全唐诗/poet.tang.30000.json','["方春到帝京，有戀有愁幷。", "萬里江海思，半年沙塞程。", "綠陰斜向驛，殘照遠侵城。", "自可資新課，還期振盛名。"]'),
('bb044b6c-7e78-4f73-a96d-b48dc1e88180','題贈宣州亢拾遺','項斯','唐','唐诗','tang','','[]','傳騎一何催，山門晝未開。',48,'全唐诗/poet.tang.30000.json','["傳騎一何催，山門晝未開。", "高人終避世，聖主不遺才。", "坐次欹臨水，門中獨舉杯。", "誰爲旦夕侶，深寺數僧來。"]'),
('bcb47d2a-a2ef-4d05-86af-411062a64ce3','姚氏池亭','項斯','唐','唐诗','tang','','[]','池館饒嘉致，幽人愜所閑。',48,'全唐诗/poet.tang.30000.json','["池館饒嘉致，幽人愜所閑。", "篠風能動浪，岸樹不遮山。", "嘯檻魚驚後，眠窗鶴語間。", "何須說廬阜，深處更躋攀。"]'),
('3e6cbfa8-7b51-4e99-b66a-1a4c22ad1905','送友人之江南','項斯','唐','唐诗','tang','','[]','東南路苦辛，去路見無因。',48,'全唐诗/poet.tang.30000.json','["東南路苦辛，去路見無因。", "萬里此相送，故交誰更親。", "日浮汀草綠，煙霽海山春。", "握手無別贈，爲予書札頻。"]'),
('bf25dbb3-393f-4e20-b695-2b84739ebcc6','彭蠡湖春望','項斯','唐','唐诗','tang','','[]','湖亭東極望，遠棹不須迴。',48,'全唐诗/poet.tang.30000.json','["湖亭東極望，遠棹不須迴。", "遍草新湖落，連天衆鴈來。", "蘆洲殘照盡，雲障積煙開。", "更想鴟夷子，扁舟安在哉。"]'),
('235f0368-5280-4c62-b023-2fbf34feb7ff','聞友人會裴明府縣樓','項斯','唐','唐诗','tang','','[]','閑閣雨吹塵，陶家揖上賓。',48,'全唐诗/poet.tang.30000.json','["閑閣雨吹塵，陶家揖上賓。", "湖山萬疊翠，門樹一行春。", "景遍歸簷燕，歌喧已醉身。", "登臨興不足，喜有數來因。"]'),
('390721dd-7011-48fd-872b-0ba53414ea40','歸家山行','項斯','唐','唐诗','tang','','[]','獻賦才何拙，經時不恥歸。',48,'全唐诗/poet.tang.30000.json','["獻賦才何拙，經時不恥歸。", "能知此意是，甘取衆人非。", "遍隴耕無圃，緣溪釣有磯。", "此懷難自遣，期在振儒衣。"]'),
('1a8aa741-f668-4ba0-93c9-72834ac716e7','長安書懷呈知己','項斯','唐','唐诗','tang','','[]','江湖歸不易，京邑計長貧。',48,'全唐诗/poet.tang.30000.json','["江湖歸不易，京邑計長貧。", "獨夜有知己，論心無故人。", "一燈愁裏夢，九陌病中春。", "爲問清平日，無門致出身。"]'),
('83de3039-2230-419f-94dc-45877f46bbe0','聞蟬','項斯','唐','唐诗','tang','','[]','動葉復驚神，聲聲斷續勻。',48,'全唐诗/poet.tang.30000.json','["動葉復驚神，聲聲斷續勻。", "坐來同聽者，俱是未歸人。", "一櫂三湘浪，單車二蜀塵。", "傷秋各有日，千可念因循。"]'),
('50068d17-bdbe-4786-9aca-0f49e6128ea3','李處土道院南樓','項斯','唐','唐诗','tang','','[]','霜晚復秋殘，樓明近遠山。',48,'全唐诗/poet.tang.30000.json','["霜晚復秋殘，樓明近遠山。", "滿壺邀我醉，一榻爲僧閑。", "樹簇孤汀眇，帆欹積浪間。", "從容更南望，殊欲外人寰。"]'),
('a2bf1b0d-2d78-48d2-a559-c06af9290677','送顧非熊及第歸茅山','項斯','唐','唐诗','tang','','[]','吟詩三十載，成此一名難。',48,'全唐诗/poet.tang.30000.json','["吟詩三十載，成此一名難。", "自有恩門入，全無帝里歡。", "湖光愁裏碧，巖景夢中寒。", "到後松杉月，何人共曉看。"]'),
('442bbfd9-4716-4663-a397-c07d46173ad5','春日題李中丞樊川別墅','項斯','唐','唐诗','tang','','[]','心知受恩地，到此亦裴回。',48,'全唐诗/poet.tang.30000.json','["心知受恩地，到此亦裴回。", "上路移時立，中軒隔宿來。", "川光通沼沚，寺影帶樓臺。", "無限成蹊樹，花多向客開。"]'),
('5b5cfac6-11fb-48b4-b305-2829e2e13b07','龍州與韓將軍夜會','項斯','唐','唐诗','tang','','[]','庭綠草纖纖，邊州白露沾。',48,'全唐诗/poet.tang.30000.json','["庭綠草纖纖，邊州白露沾。", "別歌緣劒起，客淚是愁添。", "見月鵲啼樹，避風雲滿簾。", "將軍盡尊酒，樓上賦星占。"]'),
('090be84b-e0a2-4df5-9e93-8e4c57a5cec0','途中逢友人','項斯','唐','唐诗','tang','','[]','長大有南北，山川各所之。',48,'全唐诗/poet.tang.30000.json','["長大有南北，山川各所之。", "相逢孤館夜，共憶少年時。", "爛醉百花酒，狂題幾首詩。", "來朝又分袂，後會鬢應絲。"]'),
('1683147a-c311-4559-a028-df40e7550af7','送友人下第歸襄陽','項斯','唐','唐诗','tang','','[]','失意已春殘，歸愁與別難。',48,'全唐诗/poet.tang.30000.json','["失意已春殘，歸愁與別難。", "山分關路細，江遶夜城寒。", "草色連晴坂，鼉聲離曉灘。", "差池是秋賦，何以暫懷安。"]'),
('ff397716-b8c2-403f-b5a7-35986d16c06f','宿山寺','項斯','唐','唐诗','tang','','[]','栗葉重重覆翠微，黃昏溪上語人稀。',64,'全唐诗/poet.tang.30000.json','["栗葉重重覆翠微，黃昏溪上語人稀。", "月明古寺客初到，風度閑門僧未歸。", "山果經霜多自落，水螢穿竹不停飛。", "中宵能得幾時睡，又被鐘聲催著衣。"]'),
('dfa36a1b-f03c-4ee0-a259-8c349ae36f45','病鶴','項斯','唐','唐诗','tang','','[]','青雲有意力猶微，豈料低回得所依。',64,'全唐诗/poet.tang.30000.json','["青雲有意力猶微，豈料低回得所依。", "幸念翅因風雨困，豈敎身陷稻粱肥。", "曾遊碧落寧無侶，見有清池不忍飛。", "縱使他年引仙駕，主人恩在亦應歸。"]'),
('732bc4e3-3bdd-4938-b47a-d2483bb266de','夢仙','項斯','唐','唐诗','tang','','[]','昨宵魂夢到仙津，得見蓬山不死人。',64,'全唐诗/poet.tang.30000.json','["昨宵魂夢到仙津，得見蓬山不死人。", "雲葉許裁成野服，玉漿敎喫潤愁身。", "紅樓近月宜寒水，綠杏搖風占古春。", "次第引看行未徧，浮光牽入世間塵。"]'),
('94f889e1-3648-4911-aadf-44158e6b2469','古扇','項斯','唐','唐诗','tang','','[]','昨日裁成奪夏威，忽逢秋節便相違。',64,'全唐诗/poet.tang.30000.json','["昨日裁成奪夏威，忽逢秋節便相違。", "寒塵妬盡秦王女，涼殿恩隨漢主妃。", "似月舊臨紅粉面，有風休動麝香衣。", "千年蕭瑟關人事，莫語當時掩淚歸。"]'),
('64de9e1f-855a-4c5d-a8f2-867ed06a0f64','涇州聽張處士彈琴','項斯','唐','唐诗','tang','','[]','邊州獨夜正思鄉，君又彈琴在客堂。',32,'全唐诗/poet.tang.30000.json','["邊州獨夜正思鄉，君又彈琴在客堂。", "髣髴不離燈影外，似聞流水到瀟湘。"]'),
('0d9821bf-f1e8-4952-92db-4eefbbc51d37','贈別','項斯','唐','唐诗','tang','','[]','魚在深泉鳥在雲，從來只得影相親。',32,'全唐诗/poet.tang.30000.json','["魚在深泉鳥在雲，從來只得影相親。", "他時縱有逢君處，應作人間白髮身。"]'),
('cd40b0e7-0e87-47d4-b49b-3869f1b04050','對鱠','項斯','唐','唐诗','tang','','[]','行到鱸魚鄉裏時，鱠盤如雪怕風吹。',32,'全唐诗/poet.tang.30000.json','["行到鱸魚鄉裏時，鱠盤如雪怕風吹。", "猶憐醉裏江南路，馬上垂鞭學釣時。"]'),
('bd11ab77-cdc3-45f4-9cf9-767ea00098d3','憶朝陽峰前居','項斯','唐','唐诗','tang','','[]','每憶閑眠處，朝陽最上峰。',96,'全唐诗/poet.tang.30000.json','["每憶閑眠處，朝陽最上峰。", "溪僧來自遠，林路出無蹤。", "敗褐黏苔徧，新題出石重。", "霞光侵曙發，嵐翠近秋濃。", "健羨機能破，安危道不逢。", "雪殘猨到閣，庭午鶴離松。", "此地虛爲別，人間久未容。", "何時無一事，却去養疎慵。"]'),
('4042129d-6751-457e-9daf-d4622425ec33','暮上瞿唐峽','項斯','唐','唐诗','tang','','[]','自古艱難地，孤舟旦暮程。',72,'全唐诗/poet.tang.30000.json','["自古艱難地，孤舟旦暮程。", "獨愁空託命，省已是輕生。", "有樹皆相倚，無巖不倒傾。", "蛟螭波數怒，鬼怪火潛明。", "履道知無負，離心自要驚。", "何年面骨肉，細話苦辛行。"]'),
('04732e49-34a7-4aaa-bff2-28fd510611d4','和李中丞醉中期王徵君月夜同遊滻水舊居','項斯','唐','唐诗','tang','','[]','醉後情俱遠，難忘素滻間。',48,'全唐诗/poet.tang.30000.json','["醉後情俱遠，難忘素滻間。", "照花深處月，當戶舊時山。", "事想同清話，歡期一破顏。", "風流還愛竹，此夜尚思閑。"]'),
('f6a6ca28-f855-499d-a11d-1dc886025960','濁水求珠','項斯','唐','唐诗','tang','','[]','靈魄自沉浮，從來任濁流。',72,'全唐诗/poet.tang.30000.json','["靈魄自沉浮，從來任濁流。", "願從深處得，不向暗中投。", "圓月時堪惜，滄波路可求。", "沙尋龍窟遠，泥訪蚌津幽。", "是寶終知貴，唯恩且用酬。", "如能在公掌，的不負明眸。"]'),
('f04c401f-69e1-476d-9e0c-c1d43e32c830','江村夜泊','項斯','唐','唐诗','tang','','[]','日落江路黑，前村人語稀。',24,'全唐诗/poet.tang.30000.json','["日落江路黑，前村人語稀。", "幾家深樹裏，一火夜漁歸。"]'),
('c0e21be8-7f59-4b62-a6bd-9d3bace83510','落第後歸覲喜逢僧再陽','項斯','唐','唐诗','tang','','[]','相逢須強笑，人世別離頻。',96,'全唐诗/poet.tang.30000.json','["相逢須強笑，人世別離頻。", "去曉長侵月，歸鄉動隔春。", "見僧心暫靜，從俗事多屯。", "宇宙詩名小，山河客路新。", "翠桐猶入爨，青鏡未辭塵。", "逸足常思驥，隨羣且退鱗。", "宴乖紅杏寺，愁在綠楊津。", "羞病難爲藥，開眉嬾顧人。"]'),
('f9ff3802-4992-441c-9cff-96cebd964b09','送越僧元瑞','項斯','唐','唐诗','tang','','[]','靜中無伴侶，今亦獨隨緣。',24,'全唐诗/poet.tang.30000.json','["靜中無伴侶，今亦獨隨緣。", "昨夜離空室，焚香淨去船。"]'),
('3a8de168-6e01-4b32-b467-7cf2dfc6eea1','舊宮人','項斯','唐','唐诗','tang','','[]','自出先皇玉殿中，衣裳不更染深紅。',64,'全唐诗/poet.tang.30000.json','["自出先皇玉殿中，衣裳不更染深紅。", "宮釵折盡垂空鬢，內扇穿多減半風。", "桃熟亦曾君手賜，酒闌猶候妾歌終。", "如今還向城邊住，御水東流意不通。"]'),
('640ea6c7-e3ad-49b0-90d0-2fb02ab5f3b7','夢游仙','項斯','唐','唐诗','tang','','[]','夢遊飛上天家樓，珠箔當風挂玉鉤。',64,'全唐诗/poet.tang.30000.json','["夢遊飛上天家樓，珠箔當風挂玉鉤。", "鸚鵡隔簾呼再拜，水仙移鏡嬾梳頭。", "丹霞不是人間曉，碧樹仍逢岫外秋。", "將謂便長於此地，雞聲入耳所堪愁。"]'),
('cce85db9-5233-452c-a542-cb2dfe3b4187','送宮人入道','項斯','唐','唐诗','tang','','[]','願隨仙女董雙成，王母前頭作伴行。',64,'全唐诗/poet.tang.30000.json','["願隨仙女董雙成，王母前頭作伴行。", "初戴玉冠多悞拜，欲辭金殿別稱名。", "將敲碧落新齋磬，却進昭陽舊賜箏。", "旦暮焚香繞壇上，步虛猶作按歌聲。"]'),
('e29cad57-2131-4c70-a665-685a81ce8286','長安退將','項斯','唐','唐诗','tang','','[]','塞外衝沙損眼明，歸來養病住秦京。',64,'全唐诗/poet.tang.30000.json','["塞外衝沙損眼明，歸來養病住秦京。", "上高樓閣看星坐，著白衣裳把劒行。", "常說老身思鬬將，最悲無力制蕃營。", "翠眉紅臉和回鶻，惆悵中原不用兵。"]'),
('8e5b350a-6de2-446f-ae56-942b9ab97465','遙裝夜','項斯','唐','唐诗','tang','','[]','卷席貧拋壁下牀，且鋪他處對燈光。',64,'全唐诗/poet.tang.30000.json','["卷席貧拋壁下牀，且鋪他處對燈光。", "欲行千里從今夜，猶惜殘春發故鄉。", "蚊蚋已生團扇急，衣裳未了剪刀忙。", "誰知更有芙蓉浦，南去令人愁思長。"]'),
('835f8cf3-a6c4-42d1-aa06-84ca834bed4a','送苗七求職','項斯','唐','唐诗','tang','','[]','相逢未得三回笑，風送離情入剪刀。',64,'全唐诗/poet.tang.30000.json','["相逢未得三回笑，風送離情入剪刀。", "客路最能銷日月，夢魂空自畏波濤。", "獨眠秋夜琴聲急，未拜軍城劒色高。", "去去緣多山與海，鶴身寧肯爲飛勞。"]'),
('ae971825-5e3c-4e3a-b9a7-01df4ab7dd31','山行','項斯','唐','唐诗','tang','','["\u5c71\u6c34", "\u5199\u666f", "\u6292\u60c5", "\u7530\u56ed"]','青櫪林深亦有人，一渠流水數家分。',64,'全唐诗/poet.tang.30000.json','["青櫪林深亦有人，一渠流水數家分。", "山當日午回峰影，草帶泥痕過鹿羣。", "蒸茗氣從茅舍出，繰絲聲隔竹籬聞。", "行逢賣藥歸來客，不惜相隨入島雲。"]'),
('3eccfe47-1fb9-4e1f-9040-826c26c57a11','題永忻寺影堂','項斯','唐','唐诗','tang','','[]','不遇修寺日，無錢入影堂。',48,'全唐诗/poet.tang.30000.json','["不遇修寺日，無錢入影堂。", "故來空禮拜，臨去重添香。", "僧得名難近，燈傳火已長。", "發心依止後，借住有鄰房。"]'),
('5b6adf15-e83c-419f-85ae-0a274d353d00','獻令狐相公時相公郊壇行事回','項斯','唐','唐诗','tang','','[]','鶚在卿雲冰在壺，代天才業本訏謨。',64,'全唐诗/poet.tang.30000.json','["鶚在卿雲冰在壺，代天才業本訏謨。", "榮同伊陟傳朱戶，秀比王商入畫圖。", "昨夜星辰回劒履，前年風月滿江湖。", "不知機務時多暇，還許詩家屬和無。"]'),
('21e07a5b-1b22-40f9-9594-5dedd335bc3f','句','項斯','唐','唐诗','tang','','[]','佳人背江坐，眉際列煙樹。',52,'全唐诗/poet.tang.30000.json','["佳人背江坐，眉際列煙樹。", "馬蹄沒青莎，船跡成空波。", "春風吹兩意，何意更相值。", "更望會稽何處是，沙連竹箭白鷴羣。"]'),
('c2f5bd6f-76a1-4d3f-b5d7-81d81b6c6190','校獵曲','馬戴','唐','唐诗','tang','','[]','楚子畋郊野，布罟籠天涯。',72,'全唐诗/poet.tang.30000.json','["楚子畋郊野，布罟籠天涯。", "浮雲張作羅，萬草結成罝。", "意在絕飛鳥，臂弓腰鏌鎁。", "遠將射句踐，次欲誅夫差。", "壯志一朝盡，他□□繁華。", "當時能獵賢，保國兼保家。"]'),
('d53571e8-f7e5-4870-9d07-90948ff0eb0b','蠻家','馬戴','唐','唐诗','tang','','[]','領得賣珠錢，還歸銅柱邊。',48,'全唐诗/poet.tang.30000.json','["領得賣珠錢，還歸銅柱邊。", "看兒調小象，打鼓放新船。", "醉後眠神樹，耕時語瘴煙。", "又逢衰蹇老，相問莫知年。"]'),
('0acb3a7b-8835-4ab5-bdfd-00eae745a8b7','春思','馬戴','唐','唐诗','tang','','[]','初日照楊柳，玉樓含翠陰。',48,'全唐诗/poet.tang.30000.json','["初日照楊柳，玉樓含翠陰。", "啼春獨鳥思，望遠佳人心。", "幽怨貯瑤瑟，韶光凝碧林。", "所思曾不見，芳草意空深。"]'),
('453d179f-84bc-4fa6-af4a-e6f9e52fff4b','送從叔赴南海幕','馬戴','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭秋色起，哀狖更難聞。',48,'全唐诗/poet.tang.30000.json','["洞庭秋色起，哀狖更難聞。", "身往海邊郡，帆懸天際雲。", "炎州羅翠鳥，瘴嶺控蠻軍。", "信息來非易，堪悲此路分。"]'),
('b47a6094-5e94-4794-b15f-32f21f51a47d','江行留別','馬戴','唐','唐诗','tang','','[]','吳楚半秋色，渡江逢葦花。',48,'全唐诗/poet.tang.30000.json','["吳楚半秋色，渡江逢葦花。", "雲侵帆影盡，風逼雁行斜。", "返照開嵐翠，寒潮蕩浦沙。", "余將何所往，海嶠擬營家。"]'),
('dc7ad1fe-4b03-4e4a-8b03-c1ae0841c11b','將別寄友人','馬戴','唐','唐诗','tang','','[]','帝鄉歸未得，辛苦事羇遊。',48,'全唐诗/poet.tang.30000.json','["帝鄉歸未得，辛苦事羇遊。", "別館一尊酒，客程千里秋。", "霜風紅葉寺，夜雨白蘋洲。", "長恐此時淚，不禁和恨流。"]'),
('32f34408-9464-490f-97af-b340c25f444c','客行','馬戴','唐','唐诗','tang','','[]','路岐長不盡，客恨杳難通。',48,'全唐诗/poet.tang.30000.json','["路岐長不盡，客恨杳難通。", "蘆荻晚汀雨，柳花南浦風。", "亂鐘嘶馬急，殘日半帆紅。", "却羨漁樵侶，閑歌落照中。"]'),
('a0f122f8-e54c-4cb3-a85e-3e6f59e8a21e','過野叟居','馬戴','唐','唐诗','tang','','[]','野人閑種樹，樹老野人前。',48,'全唐诗/poet.tang.30000.json','["野人閑種樹，樹老野人前。", "居止白雲內，漁樵滄海邊。", "呼兒採山藥，放犢飲溪泉。", "自著養生論，無煩憂暮年。"]'),
('b7af4048-bb6f-486f-bab0-9023e34fa2d2','答光州王使君','馬戴','唐','唐诗','tang','','[]','信來淮上郡，楚岫入秦雲。',48,'全唐诗/poet.tang.30000.json','["信來淮上郡，楚岫入秦雲。", "自顧爲儒者，何由答使君。", "蛻風蟬半失，阻雨鴈頻聞。", "欲識平生分，他時別紀勳。"]'),
('8d9e384d-5088-483a-919c-f4f5454affe0','下第再過崔邵池陽居','馬戴','唐','唐诗','tang','','[]','豈無故鄉路，路遠未成歸。',48,'全唐诗/poet.tang.30000.json','["豈無故鄉路，路遠未成歸。", "關內相知少，海邊來信稀。", "離雲空石穴，芳草偃郊扉。", "謝子一留宿，此心聊息機。"]'),
('24b560e1-a417-40f9-a8be-211c6021cecf','夕次淮口','馬戴','唐','唐诗','tang','','[]','天涯秋光盡，木末羣鳥還。',48,'全唐诗/poet.tang.30000.json','["天涯秋光盡，木末羣鳥還。", "夜久遊子息，月明岐路閑。", "風生淮水上，帆落楚雲間。", "此意竟誰見，行行非故關。"]'),
('5e33eb70-be70-480a-85c3-6c072697ebde','落日悵望','馬戴','唐','唐诗','tang','','["\u5b64\u72ec", "\u601d\u4e61"]','孤雲與歸鳥，千里片時間。',48,'全唐诗/poet.tang.30000.json','["孤雲與歸鳥，千里片時間。", "念我一何滯，辭家久未還。", "微陽下喬木，遠色隱秋山。", "臨水不敢照，恐驚平昔顏。"]'),
('661348cc-8aa7-480e-8638-4c5604571e19','早發故山作','馬戴','唐','唐诗','tang','','[]','雲門夾峭石，石路蔭長松。',48,'全唐诗/poet.tang.30000.json','["雲門夾峭石，石路蔭長松。", "谷響猨相應，山深水復重。", "餐霞人不見，採藥客猶逢。", "獨宿靈潭側，時聞岳頂鐘。"]'),
('065859f2-1939-4142-8755-51c8b7b3d977','下第別郜扶','馬戴','唐','唐诗','tang','','[]','窮途別故人，京洛泣風塵。',48,'全唐诗/poet.tang.30000.json','["窮途別故人，京洛泣風塵。", "在世即應老，他鄉又欲春。", "平生空志學，晚歲拙謀身。", "靜話歸休計，唯將海上親。"]'),
('3a4f111b-6ab4-4457-9021-8c216f44ddf7','寄終南真空禪師','馬戴','唐','唐诗','tang','','[]','閑想白雲外，了然清淨僧。',48,'全唐诗/poet.tang.30000.json','["閑想白雲外，了然清淨僧。", "松門山半寺，夜雨佛前燈。", "此境可長住，浮生自不能。", "一從林下別，瀑布幾成冰。"]'),
('b4c9a9f7-1393-45dd-a112-4e508ca991f1','長安寓居寄贈賈島','馬戴','唐','唐诗','tang','','[]','歲暮見華髮，平生志半空。',48,'全唐诗/poet.tang.30000.json','["歲暮見華髮，平生志半空。", "孤雲不我棄，歸隱與誰同。", "枉道紫宸謁，妨栽丹桂叢。", "何如隨野鹿，棲止石巖中。"]'),
('59ecaa7b-6657-4be0-9b30-9188b5101bc0','秋郊夕望','馬戴','唐','唐诗','tang','','[]','度鳥向棲急，陰蟲逢夜多。',48,'全唐诗/poet.tang.30000.json','["度鳥向棲急，陰蟲逢夜多。", "餘霞媚秋漢，迥月濯滄波。", "蔓草將萎絕，流年其奈何。", "耿然搖落思，獨酌不成歌。"]'),
('39d76270-8cab-4d68-be4a-24361f28956d','贈越客','馬戴','唐','唐诗','tang','','["\u957f\u6c5f"]','故國波濤隔，明時已久留。',48,'全唐诗/poet.tang.30000.json','["故國波濤隔，明時已久留。", "獻書雙闕晚，看月五陵秋。", "南棹何時返，長江憶共遊。", "遙知釣船畔，相望在汀洲。"]'),
('c2029bd3-9e7f-4474-b8ac-4467bbd31bc1','送顧非熊下第歸江南','馬戴','唐','唐诗','tang','','[]','無成西別秦，返駕江南春。',48,'全唐诗/poet.tang.30000.json','["無成西別秦，返駕江南春。", "草際楚田鴈，舟中吳苑人。", "殘雲挂絕島，迥樹入通津。", "想到長洲日，門前多白蘋。"]'),
('eedeb49c-b0d2-4d96-b93e-9e0bf4a766c1','汧上勸舊友','馬戴','唐','唐诗','tang','','[]','斗酒故人同，長歌起北風。',48,'全唐诗/poet.tang.30000.json','["斗酒故人同，長歌起北風。", "斜陽高壘閉，秋角暮山空。", "鴈叫寒流上，螢飛薄霧中。", "坐來生白髮，況復久從戎。"]'),
('b765fc21-7f05-4b97-891a-25ffc37d3511','送狄參軍赴杭州','馬戴','唐','唐诗','tang','','[]','新官非次受，聖主寵前勳。',48,'全唐诗/poet.tang.30000.json','["新官非次受，聖主寵前勳。", "關雪發車晚，風濤挂席聞。", "海門山疊翠，湖岸郡藏雲。", "執簡從公後，髯參豈勝君。"]'),
('36b78cdf-ce0e-4587-9114-f72b16b7cd40','過故人所遷新居','馬戴','唐','唐诗','tang','','[]','金馬詔何晚，茂陵居近修。',48,'全唐诗/poet.tang.30000.json','["金馬詔何晚，茂陵居近修。", "客來雲雨散，鳥下梧桐秋。", "迥漢銜天闕，遙泉響御溝。", "坐看涼月上，爲子一淹留。"]'),
('5697cb42-4a36-43f5-9d62-60253b5d653c','落照','馬戴','唐','唐诗','tang','','[]','照曜天山外，飛鴉幾共過。',48,'全唐诗/poet.tang.30000.json','["照曜天山外，飛鴉幾共過。", "微紅拂秋漢，片白透長波。", "影促寒汀薄，光殘古木多。", "金霞與雲氣，散漫復相和。"]'),
('85dba45f-3495-4d23-9398-9d6091c63a3c','宿崔邵池陽別墅','馬戴','唐','唐诗','tang','','[]','楊柳色已改，郊原日復低。',48,'全唐诗/poet.tang.30000.json','["楊柳色已改，郊原日復低。", "煙生寒渚上，霞散亂山西。", "待月人相對，驚風鴈不齊。", "此心君莫問，舊國去將迷。"]'),
('7456691c-636e-46d7-9093-edc778b0a7ea','楚江懷古三首 一','馬戴','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6d1e\u5ead\u6e56", "\u5199\u666f", "\u4e94\u8a00\u5f8b\u8bd7", "\u6000\u53e4"]','露氣寒光集，微陽下楚丘。',48,'全唐诗/poet.tang.30000.json','["露氣寒光集，微陽下楚丘。", "猨啼洞庭樹，人在木蘭舟。", "廣澤生明月，蒼山夾亂流。", "雲中君不降，竟夕自悲秋。"]'),
('14060d28-d860-41d2-9583-27873f1e0ac8','楚江懷古三首 二','馬戴','唐','唐诗','tang','','[]','驚鳥去無際，寒蛩鳴我傍。',48,'全唐诗/poet.tang.30000.json','["驚鳥去無際，寒蛩鳴我傍。", "蘆洲生早霧，蘭隰下微霜。", "列宿分窮野，空流注大荒。", "看山候明月，聊自整雲裝。"]'),
('44c18e0b-fd4a-42b5-a4fa-866ac8d74d54','楚江懷古三首 三','馬戴','唐','唐诗','tang','','[]','野風吹蕙帶，驟雨滴蘭橈。',48,'全唐诗/poet.tang.30000.json','["野風吹蕙帶，驟雨滴蘭橈。", "屈宋魂冥寞，江山思寂寥。", "陰霓侵晚景，海樹入迴潮。", "欲折寒芳薦，明神詎可招。"]'),
('852bd050-0f74-4c5a-93b5-39818ffee6b8','遠水','馬戴','唐','唐诗','tang','','[]','蕩漾空沙際，虛明入遠天。',48,'全唐诗/poet.tang.30000.json','["蕩漾空沙際，虛明入遠天。", "秋光照不極，鳥影去無邊。", "勢引長雲斷，波輕片雪連。", "汀洲杳難到，萬古覆蒼煙。"]'),
('b7bf1f91-98aa-4db7-8c64-2332247d7e3d','夕發邠寧寄從弟','馬戴','唐','唐诗','tang','','[]','半酣走馬別，別後鎖邊城。',48,'全唐诗/poet.tang.30000.json','["半酣走馬別，別後鎖邊城。", "日落月未上，鳥棲人獨行。", "方馳故國戀，復愴長年情。", "入夜不能息，何當閑此生。"]'),
('ccacc633-6b9d-4ce4-905f-8bcd247b2d4c','贈別北客','馬戴','唐','唐诗','tang','','[]','君生遊俠地，感激氣何高。',48,'全唐诗/poet.tang.30000.json','["君生遊俠地，感激氣何高。", "飲盡玉壺酒，贈留金錯刀。", "鴈關飛霰雪，鯨海落雲濤。", "決去如征鳥，離心空自勞。"]'),
('20ec62d2-e652-45e4-a44d-d9a5b7266a2e','夜下湘中','馬戴','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭人夜別，孤棹下湘中。',48,'全唐诗/poet.tang.30000.json','["洞庭人夜別，孤棹下湘中。", "露洗寒山遍，波搖楚月空。", "密林飛暗狖，廣澤發鳴鴻。", "行值揚帆者，江分又不同。"]'),
('76dd45a3-abc7-4553-9279-5c89ecd63a4a','送呂郎中牧東海郡','馬戴','唐','唐诗','tang','','[]','假道經淮泗，檣烏集隼旟。',48,'全唐诗/poet.tang.30000.json','["假道經淮泗，檣烏集隼旟。", "蕪城沙菼接，波島石林疎。", "海鶴空庭下，夷人遠岸居。", "山鄉足遺老，佇聽薦賢書。"]'),
('3bf70cef-b268-4021-81e3-904421bc703d','山行偶作','馬戴','唐','唐诗','tang','','[]','緣危路忽窮，投宿值樵翁。',48,'全唐诗/poet.tang.30000.json','["緣危路忽窮，投宿值樵翁。", "鳥下山含暝，蟬鳴露滴空。", "石門斜月入，雲竇暗泉通。", "寂寞生幽思，心疑舊隱同。"]'),
('ad24d16d-abc1-4cf1-be80-0cea602bd5df','巴江夜猨','馬戴','唐','唐诗','tang','','[]','日飲巴江水，還啼巴岸邊。',48,'全唐诗/poet.tang.30000.json','["日飲巴江水，還啼巴岸邊。", "秋聲巫峽斷，夜影楚雲連。", "露滴青楓樹，山空明月天。", "誰知泊船者，聽此不能眠。"]'),
('50ca3358-9db8-496f-8bd9-b09c8e80f758','送田使君牧蔡州','馬戴','唐','唐诗','tang','','[]','主意思政理，牧人官不輕。',48,'全唐诗/poet.tang.30000.json','["主意思政理，牧人官不輕。", "樹多淮右地，山遠汝南城。", "望稼周田隔，登樓楚月生。", "懸知蔣亭下，渚鶴伴閑行。"]'),
('b2a989d3-4a9d-488e-8050-fcee599678e0','雀臺怨','馬戴','唐','唐诗','tang','','[]','魏宮歌舞地，蝶戲鳥還鳴。',48,'全唐诗/poet.tang.30000.json','["魏宮歌舞地，蝶戲鳥還鳴。", "玉座人難到，銅臺雨滴平。", "西陵樹不見，漳浦草空生。", "萬恨盡埋此，徒懸千載名。"]'),
('e3bb8811-902f-45ed-bbde-517f8c5a1604','早發故園','馬戴','唐','唐诗','tang','','[]','語別在中夜，登車離故鄉。',48,'全唐诗/poet.tang.30000.json','["語別在中夜，登車離故鄉。", "曙鐘寒出岳，殘月迥凝霜。", "風柳條多折，沙雲氣盡黃。", "行逢海西鴈，零落不成行。"]'),
('5ff62c61-f702-4f28-bb22-9c520856f7b1','贈別江客','馬戴','唐','唐诗','tang','','[]','湘中有岑穴，君去挂帆過。',48,'全唐诗/poet.tang.30000.json','["湘中有岑穴，君去挂帆過。", "露細蒹葭廣，潮迴島嶼多。", "汀洲延夕照，楓葉墜寒波。", "應使同漁者，生涯許釣歌。"]'),
('a2b5f02d-7e7b-460c-bd53-f25b6d12ec4f','宿翠微寺','馬戴','唐','唐诗','tang','','[]','處處松陰滿，樵開一逕通。',48,'全唐诗/poet.tang.30000.json','["處處松陰滿，樵開一逕通。", "鳥歸雲壑靜，僧語石樓空。", "積翠含微月，遙泉韻細風。", "經行心不厭，憶在故山中。"]'),
('806a5f89-fd88-43ea-a54d-3b277fec0e11','霽後寄白閣僧','馬戴','唐','唐诗','tang','','[]','蒼翠霾高雪，西峯鳥外看。',48,'全唐诗/poet.tang.30000.json','["蒼翠霾高雪，西峯鳥外看。", "久披山衲壞，孤坐石牀寒。", "盥手水泉滴，燃燈夜燒殘。", "終期老雲嶠，煮藥伴中餐。"]'),
('44880738-1f0a-4992-9999-c31b69fa03b1','送僧歸金山寺','馬戴','唐','唐诗','tang','','[]','金陵山色裏，蟬急向秋分。',48,'全唐诗/poet.tang.30000.json','["金陵山色裏，蟬急向秋分。", "迥寺橫洲島，歸僧渡水雲。", "夕陽依岸盡，清磬隔潮聞。", "遙想禪林下，鑪香帶月焚。"]'),
('0af77225-ddfd-43f8-9ec8-9851edfdd917','新秋雨霽宿王處士東郊','馬戴','唐','唐诗','tang','','[]','夕陽逢一雨，夜木洗清陰。',48,'全唐诗/poet.tang.30000.json','["夕陽逢一雨，夜木洗清陰。", "露氣竹窗靜，秋光雲月深。", "煎嘗靈藥味，話及故山心。", "得意兩不寐，微風生玉琴。"]'),
('9ac46ba9-d263-4cc8-8ce3-d10e628ae8f7','關山曲二首 一','馬戴','唐','唐诗','tang','','[]','金甲耀兜鍪，黃金拂紫騮。',48,'全唐诗/poet.tang.30000.json','["金甲耀兜鍪，黃金拂紫騮。", "叛羌旗下戮，陷壁夜中收。", "霜霰戎衣月，關河磧氣秋。", "箭瘡殊未合，更遣擊蘭州。"]'),
('d872554a-70da-46eb-9163-3d7c3302574b','關山曲二首 二','馬戴','唐','唐诗','tang','','[]','火發龍山北，中宵易左賢。',48,'全唐诗/poet.tang.30000.json','["火發龍山北，中宵易左賢。", "勒兵臨漢水，驚鴈散胡天。", "木落防河急，軍孤受敵偏。", "猶聞漢皇怒，按劒待開邊。"]'),
('8598ad58-dc4d-4ad2-8ba5-f8df27723ceb','塞下曲二首 一','馬戴','唐','唐诗','tang','','[]','旌旗倒北風，霜霰逐南鴻。',48,'全唐诗/poet.tang.30000.json','["旌旗倒北風，霜霰逐南鴻。", "夜救龍城急，朝焚虜帳空。", "骨銷金鏃在，鬢改玉關中。", "却想羲軒氏，無人尚戰功。"]'),
('bc94d1ca-e86f-4766-b699-35a8728ec558','塞下曲二首 二','馬戴','唐','唐诗','tang','','[]','廣漠雲凝慘，日斜飛霰生。',48,'全唐诗/poet.tang.30000.json','["廣漠雲凝慘，日斜飛霰生。", "燒山搜猛獸，伏道擊迴兵。", "風折旗竿曲，沙埋樹杪平。", "黃雲飛旦夕，偏奏苦寒聲。"]'),
('6aad4e66-9af4-458c-8126-8f2998deff3c','廣陵曲','馬戴','唐','唐诗','tang','','[]','葱蘢桂樹枝，高繫黃金羈。',48,'全唐诗/poet.tang.30000.json','["葱蘢桂樹枝，高繫黃金羈。", "葉隱青蛾翠，花飄白玉墀。", "上鳴間關鳥，下醉遊俠兒。", "煬帝國已破，此中都不知。"]'),
('5ddf9bdd-fa07-4f3c-897e-d6428fb97147','送人遊蜀','馬戴','唐','唐诗','tang','','[]','別離楊柳陌，迢遰蜀門行。',48,'全唐诗/poet.tang.30000.json','["別離楊柳陌，迢遰蜀門行。", "若聽清猨後，應多白髮生。", "虹霓侵棧道，風雨雜江聲。", "過盡愁人處，煙花是錦城。"]'),
('deef2684-e928-48a8-8cb7-078c85be5500','宿無可上人房','馬戴','唐','唐诗','tang','','[]','稀逢息心侶，細話遠山期。',48,'全唐诗/poet.tang.30000.json','["稀逢息心侶，細話遠山期。", "河漢秋深夜，杉梧露滴時。", "風傳林磬響，月掩草堂遲。", "坐臥禪心在，浮生皆不知。"]'),
('4ae2c08a-704a-4475-8b4b-55ed39167cc5','旅次夏州','馬戴','唐','唐诗','tang','','[]','嘶馬發相續，行次夏王臺。',48,'全唐诗/poet.tang.30000.json','["嘶馬發相續，行次夏王臺。", "鎖郡雲陰暮，鳴笳燒色來。", "霜繁邊上宿，鬢改磧中迴。", "悵望胡沙曉，驚蓬朔吹催。"]'),
('3d907ab0-fa98-4704-aa08-7eca8c296e99','同莊秀才宿鎮星觀','馬戴','唐','唐诗','tang','','[]','的的星河落，霑苔復灑松。',48,'全唐诗/poet.tang.30000.json','["的的星河落，霑苔復灑松。", "濕光微泛草，石翠澹搖峰。", "野觀雲和月，秋城漏間鐘。", "知君親此境，九陌少相逢。"]');
